window.__dh_data["ml"] = {
  "": "Content-Type: text/plain; charset=UTF-8\nContent-Transfer-Encoding: 8bit\n",
  "title": "ധമ്മപദം",
  "chaps": "അധ്യായങ്ങൾ",
  "fontsize": "അക്ഷരസഞ്ചയത്തിന്റെ വലിപ്പം",
  "chap1": "യമകവഗ്ഗോ",
  "1": "പദാര്‍ത്ഥങ്ങള്‍ക്കു ഗുണങ്ങളും സ്ഥിരതയും സ്വരൂപവും കല്പിക്കുന്നതു മനസ്സാകുന്നു. ഒരുവന്‍ ദുഷ്ടമനസ്സോടുകൂടി സംസാരിക്കുകയോ (കളവു മുതലായതു പറയുകയോ) പ്രവര്‍ത്തിക്കുകയോ (പ്രാണിഹിംസാദി ചെയ്യുകയോ) ചെയ്യുന്നതായാല്‍ വാഹനത്തെ ചക്രമെന്നപോലെ അവനെ ദുഃഖം പിന്തുടരുന്നു.",
  "2": "പദാര്‍ത്ഥങ്ങള്‍, ഗുണങ്ങള്‍, സ്ഥിരത, സ്വരൂപം എന്നിവയെ കല്പിക്കുന്നതു മനസ്സാകുന്നു. മനഃശുദ്ധിയോടെ സംസാരിക്കുകയോ (സ്തോത്രം മുതലായതു ചൊല്ലുകയോ?) പ്രവര്‍ത്തിക്കുകയോ ദാനം ചെയ്യുകയോ ചെയ്യുന്നവനെ വിട്ടുപോകാത്ത നിഴലെന്നപോലെ സുഖം അനുഗമിക്കുന്നു.",
  "3": "അവന്‍ എന്നെ ശകാരിച്ചു, അടിച്ചു, തോല്പിച്ചു, മുതല്‍ പിടിച്ചു പറിച്ചു, എന്നും മറ്റും കരുതിക്കൊണ്ടിരിക്കുന്നവരില്‍ വൈരം വിട്ടുപോകുന്നതല്ല.",
  "4": "എന്നെ അയാള്‍ ശകാരിച്ചു, അടിച്ചു, തോല്പിച്ചു, എന്റെ മുതലപഹരിച്ചു എന്നൊന്നും കരുതിക്കൊണ്ടിരിക്കാത്തവരെ വൈരം ബാധിക്കുന്നില്ല.",
  "5": "ദ്വേഷംകൊണ്ടു ദ്വേഷം ശമിക്കുന്നില്ല. ദ്വേഷം മിത്രത്വം (അവൈരം) കൊണ്ടേ നശിക്കുകയുള്ളൂ. ഇതു സനാതന ധര്‍മ്മമാണ്‌.",
  "6": "നാം വൈരംനിമിത്തം നശിച്ചുപോകുന്നു എന്നായി ചിലര്‍ അറിയുന്നില്ല. അതറിയുന്നവര്‍ ഏവ ചിലരോ അവരുടെ ദോഷം ശമിക്കുന്നു.",
  "7": "ഭോഗങ്ങള്‍ ശുഭങ്ങളാണെന്നു ധരിച്ചും ഇന്ദ്രിയങ്ങളെ ഒതുക്കാതെ ഭോജനാദികളില്‍ മാത്രം ശ്രദ്ധിച്ചും മടിയനായും നിരുത്സാഹിയായുമിരിക്കുന്നവനെ കൊടുങ്കാറ്റ് ദുര്‍ബലമായ വൃക്ഷത്തിനെന്നപോലെ മാരന്‍ (കാമദേവന്‍) എളുപ്പത്തില്‍ ഭ്രംശം വരുത്തുന്നു.",
  "8": "വിഷയങ്ങളില്‍ ഭ്രമിക്കാതെയും ഇന്ദ്രിയങ്ങളെ നിഗ്രഹിച്ചും ഭോജനാദികളില്‍ മിതവാനായും ശ്രദ്ധ, വീര്യം ഇതുകളോടു കൂടിയുമിരിക്കുന്നവനെ കൊടുങ്കാറ്റിനു ശിലാമയമായ പര്‍വ്വതത്തെ എന്നപോലെ മാരന്‍ (കാമന്‍) ഇളക്കുവാന്‍ കഴിയുന്നതല്ല.",
  "9": "ദമ (ഇന്ദ്രിയനിഗ്രഹം)വും സത്യവുമല്ലാത്ത തൃഷ്ണാകഷായത്താല്‍ മൂടപ്പെട്ടവന്‍ കാഷായവസ്ത്രം (കാവിവസ്ത്രം) ധരിക്കേണ്ടതില്ല. അവന്‍ അതിന് അര്‍ഹനല്ല.",
  "10": "ജിതേന്ദ്രിയനും സത്യവാനും തൃഷ്ണാരഹിതനും ശിക്ഷാശീലയുക്തനും സമാധിനിരതനുമായവന്‍ (ഭിക്ഷു) യോഗ്യമായ കാഷായവസ്ത്രത്തിന് അര്‍ഹനാകുന്നു.",
  "11": "അസാരവസ്തുവില്‍ സാരബുദ്ധ്യാ ഭ്രമിക്കുകയും സാരത്തില്‍ മിഥ്യാത്വം കല്പിക്കുകയും ചെയ്യുന്നവന്‍ മായാഭ്രമത്തില്‍ കിടന്നുഴലുന്നതല്ലാതെ സാരത്തില്‍ പ്രവേശിക്കയുണ്ടാവില്ല. (നാസ്തികാദി മതത്തില്‍ ഭ്രമിച്ചും സനാതനധര്‍മ്മത്തെ തെറ്റിദ്ധരിച്ചും കഴിയുന്നവന്‍ നിര്‍വ്വാണത്തെ പ്രാപിക്കയില്ലെന്നര്‍ത്ഥം)",
  "12": "സാരത്തെ സാരമെന്നും അസാരത്തെ അസാരമെന്നും വാസ്തവംപോലെ ധരിക്കുന്നവന്‍ നേര്‍വഴിക്കു പോകുന്നതുകൊണ്ട് സാരത്തില്‍ എത്തുന്നു.",
  "13": "മേല്‍പ്പുര വേണ്ടതുപോലെ മേയാത്ത ഒരു വീട്ടിനകത്തു വര്‍ഷധാരകളെന്നപോലെ സുശിക്ഷിതമല്ലാത്ത മനസ്സില്‍ രാഗാദികള്‍ കടന്നു കൂടുന്നു.",
  "14": "പുര നല്ലവണ്ണം മേഞ്ഞിട്ടുള്ള വീട്ടിനകത്തു മഴ കടക്കുന്നതല്ല. അതുപോലെ തന്നെ ശിക്ഷിതമായ മനസ്സിലേയ്ക്കു രാഗാദിയും പ്രവേശിക്കുന്നതല്ല.",
  "15": "പാപകര്‍മ്മം ചെയ്യുന്നവനു ഇഹലോകത്തിലും പരലോകത്തിലും ഒരുപോലെ ക്ലേശിക്കേണ്ടിവരുന്നു. അവന്‍ തന്റെ കര്‍മ്മം പാപമാണെന്നറിഞ്ഞുകൊണ്ട് പിന്നെയും പിന്നെയും പശ്ചാത്താപത്തോടുകൂടി ക്ലേശം അനുഭവിച്ചുകൊണ്ടിരിക്കുന്നു.",
  "16": "പുണ്യാത്മാവ് ഇഹത്തിലും പരത്തിലും ഒരുപോലെ മോദിക്കുന്നു. അവന്റെ കര്‍മ്മം പരിശുദ്ധമാണെന്നറിഞ്ഞു പിന്നെയും പിന്നെയും അതിയായി ആനന്ദിക്കുന്നു.",
  "17": "പാപികള്‍ ഇഹത്തിലും പരത്തിലും ഒരുപോലെ ദുഃഖിക്കുന്നു. അവര്‍ തങ്ങള്‍ ചെയ്യുന്നത് പാപമാണെന്നറിഞ്ഞുകൊണ്ട് ദുഃഖിച്ചു ദുഃഖിച്ചു നരകത്തെ പ്രാപിക്കുന്നു.",
  "18": "പുണ്യവാന്‍ ഇഹലോകത്തിലും പരലോകത്തിലും ഭേദംകൂടാതെ ആനന്ദമനുഭവിക്കുന്നു. അവന്‍ താന്‍ ചെയ്തതു പുണ്യമാണെന്നറിഞ്ഞു അഭിനന്ദിക്കയും അവസാനത്തില്‍ സ്വര്‍ഗ്ഗത്തെ പ്രാപിക്കുകയും ചെയ്യുന്നു.",
  "19": "യാതൊരു മനുഷ്യന്‍ അന്യന് പാരമാര്‍ത്ഥികങ്ങളായ ഉപദേശങ്ങളെ ധാരാളം ചെയ്യുന്നുവെങ്കിലും ഉപദേശങ്ങള്‍ക്കനുസരിച്ചുള്ള അനുഷ്ഠാനങ്ങളൊന്നും താന്‍ ചെയ്യാതെയും പ്രമത്തനായും ഇരിക്കുന്നുവോ അവന്‍ കൂലി കിട്ടുവാൻ വേണ്ടി അന്യന്റെ പശുക്കളെ ഗണിക്കുന്ന (മേയ്ക്കുന്ന) ഒരു ഇടയന് തുല്യനാകുന്നു.",
  "20": "ഒരുവന്‍ ഉപദേശപ്രസംഗങ്ങള്‍ കുറെ കുറച്ചാലും ഉപദേശപ്രകാരമുള്ള ധര്‍മ്മാചരണങ്ങളെ ചെയ്തും രാഗദ്വേഷമോഹങ്ങളെ വിട്ടൊഴിഞ്ഞും തത്ത്വത്തെയറിഞ്ഞും വിമുക്താത്മാവായും ഐഹികവും പാരത്രികവുമായി യാതൊരു കാമവുമില്ലാതെയും കാലക്ഷേപം ചെയ്യുന്നതായാല്‍ അവന്‍ പരമോത്തമമായ മോക്ഷപദത്തിന്റെ ഭാഗഭാക്കായി ഭവിക്കുന്നതാണ്.",
  "chap2": "അപ്പമാദവഗ്ഗോ",
  "21": "(ധര്‍മാചരണത്തില്‍) അപ്രമാദം (അതിശ്രദ്ധ) എന്നതു മുക്തിക്കു മാര്‍ഗമാകുന്നു. അപ്രമത്തന്മാര്‍ മരിക്കുന്നില്ല. പ്രമത്തന്മാര്‍ (നിരുത്സാഹികള്‍) മൃതതുല്യരാകുന്നു.",
  "22": "ഈ വിധം പ്രതൃക്ഷമായി അറിഞ്ഞു അപ്രമാദത്തില്‍ പരിജ്ഞാനമുള്ളവന്‍ അപ്രമാദത്തില്‍ മോദിക്കുന്നു. ആര്യധര്‍മ്മത്തില്‍ എപ്പോഴും സന്തോഷിക്കുന്നു.",
  "23": "ധ്യാനരതന്മാരും, സാത്വികന്മാരും ദൃഢഃപരാക്രമികളുമായ വിദ്വാന്മാര്‍ പരമമുക്തിയാകുന്ന നിര്‍വ്വാണത്തെ പ്രാപിക്കുന്നു.",
  "24": "ജാഗരണശീലനും സ്മൃതിമാനും സദാചാരനിരതനും സൂക്ഷ്മജ്ഞാനിയും ജിതേന്ദ്രിയനും ധര്‍മ്മജീവിയും അപ്രമത്തനുമായ മനുഷ്യന്റെ കീര്‍ത്തി ഏറ്റവും വര്‍ദ്ധിക്കുന്നു.",
  "25": "വിദ്വജ്ജനം ഉദ്യോഗം, അപ്രമാദം, സംയമം, ദമനം ഇതുകളെ കൊണ്ട് ഒരു ദ്വീപിനെ സൃഷ്ടിക്കുന്നു. അതിനെ ഏതൊരു വെള്ളപ്പൊക്കവും മുക്കിക്കളയുകയില്ല.",
  "26": "മന്ദബുദ്ധികള്‍ പ്രമാദത്താല്‍ ധര്‍മ്മകാര്യവിഭ്രഷ്ടരായിട്ടു വിഷയവാസനയിങ്കല്‍ ലയിക്കുന്നു. വിദ്വാനാകട്ടെ ധര്‍മ്മത്തെ (അപ്രമാദത്തെ) അമൂല്യധനത്തെ എന്നപോലെ രക്ഷിക്കുന്നു.",
  "27": "ധര്‍മ്മകാര്യങ്ങളില്‍ ആലസ്യമോ വിഷയഭോഗങ്ങളില്‍ തൃഷ്ണയോ അരുത്. അപ്രമത്തന്‍, ഉത്സാഹത്തോടെ ധ്യാനശീലനായിരിക്കുന്നവന്‍ വിപുലമായ സുഖത്തെ പ്രാപിക്കുന്നു.",
  "28": "ചതുരനായ ഏതൊരു പണ്ഡിതന്‍ ആകുന്നു അപ്രമാദം കൊണ്ടു പ്രമാദത്തെ അകറ്റുന്നത് ആ ധീരന്‍ പ്രജ്ഞയാകുന്ന ഉന്നതപ്രാസാദത്തില്‍ കയറി ക്ലേശരഹിതനായിട്ടു ദുഃഖനിമഗ്നന്മാരായ മൂഢന്മാരെ പര്‍വ്വതപൃഷ്ടത്തില്‍ നില്‍ക്കുന്നവന്‍ ഭൂമധ്യത്തില്‍ നില്‍ക്കുന്നവരെ എന്നപോലെ നോക്കുന്നു.",
  "29": "ബുദ്ധിമാന്‍ അലസന്മാരുടെയിടയില്‍ ഉത്സാഹിയും നിദ്രാലുക്കളുടെ ഇടയില്‍ ജാഗരൂകനുമായി വേഗമേറിയ കുതിര ക്ഷീണിച്ച കുതിരയെ അതിക്രമിക്കുന്നതുപോലെ ഗമിക്കുന്നു.",
  "30": "അപ്രമാദം നിമിത്തമാകുന്നു മഘവാവ് (ഇന്ദ്രന്‍) ദേവന്മാരില്‍ ശ്രേഷ്ഠതയെ ലഭിച്ചത്. വിദ്വാന്മാര്‍ അപ്രമാദത്തെ പ്രശംസിക്കുന്നു. പ്രമാദം എപ്പോഴും നിന്ദിതമാകുന്നു.",
  "31": "അപ്രമാദരതനായും പ്രമാദത്തില്‍ ഭയത്തോടുകൂടിയുമിരിക്കുന്ന ഭിക്ഷു സാരങ്ങളും അസാരങ്ങളുമായ ബന്ധങ്ങളെ ദഹിപ്പിച്ചു അഗ്നിയെപ്പോലെ ഗമിക്കുന്നു.",
  "32": "അപ്രമാദരതനായും പ്രമാദത്താല്‍ ഭയദര്‍ശിയുമായിരിക്കുന്ന യോഗി ധര്‍മ്മഭ്രഷ്ടനായി വരുവാനിടയില്ല. നിര്‍വ്വാണപ്രാപ്തിക്കു തന്നെ അടുക്കുന്നു.",
  "chap3": "ചിത്തവഗ്ഗോ",
  "33": "(ഭയത്താല്‍) വിറയ്ക്കുന്നതും (സംശയാദിയാല്‍) ചഞ്ചലവും ഒതുക്കുവാനും അടക്കുവാനും പ്രയാസമുള്ളതുമായ മനസ്സിനെ ആയുധവേലക്കാരന്‍ അമ്പിനെ ചൊവ്വാക്കുന്നതുപോലെ ബുദ്ധിമാന്‍ നേരെയാക്കി നിറുത്തുന്നു.",
  "34": "ജലചരമായ മത്സ്യത്തെ പിടിച്ചു കരയ്ക്കിട്ടാല്‍ ഏതുവിധം പിടയ്ക്കുന്നുവോ അതേവിധം കാമാധീനമായ മനസ്സ് സ്വസ്ഥാനം വിടുമ്പോള്‍ പിടയ്ക്കുന്നു.",
  "35": "ബുദ്ധിമാന്‍ ഒതുക്കാന്‍ കഴിയാത്തതും ഉറപ്പില്ലാത്തതും വ്യാമോഹവത്തുമായ ചിത്തത്തെ സ്വാധീനിക്കേണ്ടതാകുന്നു. ദമനം ചെയ്യപ്പെട്ട ചിത്തം സുഖത്തെ ചെയ്യുന്നു.",
  "36": "ജ്ഞാനഗോചരമല്ലാതെ അത്യന്തം സുനിപുണമാകുംവണ്ണം രൂപാദി വിഷയങ്ങളില്‍ വിഹരിക്കുന്ന മനസ്സിനെ പണ്ഡിതന്‍ ഒതുക്കേണ്ടതാണ്. ഒതുക്കപ്പെട്ട മനസ്സു സുഖകരമാകുന്നു.",
  "37": "ദൂരസഞ്ചാരിയും ഏകാകിയും നിരാകാരവും ശരീരഗുഹാശയവുമായ ചിത്തത്തെ അടക്കുന്നുവോ അവര്‍ മാരബന്ധനത്തില്‍ നിന്നു വേര്‍പെടുന്നു.",
  "38": "അനവസ്ഥിതചിത്തനും ധര്‍മ്മബോധമില്ലാത്തവനും മനസ്സമാധാനമില്ലാത്തവനും ആയവന് പ്രജ്ഞ (വിശേഷജ്ഞാനം) പരിപൂര്‍ണ്ണമാകുന്നതല്ല.",
  "39": "മോഹാദി തീവ്രധാരയാല്‍ മനതശ്ചാഞ്ചല്യം ബാധിക്കാത്തവനും ചിത്തഭ്രാന്തിയില്ലാത്തവനും പുണ്യപാപങ്ങളെ മോചിച്ചവനും ജാഗരൂകനുമായ മനുഷ്യന് ഭയമുണ്ടാവുകയില്ല.",
  "40": "ഈ ദേഹം മണ്‍കുടം പോലെ ക്ഷണഭംഗുരമാണെന്നും ചിത്തം കോട്ടപോലെ ഉറപ്പുള്ളതാണെന്നും അറിഞ്ഞ് ജ്ഞാനാസ്ത്രം കൊണ്ട് മാരനെ എതിര്‍ത്തുകൊള്‍വിന്‍. ഉല്ലാസകരങ്ങളായ വിനോദങ്ങളില്‍ ഏര്‍പ്പെട്ടുപോകാതെ അങ്ങിനെ സമ്പാദിച്ച ജയത്തെ രക്ഷിച്ചുകൊണ്ടു ശ്രദ്ധയോടുകൂടിയിരിക്കുവിന്‍.",
  "41": "തുച്ഛമായ ഈ ദേഹം പ്രജ്ഞവിട്ട് അല്പകാലംകൊണ്ട് ഉപയോഗമില്ലാത്ത മരക്കഷണംപോലെ മണ്ണില്‍ പതിച്ചുകൂടുന്നതാണ്.",
  "42": "ദ്വേഷിക്കപ്പെട്ടവന്‍ ദ്വേഷിച്ചവന് ദ്വേഷം ചെയ്യുന്നു. വൈരികളും പരസ്പരം ദ്വേഷം ചെയ്യുന്നു. അസത്യത്തില്‍ പ്രവേശിച്ച മനസ്സ് ഇവ രണ്ടിലുമധികം പാപകരമായിട്ടുള്ളതാണ്.",
  "43": "മാതാപിതാക്കളില്‍നിന്നോ മറ്റു ബന്ധുക്കളില്‍നിന്നോ ഉണ്ടാവുന്ന ഗുണത്തേക്കാളധികം ഗുണം സത്യനിഷ്ഠയോടുകൂടിയിരിക്കുന്ന മനസ്സില്‍ നിന്ന് ഒരുവനുണ്ടാകുന്നതാണ്.",
  "chap4": "പുപ്പ്ഫവഗ്ഗോ",
  "44": "ഭൂലോകവും യമലോകവും, ദേവലോകവും ജയിപ്പാന്‍ ആരു ശക്തനാകുന്നു? സമര്‍ത്ഥനായ മാലാകാരന്‍ പുഷ്പങ്ങളെ എന്നപോലെ ധര്‍മ്മപദമെന്ന ബുദ്ധോപദേശത്തെ തരംതിരിച്ചു മനസ്സിലാക്കുവാന്‍ ആര്‍ക്കു കഴിയും?",
  "45": "ബുദ്ധശിഷ്യന്‍ ഭൂമിയും, യമലോകവും ദേവലോകവും ജയിക്കുന്നു. ഒരു ശിഷ്യന്‍ ചതുരനായ മാലാകാരന്‍ പുഷ്പസഞ്ചയങ്ങളെ തരം തിരിക്കുന്നതുപോലെ ബുദ്ധോപദേശമായ ധര്‍മ്മപദത്തെ വകതിരിച്ചു ഗ്രഹിക്കുന്നു.",
  "46": "ദേഹം വെള്ളത്തിലെ പോളപോലെയുള്ളതും, മൃഗതൃഷ്ണപോലെ സത്യമില്ലാത്തതുമാണെന്ന് ആരു ഗ്രഹിക്കുന്നുവോ അവന്‍ മാരന്റെ പുഷ്പമയമായ ശരത്തെ ഭഞ്ജിക്കുന്നു, മൃത്യുരാജനെ ഒരിക്കലും കാണുകയില്ല.",
  "47": "പുഷ്പങ്ങളെ പറിച്ചെടുക്കുന്നപോലെ വിഷയരസങ്ങളെ അനുഭവിച്ചുകൊണ്ടിരിക്കുന്നവനെ സുപ്തമായിരിക്കുന്ന ഗ്രാമത്തെ വെള്ളപ്പൊക്കമെന്നപോലെ മൃത്യു തട്ടിക്കൊണ്ടുപോകുന്നു.",
  "48": "പുഷ്പങ്ങളെ സഞ്ചയിക്കുന്നതുപോലെ വിഷയരസങ്ങളെ സഞ്ചയിക്കുകയും കാമഭോഗങ്ങളില്‍ അലംഭാവമില്ലാതിരിക്കുകയും ചെയ്യുന്ന മൂഢന്‍ അന്തകന് അധീനനാകുന്നു.",
  "49": "വണ്ടു പുഷ്പത്തില്‍നിന്നു സൌന്ദര്യവും സൌരഭ്യവും നശിക്കാതെ മധുവിനെ മാത്രം വലിച്ചെടുത്തു പോകുന്നു. ഇപ്രകാരം ഒരു മുനി ഗ്രാമത്തില്‍ (ഉള്ളവരുടെ ഭക്തിശ്രദ്ധാദികള്‍ക്കു ദോഷം വരുത്താതെ) ചരിക്കട്ടെ (വസിക്കട്ടെ).",
  "50": "അന്യന്മാരുടെ പിഴകളേയും കൃതാകൃതങ്ങളായ പാപങ്ങളേയും പറ്റിയല്ല വിചാരപ്പെടേണ്ടത് തന്റെ ദുഷ്കര്‍മ്മങ്ങളേയും വീഴ്ചകളേയുമാണ് വിചാരിക്കേണ്ടത്.",
  "51": "കാഴ്ചയില്‍ മനോഹരമാണെങ്കിലും ഗന്ധമില്ലാത്ത പുഷ്പം കൊണ്ട് ഉപയോഗമില്ല. അതുപോലെതന്നെ ഉപദേശത്തിന്നനുരൂപമായി ആചരിക്കാത്തവന്റെ വാക്കു ഭംഗിയുള്ളതാണെങ്കിലും നിഷ്പ്രയോജനമായി ഭവിക്കുന്നു.",
  "52": "ഭംഗിയേറിയ പുഷ്പം സൌരഭ്യമുള്ളതായിക്കൂടിവന്നാല്‍ അധികം ആദരണീയമായിത്തീരുന്നു. അതുപോലെത്തന്നെ അനുരൂപമായ കര്‍മ്മവും കൂടിയുണ്ടെങ്കില്‍ സദുപദേശം അധികം ഫലവത്തായിത്തീരുന്നു.",
  "53": "പുഷ്പം കൂട്ടിവെച്ചതില്‍നിന്ന് എടുത്ത് അനേകം മാലകളെ ഉണ്ടാക്കുന്നതുപോലെ മനുഷ്യന്‍ ജന്മത്തില്‍നിന്ന് ബഹുലമായ പുണ്യത്തെ സംഗ്രഹിച്ചുകൊള്ളണം.",
  "54": "ചന്ദനം, അകില്‍, മല്ലിക മുതലായവയുടെ വാസന കാറ്റിനു വിപരീതമായി നടക്കുന്നില്ല. സത്തുക്കളുടെ വാസന (യശസ്സു) കാറ്റിനു വിപരീതമായും സഞ്ചരിക്കുന്നു. സല്‍പുരുഷന്‍ സര്‍വദിക്കുകളിലും വ്യാപിക്കുന്നു.",
  "55": "ചന്ദനം, ധൂപക്കൂട്ട മുതലായതിനേക്കാളും താമര, മല്ലിക തുടങ്ങിയ പുഷ്പങ്ങളേക്കാളും അധികം വാസന സത്കര്‍മ്മത്തിനു കൂടും.",
  "56": "ധൂപം, ചന്ദനം മുതലായതിന്റെ വാസന അല്പമാത്രമാകുന്നു. എന്നാല്‍ ശീലവാന്മാരുടെ വാസന സര്‍വ്വോത്കൃഷ്ടമായിട്ടു ദേവലോകത്തുകൂടി എത്തുന്നു.",
  "57": "സദാചാരശീലന്മാരും അപ്രമത്തന്മാരും സമ്യഗ്ജ്ഞാനശക്തിനിമിത്തം വിഷയവാസനയില്‍നിന്നു വിമുക്തന്മാരുമായ മഹാത്മാക്കളില്‍ പ്രവേശിപ്പാന്‍ കാമദേവന്നു (മാരന്) വഴികിട്ടുന്നില്ല.",
  "58": "പെരുവഴിയിൽ ദുർഗന്ധമുള്ള കുപ്പകൾക്കകത്തു താമരപ്പൂ വാസനയും ഭംഗിയുമുള്ളതായി വിടർന്നു നില്ക്കുന്നത് എങ്ങിനെയോ",
  "59": "അങ്ങിനെതന്നെ ലോകവിഷയതത്പരന്മാരായും അന്ധന്മാരുമായിരിക്കുന്ന മൂർഖന്മാരുടെ ഇടയിൽ ഭഗവാനിൽനിന്നും സിദ്ധി ലഭിച്ചിട്ടുള്ള ശിഷ്യന്മാർ ഏറ്റവും ശോഭിക്കുന്നു.",
  "chap5": "ബാലവഗ്ഗോ",
  "60": "ഉറക്കം വരാത്തവന് രാത്രി വളരെ ദീര്‍ഘയാണെന്ന് തോന്നുന്നു. ക്ഷീണിച്ച പാന്ഥന് യോജന ദീര്‍ഘമുള്ളതായി തോന്നുന്നു. അതുപോലെതന്നെ സദ്ധര്‍മ്മത്തെ അറിയാത്ത ബാലന്മാര്‍ക്ക് സംസാരവും ദീര്‍ഘമേറിയതായി തോന്നും.",
  "61": "ഒരുവന്‍ യാത്ര ചെയ്യുമ്പോള്‍ തനിക്ക് സമനോ തന്നേക്കാള്‍ ശ്രേഷ്ഠനോ ആയവനെ സഹായത്തിന് കൂട്ടണം. അങ്ങനെയുള്ളവരെ കിട്ടാത്തപക്ഷം ഒറ്റയ്ക്ക് നടന്നുപോകുന്നതാണ് ഉത്തമം. ബുദ്ധിശൂന്യനെ ഒന്നിച്ചു കൂട്ടിയതുകൊണ്ട് സഹായമാവില്ല.",
  "62": "എനിക്ക് പുത്രന്മാരുണ്ട്, ധനമുണ്ട് എന്നും മറ്റും കരുതി ബുദ്ധിഹീനന്‍ (മൂഢന്‍) ക്ലേശിക്കുന്നു. തനിക്ക് താനേ സ്വാധീനമില്ലാത്തവന് പുത്രനെവിടെ? ധനമെവിടെ?",
  "63": "ബുദ്ധിഹീനന് തന്റെ മൂഢതയെപ്പറ്റി ബോധംവന്നാല്‍ അതുതന്നെ ജ്ഞാനമായി. തന്റെ മൂഢതയെ പാണ്ഡിത്യമായി ധരിക്കുന്നവനെയാണ് വാസ്തവത്തില്‍ മൂഢനെന്ന് പറയേണ്ടത്.",
  "64": "അവിവേകിയായ പുരുഷന്‍ ജീവാവസാനം വരെ ബുദ്ധിമാനോട് സഹവസിക്കുന്നതായാലും അവന് ധര്‍മ്മജ്ഞാനമുണ്ടാകുന്നതല്ല. ഒരു കയില്‍ (തവി) എത്ര കാലം കറിയില്‍ കിടന്നാലും അതിന് കറിയുടെ സ്വാദ് അറിയാറാകയില്ല.",
  "65": "നാവ് സ്പര്‍ശത്താല്‍ കറിയുടെ രസത്തെ അറിയുന്നതെങ്ങനെയോ അങ്ങിനെതന്നെ ബുദ്ധിമാന്‍ മഹാത്മാക്കളുമായുള്ള ക്ഷണനേരത്തെ സമ്പര്‍ക്കത്താല്‍ ധര്‍മ്മജ്ഞാനം ലഭിക്കുന്നു.",
  "66": "വിവേകവും പഠിപ്പുമില്ലാത്തവര്‍ ആത്മശത്രുക്കളായി നടക്കുന്നു; അവര്‍ ദുഷ്കര്‍മ്മം ചെയ്യുകയും ഫലം കഠിനമായിത്തീരുകയും ചെയ്യുന്നു.",
  "67": "പശ്ചാത്താപത്തിന് ഇടവരുത്തുന്ന കര്‍മ്മവും അശ്രുവിനും രോദനത്തിനും കാരണമായിത്തീരുന്ന കര്‍മ്മവും സത്കര്‍മ്മമല്ല.",
  "68": "പശ്ചാത്താപത്തിന് ഇടവരാതെയും സന്തോഷത്തിനും സഖ്യത്തിനും കാരണമായും തീരുന്ന കര്‍മ്മം സത്കര്‍മ്മമാകുന്നു.",
  "69": "അവിവേകിക്ക് തന്റെ ദുഷ്കര്‍മ്മം പരിപാകം വരുന്നതുവരെ തേന്‍ പോലെ രസകരമായി തോന്നുന്നു. എന്നാല്‍ കര്‍മ്മത്തിന് പാകം വന്നാല്‍ പിന്നെ അവന്‍ ദുഃഖം അനുഭവിക്കുകയും ചെയ്യുന്നു.",
  "70": "അവിവേകിയായ പുരുഷന്‍ മാസത്തിലൊരിക്കല്‍ കുശാഗ്രം കൊണ്ട് ഭക്ഷണമെടുത്തു ഭക്ഷിച്ച് ജീവനെ നിറുത്തുന്നതായാല്‍കൂടി അവന് ധര്‍മ്മിഷ്ഠന്മാര്‍ക്ക് കിട്ടുന്നതില്‍ പതിനാറിലൊരംശം ഫലം ലഭിക്കുന്നതല്ല.",
  "71": "പാപകര്‍മ്മത്തിന്റെ ഫലം പാല്‍ ഉറ കൂടുന്നതുപോലെ വേഗത്തില്‍ വികാരം പ്രാപിക്കുന്നതല്ല. ഭസ്മച്ഛന്നമായ അഗ്നിയെന്നപോലെ അത് മൂഢനിലിരുന്ന് ക്രമേണ നശിപ്പിക്കുന്നു.",
  "72": "മൂഢന് അനര്‍ത്ഥത്തിനായിക്കൊണ്ടുള്ള ജ്ഞാനം എപ്പോള്‍ ഉണ്ടാകുന്നുവോ അവന്റെ സഖ്യം (ശുദ്ധാംശം) നശിക്കുകയും മൂര്‍ദ്ധാവ് പൊട്ടിത്തെറിക്കുകയും ചെയ്യുന്നു.",
  "73": "മൂഢന്മാരും മൂര്‍ഖന്മാരുമായ മനുഷ്യര്‍ അസത്യവസ്തുക്കളെ കൊതിക്കുന്നു. ഭിക്ഷുക്കളുടെയിടയില്‍ മുന്‍പനാകാന്‍ ശ്രമിക്കുന്നു; തങ്ങള്‍ നിവസിക്കുന്നിടത്ത് ഐശ്വര്യമുണ്ടാകാന്‍ അഭിലഷിക്കുന്നു. പരകുലങ്ങളില്‍ ആദരവും, സല്‍ക്കാരവും പൂജയും ലഭിക്കണമെന്നാഗ്രഹിക്കുന്നു.",
  "74": "എല്ലാ ലൗകികന്മാരും സന്യാസികളും എന്റെ കര്‍മ്മങ്ങളെ അനുമോദിക്കണം, അവര്‍ എന്റെ ആജ്ഞയെ നടത്തുകയും നിരോധനങ്ങളെ വിലവെക്കുകയും വേണം' എന്നിങ്ങനെ സങ്കല്പിച്ചുവരുന്ന മൂര്‍ഖന് മോഹവും ഗര്‍വ്വവും വര്‍ദ്ധിക്കുന്നു.",
  "75": "ലാഭത്തിന്നുള്ള ആഗ്രഹം വേറെ; നിര്‍വ്വാണത്തിലേക്കുള്ള മാര്‍ഗ്ഗം വേറെ; ഇങ്ങിനെ വിശേഷജ്ഞാനം വന്നിട്ടുള്ള ബുദ്ധശിഷ്യനായ ഭിക്ഷു സല്‍ക്കാരത്തെ അഭിനന്ദിക്കാതെ ഏകാന്തവാസത്തെ മാത്രം ശ്രദ്ധിക്കട്ടെ.",
  "chap6": "പണ്ഡിതവഗ്ഗോ",
  "76": "നിധികളുടെ ഇരിപ്പിടം പറഞ്ഞുകൊടുക്കുന്നവരെപ്പോലെ വര്‍ജ്യകാര്യങ്ങളിന്നിന്നവയെന്നു പറഞ്ഞുകൊടുക്കുന്ന ആള്‍ നിഗൃഹീതവാദിയും മേധാവിയുമാണ്. ഇത്തരക്കാരെയാണ് കൂട്ടിന് കൂട്ടേണ്ടത്. അത്തരക്കാരുടെ കൂടെ നടക്കുന്നവര്‍ക്ക് പുണ്യമേ ലഭിക്കൂ; പാപം തട്ടുകയില്ല.",
  "77": "ഉപദേശിക്കുകയും അച്ചടക്കം ശീലിക്കുകയും അസഭ്യാചരണങ്ങളില്‍നിന്ന് നിവാരണം ചെയ്യുകയും ചെയ്യുന്ന മനുഷ്യന്‍ സത്യവാദികള്‍ക്കും സജ്ജനങ്ങള്‍ക്കും പ്രിയനായി ഭവിക്കുന്നു. അസജ്ജനങ്ങള്‍ക്ക് അപ്രിയനായും.",
  "78": "പാപികളായ മിത്രങ്ങളെ ആശ്രയിച്ചുകഴിയരുത്, അധമപുരുഷന്മാരോടു കൂടിക്കഴിയരുത്. മംഗലകാരികളായ മിത്രങ്ങളെ ആശ്രയിക്കുക. ഉത്തമപുരുഷന്മാരോടു സഹവസിച്ചുകഴിയുക. ഇതാണ് നന്മയ്ക്ക് വഴി.",
  "79": "ധര്‍മ്മത്തെ പാലിക്കുന്നവന്‍ പ്രസന്നചിത്തനായി സുഖമായി ശയിക്കുന്നു (ഉറങ്ങുന്നു). പണ്ഡിതന്‍ ആര്യന്മാര്‍ പ്രതിപാദിച്ച ധര്‍മ്മത്തില്‍ സദാ രമിക്കുന്നു.",
  "80": "(ജലഗതാഗതത്തിന്) തോടുകള്‍ നിര്‍മ്മിക്കുന്നവര്‍ വെള്ളം (ഒരിടത്തുനിന്നു മറ്റിടത്തേക്ക്) കൊണ്ടുപോകുന്നു. അസ്ത്രങ്ങളുണ്ടാക്കുന്നവര്‍ അവ അണച്ച് മൂര്‍ച്ചകൂട്ടുന്നു (മൂര്‍ച്ചകൂട്ടി ആഴത്തില്‍ തറപ്പിക്കുന്നു). ആശാരിമാര്‍ മരത്തെ ശരിപ്പെടുത്തുന്നു. പണ്ഡിതന്മാര്‍ ആത്മാവിനെ ദമനം ചെയ്യുന്നു.",
  "81": "ഒറ്റക്കട്ടിയായ പര്‍വ്വതം കാറ്റു തട്ടുമ്പോള്‍ ഇളക്കം തട്ടാതിരിക്കുന്നപോലെ പണ്ഡിതന്മാര്‍ നിന്ദിക്കപ്പെട്ടാലും പ്രശംസിച്ചാലും ഭാവഭേദംകൂടാതെ സ്ഥിരമായിരിക്കുന്നു.",
  "82": "അഗാധജലാശയങ്ങള്‍ സ്വച്ഛനിര്‍മ്മലങ്ങളായിരിക്കുന്നപോലെതന്നെ പണ്ഡിതന്മാര്‍ ധര്‍മ്മങ്ങളെ ശ്രവിച്ച് പ്രസന്നമനസ്സുകളായിരിക്കും.",
  "83": "സല്‍പുരുഷന്മാര്‍ സര്‍വ്വത്ര സഞ്ചരിക്കുന്നു. സത്തുക്കള്‍ കാമ്യവസ്തുക്കളില്‍ ഭ്രമിച്ച് വ്യര്‍ത്ഥപ്രലാപം ചെയ്യുന്നില്ല. സുഖം കിട്ടിയാലും ദുഃഖം തട്ടിയാലും പണ്ഡിതന്മാര്‍ ഉച്ചഭാവത്തെയോ നീചഭാവത്തെയോ ഉയര്‍ച്ചയെയോ താഴ്ചയെയോ പ്രദര്‍ശിപ്പിക്കുന്നില്ല.",
  "84": "തനിക്കുവേണ്ടിയോ പരന്മാര്‍ക്കുവേണ്ടിയോ പുത്രനെ ആഗ്രഹിക്കരുത്; ധനത്തെയും ആഗ്രഹിക്കരുത്; അധര്‍മ്മപ്രവൃത്തിയാല്‍ തന്റെ സമൃദ്ധിയെയും ആഗ്രഹിക്കരുത്. അങ്ങനെയുള്ളവന്‍ ശീലവാനും പ്രജ്ഞാവാനും ധാര്‍മ്മികനും ആയിരിക്കും.",
  "85": "കര കടക്കുന്നവര്‍ ചുരുക്കമാണ്. ഭൂരിപക്ഷംവരുന്ന മറ്റുള്ളവര്‍ കരയ്ക്കടുത്തുക്കൂടി പരിഭ്രമിച്ചോടുന്നവരാണ്.",
  "86": "എന്നാല്‍ സമ്യക് ഉപദിഷ്ടങ്ങളായ ധര്‍മ്മത്തെ അനുസരിച്ചാചരിക്കുന്നവര്‍ വളരെ ബുദ്ധിമുട്ടി കടന്നെത്തേണ്ടുന്നതായ മൃത്യുരാജ്യത്തിന്നക്കരെ ചെന്നെത്തുന്നു.",
  "87": "പണ്ഡിതന്‍ തമോവര്‍ഗ്ഗത്തെ വിട്ടു സാത്വികാവസ്ഥയെ കൈക്കൊള്ളണം. സ്വഗൃഹത്തെ വിട്ടു വിജനസ്ഥാനത്തെത്തി മുന്‍пуണ്ടാകുവാന്‍ പ്രയാസമാണെന്നു തോന്നീട്ടുള്ള സുഖത്തെ ആ വിജനസ്ഥിതിയില്‍ ഉണ്ടാക്കുവാന്‍ ശ്രമക്കണം.",
  "88": "പണ്ഡിതന്‍ സര്‍വ്വകാമങ്ങളെയും തള്ളിയും സ്വാര്‍ത്ഥബുദ്ധി ലേശമില്ലാതെയും മാനസികങ്ങളായ സകല ക്ലേശങ്ങളില്‍നിന്നും ആത്മാവിനെ ശുദ്ധമാക്കണം.",
  "89": "ഏഴു ബോധ്യംഗങ്ങളില്‍ മനസ്സു നിറുത്തിക്കൊണ്ടു മനസ്സിന് യാതൊന്നിലും സക്തികൂടാതെയും നിസ്സംഗത്തില്‍ പ്രീതരായും തൃഷ്ണകളടക്കിയും പ്രകാശിക്കുന്നത് ഏവരോ അവര്‍തന്നെ ജീവന്മുക്തന്മാരാകുന്നു.",
  "chap7": "അരഹന്തവഗ്ഗോ",
  "90": "ലോകയാത്രയില്‍നിന്ന് നിവൃത്തനും ശോകമൊഴിഞ്ഞവനും സര്‍വ്വബന്ധങ്ങളില്‍നിന്ന് വിമുക്തനുമായ മനുഷ്യന് അരിഷ്ടം സംഭവിക്കുന്നില്ല.",
  "91": "അവര്‍ വിചാരങ്ങളെ നല്ല നിലയില്‍ നിര്‍ത്തിക്കൊണ്ട് ഉദ്യമിക്കുന്നു. അവര്‍ ഗൃഹത്തില്‍ രമിക്കുന്നില്ല. ഹംസങ്ങള്‍ പൊയ്കയെ വിട്ടുപോകുന്നപോലെ അവര്‍ തങ്ങളുടെ വീടും ദേശവും ഉപേക്ഷിക്കുന്നു.",
  "92": "യാതൊരു മുതലും ഇല്ലാത്തവരും ഭോജനത്തില്‍ കൃത്യമുള്ളവരും നിര്‍ഗുണമായും രാഗാദിവിമുക്തമായും ഇരിക്കുന്ന മോക്ഷത്തിന്റെ ജ്ഞാനമുള്ളവരും ആയിരിക്കുന്നവര്‍ ഏവചിലരോ അവരുടെ മാര്‍ഗ്ഗം ആകാശത്തില്‍ പക്ഷികളുടെ മാര്‍ഗ്ഗമെന്നപോലെ കണ്ടുപിടിപ്പാന്‍ പ്രയാസമുള്ളതാകുന്നു.",
  "93": "തൃഷ്ണകള്‍ ക്ഷയിച്ച് ആഹാരാദികളില്‍ വിമോഹിക്കാതെയും, നിര്‍ഗുണമായും രാഗാദിവിമുക്തമായും ഇരിക്കുന്ന മോക്ഷത്തിന്റെ ജ്ഞാനമുള്ളവരുടെ മാര്‍ഗ്ഗം ആകാശത്തില്‍ പക്ഷികളുടെ മാര്‍ഗ്ഗമെന്നപോലെ അറിവാന്‍ പ്രയാസമുള്ളതാകുന്നു.",
  "94": "സാരഥി കുതിരകളെ ഒരുക്കുന്നതുപോലെ ഇന്ദ്രിയങ്ങളൊതുക്കിയും അഹങ്കാരവും തൃഷ്ണയുമില്ലാതെയുമുള്ള ഒരുവന്‍ ദേവന്മാര്‍ക്കുകൂടി അനുകരണീയനാകുന്നു, സ്പൃഹണീയനാകുന്നു.",
  "95": "ഭൂമിപോലെ ക്ഷമയും വാതില്‍ത്തഴുതുപോലെ ഉറപ്പും ചളിയൊഴിഞ്ഞ തടാകംപോലെ കലക്കുവാന്‍ പ്രയാസവും ഉള്ളവനാരോ അവന് സംസാരബന്ധം ഭവിക്കുകയില്ല.",
  "96": "സമ്യഗ്ബോധത്താല്‍ വിമുക്തനായും ഉപശാന്തനായും ഇരിക്കുന്നവന്റെ മനസ്സ് ശാന്തമായിത്തീരുന്നു. വാക്കും കര്‍മ്മവും ശാന്തങ്ങളാകുന്നു.",
  "97": "അന്ധവിശ്വാസമില്ലാതെയും നിര്‍വ്വാണത്തെ അറിഞ്ഞും ബന്ധങ്ങളെല്ലാം ഛേദിച്ചും ആശകളൊഴിച്ചും ഏതൊരു മനുഷ്യനുണ്ടോ അവന്‍ മനുഷ്യരില്‍വെച്ച് ഉത്തമപുരുഷനാകുന്നു.",
  "98": "ഗ്രാമത്തിലോ വനത്തിലോ ജലത്തിലോ സ്ഥലത്തിലോ എവിടെയായാലും വന്ദ്യപുരുഷന്മാര്‍ (അര്‍ഹതന്മാര്‍) വസിക്കുന്ന ഭൂമി രമണീയമാകുന്നു.",
  "99": "സാധാരണജനങ്ങള്‍ രമിക്കാത്തതായ അരണ്യങ്ങള്‍ വീതരാഗന്മാര്‍ക്ക് (അര്‍ഹതന്മാര്‍ക്ക്) രമണീയസ്ഥലങ്ങളാകുന്നു. അവര്‍ കാമങ്ങളെ അന്വേഷിച്ചുനടക്കുന്നവരല്ല.",
  "chap8": "സഹസ്സവഗ്ഗോ",
  "100": "നിരര്‍ത്ഥകങ്ങളായ ആയിരം വാക്കുകളെ പ്രസംഗിക്കുന്നതിനേക്കാള്‍ നല്ലത് അര്‍ത്ഥവത്തായ ഒരു വാക്ക് സംസാരിക്കുകയാകുന്നു. അതിനെ കേള്‍ക്കുന്നവന്‍ ഉപശാന്തനായി ഭവിക്കുന്നു.",
  "101": "അര്‍ത്ഥമില്ലാത്ത ആയിരമായിരം ശ്ലോകങ്ങളെക്കാളും ശ്രേഷ്ഠമായിട്ടുള്ളത് അര്‍ത്ഥവത്തായ ഒരു ശ്ലോകമാകുന്നു. അതിനെ ശ്രവിക്കുന്നവന്‍ ഉപശാന്തനായിത്തീരുന്നു.",
  "102": "നിരര്‍ത്ഥകങ്ങളായ നൂറു ഗാഥകളെ ചൊല്ലുന്നതിലും നല്ലത് ഒരു ധര്‍മ്മപദത്തെ ചൊല്ലുകയാകുന്നു. അത് കേള്‍ക്കുന്നവന്‍ ശാന്തനായിത്തീരുന്നു.",
  "103": "ആയിരമായിരം (പത്തുലക്ഷം) മനുഷ്യരെ യുദ്ധത്തില്‍ ജയിച്ചവനേക്കാള്‍ തന്നെത്താന്‍ ജയിച്ചവനാകുന്നു അധികം ശ്രേഷ്ഠന്‍ (സംഗ്രാമജിത്ത് - യുദ്ധവിജയി).",
  "104": "തന്നെത്താന്‍ ജയിച്ചവന്‍ മറ്റെല്ലാവരെക്കാളും ശ്രേഷ്ഠനാകുന്നു.",
  "105": "ദേവനോ ഗന്ധര്‍വ്വനോ ബ്രഹ്മാവിനോ മാരനോ അവനവനെ ജയിച്ചു നിത്യശാന്തനായിരിക്കുന്നവന്റെ ജയത്തെ അപജയമാക്കിത്തീര്‍ക്കുവാന്‍ കഴിയില്ല.",
  "106": "ഒരുവന്‍ നൂറുവര്‍ഷക്കാലം മാസംതോറും അനവധി ദ്രവ്യം ചെലവിട്ട് യാഗങ്ങളെ ചെയ്യുകയും യഥാര്‍ത്ഥജ്ഞാനത്തില്‍ സ്ഥിരചിത്തനായ ഒരാളെ മുഹൂര്‍ത്തനേരം പൂജചെയ്യുകയുമായാള്‍ നൂറു വര്‍ഷക്കാലത്തെ യാഗങ്ങളെക്കാളധികം നല്ലത് അപ്രകാരമുള്ള പൂജയാകുന്നു.",
  "107": "നൂറുവര്‍ഷക്കാലം വനത്തില്‍ അഗ്നിയെ സേവിക്കുകയും ഒരു യഥാര്‍ത്ഥജ്ഞാനിയെ മുഹൂര്‍ത്തനേരം പൂജിക്കുകയും ചെയ്യുന്നതായാല്‍ നൂറു വര്‍ഷത്തെ യജ്ഞത്തെക്കാളധികം ശ്രേഷ്ഠത ആ പൂജയ്ക്കാകുന്നു.",
  "108": "ലോകത്തില്‍ ഒരുവന്‍ പുണ്യത്തെ അപേക്ഷിച്ചുകൊണ്ട് ഒരു വര്‍ഷം മുഴുവനും യജ്ഞവും ഹോമവും ചെയ്യുന്നതായാലും അതിന്നാകപ്പാടെയുള്ള ഫലം നിസ്സാരമാകുന്നു. ഋജുഗതികളില്‍ (നേരുള്ളവരില്‍) ചെയ്യുന്ന അഭിവാദ്യം മേല്‍പറഞ്ഞതിനേക്കാള്‍ അധികം ശ്രേഷ്ഠമാകുന്നു.",
  "109": "എന്നും വൃദ്ധന്മാരെ വന്ദിക്കുകയും പൂജിക്കുകയും ചെയ്യുന്നവന് ആയുസ്സ്, സൗന്ദര്യം, സുഖം, ബലം ഈ നാലും വര്‍ദ്ധിച്ചുവരും.",
  "110": "ദുശ്ശീലത്തോടും അസ്ഥിരബുദ്ധിയോടുംകൂടി നൂറു വര്‍ഷം ജീവിച്ചിരിക്കുന്നതിലും നല്ലത് സുശീലത്തോടും ധ്യാനഗുണത്തോടുംകൂടി ഒരു ദിവസം ജീവിച്ചിരിക്കുന്നതാകുന്നു.",
  "111": "അജ്ഞാനിയും അശാന്തനുമായി നൂറു വര്‍ഷം ജീവിച്ചിരിക്കുന്നതിനേക്കാള്‍ അധികം നല്ലത് ജ്ഞാനിയും ധ്യാനശീലനുമായി ഒരു ദിവസം ജീവിച്ചിരിക്കുകയാകുന്നു.",
  "112": "കുത്സിതനും (മടിയനും) വീര്യഹീനനുമായി നൂറു വര്‍ഷം ജീവിച്ചിരിക്കുന്നതിനേക്കാള്‍ നല്ലത് വീര്യത്തോടുകൂടി ഒരു ദിവസം ജീവിച്ചിരിക്കുകയാകുന്നു.",
  "113": "ആരംഭവും അവസാനവും കണ്ടറിയാതെ നൂറു വര്‍ഷം ജീവിച്ചിരിക്കുന്നതിലും ഭേദം ആരംഭാവസാനങ്ങളെ കണ്ടറിഞ്ഞ് ഒരു ദിവസം ജീവിക്കുന്നതാണ്.",
  "114": "അമൃതമായ പദത്തെ (നിര്‍വ്വാണപദം) കാണാതെ നൂറുവര്‍ഷം ജീവിക്കുന്നതിനേക്കാള്‍ നല്ലത് അമൃതപദത്തെ കണ്ട് ഒരു ദിവസം ജീവിക്കുന്നതാണ്.",
  "115": "ഉത്തമമായ ധര്‍മ്മത്തെ കാണാതെ നൂറു വര്‍ഷക്കാലം ജീവിച്ചിരിക്കുന്നതിനേക്കാള്‍ നല്ലത് ഉത്തമധര്‍മ്മത്തെ കണ്ടറിഞ്ഞ് ഒരു ദിവസം ജീവിക്കുകയാകുന്നു.",
  "chap9": "പാപവഗ്ഗോ",
  "116": "മനുഷ്യന്‍ പുണ്യം ചെയ്യുന്നത് വേഗത്തില്‍ വേണ്ടതും പാപത്തില്‍നിന്ന് മനസ്സിനെ നിവാരണം ചെയ്യേണ്ടതുമാകുന്നു. പുണ്യത്തെ ചെയ്യാന്‍ മന്ദിക്കുന്നവന്റെ മനസ്സ് പാപത്തില്‍ രമിക്കുന്നു.",
  "117": "ഒരുവന്‍ പാപം ഒരിക്കല്‍ ചെയ്തുപോയാലും വീണ്ടും ചെയ്യരുത്. അവന്‍ അതില്‍ മനസ്സ് നിറുത്തരുത്. പാപം വര്‍ദ്ധിച്ചുകൂടുന്നത് ദുഃഖകരമാകുന്നു.",
  "118": "പുണ്യത്തെയാകട്ടെ ഒരിക്കല്‍ ചെയ്താല്‍ പിന്നെയും പിന്നെയും ചെയ്യണം. അതില്‍ മനസ്സു രമിക്കണം. പുണ്യം കൂടിവരുന്നത് സന്തോഷകരമാകുന്നു (സുഖമാകുന്നു).",
  "119": "പാപി പാപത്തിന് പരിപാകം വരുന്നതുവരെ പാപത്തെ സുഖമായി കാണുന്നു. പാപം പരിപക്വമായാല്‍ അവന്‍ പാപത്തെ കണ്ടുതുടങ്ങുന്നു.",
  "120": "പുണ്യവാന്‍ തന്റെ പുണ്യത്തിന് പരിപാകം വരുന്നതുവരെ എല്ലാം ദുഃഖമായി (പാപമായി) കാണുന്നു. പുണ്യത്തിന് പരിണാമം വന്നാല്‍ പുണ്യവാന്‍ പുണ്യത്തെ കാണുന്നു.",
  "121": "തനിക്കു അതിന്റെ ഫലം വരികയില്ലെന്നു കരുതി പാപത്തെ ലഘുവായിട്ടാരും വിചാരിക്കരുത്. വെള്ളം തുള്ളി തുള്ളിയായിട്ട് വീണ് ക്രമേണ കുടം നിറയുന്നതുപോലെ മൂഢനില്‍ പാപം അല്പാല്പമായി സ്വരൂപിച്ച് ക്രമേണ നിറയുന്നു.",
  "122": "പുണ്യം തനിക്കുണ്ടാവില്ലെന്നു കരുതി പുണ്യത്തെ നിസ്സാരമായി വിചാരിക്കരുത്. വെള്ളം തുള്ളിതുള്ളിയായി വീണാലും കുടം നിറയുന്നു. അറിവുള്ളവന്‍ അല്പാല്പമായി സമ്പാദിച്ച പുണ്യങ്ങളാല്‍ ക്രമേണ പരിപൂര്‍ണ്ണനാകുന്നു.",
  "123": "ഒരു കച്ചവടക്കാരന്‍ അധികം ദ്രവ്യത്തോടുകൂടി പോകുമ്പോള്‍ സഹായികള്‍ ഇല്ലാതെയിരുന്നാല്‍ അപായമുള്ള മാര്‍ഗ്ഗത്തെ വര്‍ജ്ജിക്കുന്നതുപോലെയും ജീവനില്‍ ആശയുള്ളവന്‍ വിഷത്തെ വര്‍ജ്ജിക്കുന്നതുപോലെയും മനുഷ്യന്‍ പാപകര്‍മ്മങ്ങളെ വര്‍ജ്ജിക്കണം.",
  "124": "കൈയിന്മേല്‍ വ്രണമില്ലാത്തവര്‍ക്ക് വിഷത്തെ സ്പര്‍ശിക്കുവാന്‍ കഴിയും, വ്രണമില്ലാത്തവനില്‍ വിഷം പ്രവേശിക്കുകയില്ല. പാപകളും ചെയ്യാത്തവനില്‍ പാപവും പ്രവേശിക്കുന്നില്ല.",
  "125": "ഒരുവന്‍ നിര്‍ദ്ദोषിയും ശുദ്ധനും നിരപരാധിയുമായവന്റെ നേരെ ദോഷം ചെയ്യുന്നതായാല്‍ ആ ദോഷം വായുവിന്നെതിരെ എറിയപ്പെട്ട പൊടിയെന്നപോലെ ആ മൂഢനെത്തന്നെ തിരിഞ്ഞടിക്കുന്നു.",
  "126": "ചില ജനങ്ങള്‍ (മരണശേഷം) പിന്നെയും ജനിക്കുന്നു. പാപികള്‍ നരകത്തില്‍ പതിക്കുന്നു. സുകൃതികള്‍ സ്വര്‍ഗ്ഗത്തെ പ്രാപിക്കുന്നു. തൃഷ്ണാരഹിതന്മാര്‍ നിര്‍വ്വാണം പ്രാപിക്കുന്നു.",
  "127": "ആകാശത്തിലോ സമുദ്രമദ്ധ്യത്തിലോ പര്‍വ്വതഗഹ്വരത്തിലോ എന്നല്ല ലോകത്തൊരേടത്തും പാപകര്‍മ്മം ചെയ്തവന്‍ അതിന്റെ ഫലത്തില്‍നിന്ന് മോചനം കിട്ടുന്നതായ പ്രദേശമില്ല.",
  "128": "ആകാശത്തിലോ സമുദ്രമദ്ധ്യത്തിലോ പര്‍വ്വതഗഹ്വരത്തിലോ എന്നല്ല ലോകത്തൊരേടത്തും ചെന്നാലും, മരണം ബാധിക്കാത്തതായ പ്രദേശത്തെ കാണുകയില്ല.",
  "chap10": "ദണ്ഡവഗ്ഗോ",
  "129": "സര്‍വ്വജനങ്ങളും ദണ്ഡത്തെ (ശിക്ഷയെ) ഓര്‍ത്തു വിറയ്ക്കുന്നു. സര്‍വ്വജനങ്ങളും മൃത്യുവില്‍നിന്ന് ഭയപ്പെടുന്നു. സകല ജീവികളെയും തന്നെപ്പോലെതന്നെ കരുതി ആരെയും ഹിംസിക്കുകയോ ഹിംസിപ്പിക്കുകയോ ചെയ്യാതിരിക്കുക.",
  "130": "സകല ജീവികളും ദണ്ഡത്തെ ഭയപ്പെടുന്നു; ജീവിതം എല്ലാവര്‍ക്കും പ്രിയമാകുന്നു. അതിനാല്‍ മറ്റുള്ളവരെയും തന്നെപ്പോലെ വിചാരിച്ച് നിഗ്രഹിക്കുകയോ നിഗ്രഹിപ്പിക്കുകയോ ചെയ്യാതിരിക്കണം.",
  "131": "ഏതൊരുവനാകുന്നു തന്റെ സുഖത്തിന് വേണ്ടി സുഖകാമികളായ ജീവികളെ ദണ്ഡിക്കുകയോ വധിക്കുകയോ ചെയ്യുന്നത് അവന് പരലോകത്തില്‍ സുഖം ലഭിക്കുന്നില്ല.",
  "132": "ആത്മസുഖാഭിലാഷികളായ പ്രാണികളെ തന്റെ സുഖത്തിന് വേണ്ടി ദണ്ഡിക്കുകയോ ഹിംസിക്കുകയോ ചെയ്യാതിരിക്കുന്നവന്‍ പരലോകസുഖത്തെ അനുഭവിക്കുന്നു.",
  "133": "ആരോടും പരുഷവാക്ക് പറയരുത്. അങ്ങോട്ട് പറഞ്ഞ പ്രകാരം ഇങ്ങോട്ട് പറയും. തമ്മില്‍ കയര്‍ക്കുവാനിടവരുന്നത് ദുഃഖകരമാണ്. ദണ്ഡിക്കുന്നവന് പകരം ദണ്ഡം കിട്ടുന്നതാണ്.",
  "134": "പൊട്ടിയ ചേങ്ങലപോലെ നിശ്ശബ്ദനായിരിക്കുന്നതായാല്‍ നിങ്ങള്‍ നിര്‍വ്വാണം പ്രാപിച്ചുകഴിഞ്ഞു. എന്തുകൊണ്ടെന്നാല്‍ നിങ്ങളില്‍ ക്രോധാവേശം കാണുന്നതല്ല.",
  "135": "ഗോപാലന്‍ ഏതുവിധം ദണ്ഡുകൊണ്ട് പശുക്കളെ മേച്ചില്‍സ്ഥലത്തേക്ക് ആട്ടിക്കൊണ്ടുപോകുന്നുവോ അതേവിധം ജരയും മൃത്യുവും പ്രാണികളുടെ ആയുസ്സിനെ ആട്ടിക്കൊണ്ടുപോകുന്നു.",
  "136": "മൂഢന്‍ പാപകര്‍മ്മങ്ങള്‍ ചെയ്യുമ്പോഴും അറിയുന്നില്ല. ദുര്‍ബുദ്ധി അഗ്നിയാലെന്നപോലെ സ്വകര്‍മ്മങ്ങളാല്‍ ദഹിക്കപ്പെടുന്നു.",
  "137": "അദണ്ഡ്യന്മാരും നിര്‍ദ്ദോഷികളുമായവരെ ദണ്ഡിക്കുന്നവന്‍ താഴെ പറയുന്ന പത്തവസ്ഥകളില്‍ ഒന്നില്‍ ക്ഷണത്തിലെത്തും:",
  "138": "അവന് കഠിനവേദന, ധനനാശം (ഹാനി), ശരീരഭംഗം, കഠോരരോഗം, ഭ്രാന്ത് എന്നിവ ഉണ്ടാകുന്നു.",
  "139": "അഥവാ രാജാവില്‍നിന്ന് ആപത്ത്, കഠിനമായ ദോഷാരോപണം, ബന്ധുനാശം, ഭോഗങ്ങളുടെ നാശം എന്നിവ സംഭവിക്കുന്നു.",
  "140": "അല്ലെങ്കില്‍ ഗൃഹം ഇടിത്തീ വീണ് ദഹിക്കുന്നു. ആ ദുര്‍ബുദ്ധി മരണശേഷം നരകത്തില്‍ വീഴുന്നു.",
  "141": "അവധൂതചര്യ, ജടാധാരണം, ചളിതേച്ച് കുളിക്കുക, ഉപവാസം ചെയ്യുക, വെറും നിലത്ത് കിടന്നുറങ്ങുക, പൊടിവാരിത്തേയ്ക്കുക, ഉല്‍ക്കുടികാസനം ഇതൊന്നും തൃഷ്ണയൊഴിയാത്തവന് ശുദ്ധി വരുത്തുന്നതല്ല.",
  "142": "ഒരുവന്‍ ഭംഗിയില്‍ അലങ്കരിക്കുന്നവനായാലും അതോടുകൂടി ശാന്തനും, ദാന്തനും, നിയതനും, ബ്രഹ്മചാരിയും സര്‍വ്വഭൂതങ്ങളിലും ദണ്ഡമൊഴിച്ചവനുമായിരിക്കുന്നതായാല്‍ അവനാകുന്നു ബ്രാഹ്മണന്‍; അവനാണ് ശ്രമണന്‍; അവനാണ് ഭിക്ഷു.",
  "143": "നല്ല ശീലമുള്ള കുതിരയ്ക്ക് ചാട്ടവാര്‍ ആവശ്യമില്ല. അതുപോലെ ഒരിക്കലും ശകാരത്തിന് വിഷയമാകാത്ത വിധത്തില്‍ അധര്‍മ്മഭീരുവായിട്ട് ഈ ലോകത്തില്‍ ആരാണുമുള്ളത്?",
  "144": "ശിക്ഷിതമായ ഒരശ്വം ചാട്ടവാറിനാല്‍ സ്പര്‍ശിക്കപ്പെട്ടതുപോലെ നിങ്ങള്‍ ശ്രദ്ധയോടും, ശീലത്തോടും, വീര്യത്തോടും, സമാധിയോടും, ധര്‍മ്മവിനിശ്ചയത്തോടും, വിദ്യാചരണങ്ങളോടും കൂടി ജാഗരൂകരായി ഈ മഹാദുഃഖത്തെ തരണം ചെയ്യുവിന്‍.",
  "145": "തോടു വെട്ടുന്നവര്‍ വെള്ളം കൊണ്ടുപോകുന്നു. അമ്പുണ്ടാക്കുന്നവര്‍ അമ്പിനെ നേരെയാക്കുന്നു. ആശാരി മരം ശരിപ്പെടുത്തുന്നു. ഇതേവിധം സുവ്രതന്മാര്‍ (പണ്ഡിതന്മാര്‍) സ്വയം ദമനം ചെയ്യുന്നു.",
  "chap11": "ജരാവഗ്ഗോ",
  "146": "ലോകം എന്നും ദഹിച്ചുകൊണ്ടിരിക്കെ എന്തു ചിരിയാകുന്നു? എന്തു സന്തോഷമാകുന്നു? ഇരുട്ടിനാല്‍ മൂടപ്പെട്ട നിങ്ങള്‍ക്ക് ഒരു പന്തക്കൊള്ളി കിട്ടിയാല്‍ നന്നെന്നു തോന്നുന്നില്ലയോ? (വെളിച്ചം എന്തുകൊണ്ടന്വേഷിക്കുന്നില്ല?)",
  "147": "ചിത്രമെഴുതിയപോലുള്ള ഈ ബിംബത്തെ (ദേഹത്തെ) നോക്കുക. ഇത് വ്രണപൂര്‍ണ്ണവും പരസ്പരം കൂടിപ്പിണഞ്ഞതും വ്യാധിതവും അനേകസങ്കല്പങ്ങളോടുകൂടിയതും ആകുന്നു. ഇതിന് ഒരിക്കലും സ്ഥിരതയില്ല.",
  "148": "ഈ രൂപം ജീര്‍ണ്ണവും ഭംഗം വരാനെളുപ്പമുള്ളതുമാകുന്നു. അഴുക്കുകളുടെ കൂട്ടമായ ഈ ദേഹം നശിച്ചുപോകും. ജീവിതാവസാനം മരണമാകുന്നു.",
  "149": "വേനല്‍ക്കാലത്ത് എറിയപ്പെട്ട ചുരയ്ക്കാക്കുടുക്കകള്‍ പോലെ കപോതവര്‍ണ്ണത്തിലുള്ള ഈ അസ്ഥികള്‍ കാണുന്ന ഏതൊരുവനാണ് സന്തോഷമുണ്ടാകുന്നത്?",
  "150": "അസ്ഥികളെ കൊണ്ട് ഒരു നഗരമുണ്ടാക്കി അത് മാംസരക്തങ്ങളെ കൊണ്ട് തേച്ചുമിനുക്കിയിരിക്കുന്നു. ഈ നഗരത്തില്‍ ജര, മൃത്യു, അഹംകാരം, ഈര്‍ഷ്യ എന്നിവര്‍ പാര്‍ത്തു വരുന്നു.",
  "151": "പല ചിത്രപ്പണികള്‍ ചേര്‍ന്ന രാജരഥങ്ങളും ജീര്‍ണ്ണിച്ചുപോകുന്നു. അതേവിധം മനുഷ്യ ശരീരവും ജീര്‍ണ്ണിക്കുന്നു. സജ്ജനധര്‍മ്മം ജീര്‍ണ്ണമാകുന്നില്ല. ഇങ്ങിനെയാണ് സജ്ജനങ്ങള്‍ക്കു സജ്ജനങ്ങള്‍ ഉപദേശിക്കാറുള്ളത്.",
  "152": "കിഞ്ചിജ്ഞനായ (അറിവില്ലാത്ത) മനുഷ്യന്‍ കൂറ്റന്‍ മൂരിയെപ്പോലെ മൂത്തു വശനാവുന്നു. അവന്റെ മാംസങ്ങള്‍ വളരുന്നു; എന്നാല്‍ പ്രജ്ഞ വളരുന്നുമില്ല.",
  "153": "ഞാന്‍ (ശരീരമാകുന്ന) ഗൃഹത്തെ നിര്‍മ്മിച്ചവനെ അന്വേഷിച്ച് വളരെ ജന്മമായി നടക്കുകയാണ്. അയാളെ കണ്ടുകിട്ടിയിട്ടില്ല. വീണ്ടും വീണ്ടും ജന്മം ദുഃഖമിശ്രിതമാവുകയാണ്.",
  "154": "എന്നാല്‍ എടോ ഗൃഹകാരകാ! നിന്നെ ഞാന്‍ കണ്ടെത്തിയിരിക്കുന്നു. നീ ഇനിമേല്‍ ഗൃഹമുണ്ടാക്കുകയില്ല. ഇതിന്റെ ഉത്തരങ്ങളെല്ലാം മുറിഞ്ഞു; മോന്തായം പൊട്ടിപ്പോയി. സകല തൃഷ്ണയുമൊഴിഞ്ഞ മനസ്സ് വിസംസ്കാരത്തില്‍ (നിര്‍വ്വാണത്തില്‍) എത്തിക്കഴിഞ്ഞു.",
  "155": "വേണ്ടുംവണ്ണം ബ്രഹ്മചര്യമനുഷ്ഠിക്കാതെയും യൗവനകാലത്ത് ധനം സമ്പാദിക്കാതെയുമുള്ള മനുഷ്യര്‍, വാര്‍ദ്ധക്യത്തില്‍ വൃദ്ധന്മാരായ ഞാറപ്പക്ഷികള്‍ മത്സ്യങ്ങളില്ലാത്ത പൊയ്കയിലെന്നപോലെ ഇരുന്ന് മനോരാജ്യം വിചാരിച്ചുകൊണ്ട് കാലം കഴിക്കുന്നു.",
  "156": "ബ്രഹ്മചര്യം കൂടാതെയും യൗവനകാലത്തില്‍ ധനം സമ്പാദിക്കാതെയുമുള്ള മനുഷ്യര്‍ പ്രയോഗിച്ചു തീര്‍ന്ന (മുറിഞ്ഞ) വില്ലുകളെന്നപോലെ പൂര്‍വ്വകഥകളെ ഓര്‍ത്തു ദുഃഖിച്ചുകിടക്കുന്നു.",
  "chap12": "അത്തവഗ്ഗോ",
  "157": "മനുഷ്യന് തന്നോട് (ആത്മാവിനോട്) സ്നേഹമുണ്ടെങ്കിൽ വളരെ കരുതലോടുകൂടി തന്നെത്താൻ സൂക്ഷിച്ചുകൊള്ളണം. രാത്രിയുടെ മൂന്നു യാമങ്ങളിൽ ഒന്നിലെങ്കിലും ബുദ്ധിമാൻ ഉറക്കമൊഴിഞ്ഞ് പ്രത്യേകം ശ്രദ്ധിച്ചിരിക്കണം.",
  "158": "മനുഷ്യൻ ആദ്യമായി തന്നെത്താൻ വേണ്ട നിലയിൽ കൊണ്ടുനടത്തണം (ഉചിതകാര്യത്തിൽ മുഴുകി പ്രവർത്തിക്കണം). അതിനുശേഷമാണ് അന്യനെ അനുശാസിക്കേണ്ടത്. ഇങ്ങനെയുള്ള പണ്ഡിതൻ ക്ലേശിക്കേണ്ടിവരികയില്ല.",
  "159": "ഒരാൾ അന്യന്മാരെ പഠിപ്പിക്കുന്നത് ഏതു പ്രകാരമോ അപ്രകാരം തന്നെത്താൻ അനുഷ്ഠിക്കുന്നതായാൽ അവനാകുന്നു സുദാന്തൻ. അവന് അന്യരെയും ദമനം ചെയ്യാം. ഒരുവന് തന്നെ ഒതുക്കുവാനാകുന്നു പ്രയാസമായിട്ടുള്ളത്.",
  "160": "തന്റെ സ്വാമി താൻതന്നെയാകുന്നു; അല്ലാതെ മറ്റാരാകുന്നു തനിക്ക് സ്വാമി? തന്നെത്താൻ നല്ലവണ്ണം ഒതുക്കിയവൻ അധികം പേർക്കും കണ്ടുകിട്ടാൻ പ്രയാസമുള്ള ഒരു സ്വാമിയെ (ആശ്രയത്തെ) നേടുന്നു.",
  "161": "താൻതന്നെ ഉണ്ടാക്കിയതും തന്നിൽത്തന്നെ ഉണ്ടായതും തന്നിൽത്തന്നെ വളർന്നതുമായ പാപം, വജ്രം കല്ലുമയമായ രത്നത്തെ എന്നപോലെ ആ ദുർബുദ്ധിയെ തകർത്തു കളയുന്നു.",
  "162": "дуശ്ശീലം ഏറ്റവും അധികരിച്ചിട്ടുള്ളവൻ, മാലുവാ വള്ളി പടർന്നുപിടിച്ച സാലവൃക്ഷത്തെപ്പോലെ ആകുന്നു. ശത്രു ആഗ്രഹിക്കുന്നതുപോലെ അവൻ തന്നെത്താൻ നാശത്തിലേക്ക് എത്തിക്കുന്നു.",
  "163": "അവനവന് ദോഷം വരുന്നതായ ദുഷ്കർമ്മങ്ങൾ ചെയ്യാനെളുപ്പമുണ്ട്; ഹിതമായിട്ടും സാധുവായിട്ടുമുള്ളത് ഏതൊന്നോ അത് ചെയ്യാൻ പരമപ്രയാസവുമുണ്ട്.",
  "164": "ഏതൊരു മൂഢനാകുന്നു പാപകരമായ ദൃഷ്ടിയെ ആശ്രയിച്ച്, ധർമ്മിഷ്ഠരും ആര്യന്മാരുമായ അർഹതന്മാരുടെ ശാസനയെ നിന്ദിക്കുന്നത്, അവൻ മുളയെന്നപോലെ തന്റെ സ്വന്തം വിനാശത്തിനായിട്ടാണ് ഫലിക്കുന്നത്.",
  "165": "താൻ ചെയ്ത പാപം കാരണം താൻതന്നെ ക്ലേശിക്കുന്നു. പാപം ചെയ്യാതിരുന്നാൽ താൻതന്നെ വിശുദ്ധനാകുന്നു. ശുദ്ധിയും അശുദ്ധിയും അവനവനിലുള്ളതുതന്നെയാകുന്നു; ഒരുവന് മറ്റൊരാളെ ശുദ്ധീകരിക്കാൻ കഴിയുന്നതല്ല.",
  "166": "അന്യന്റെ വലിയ കാര്യത്തിനുവേണ്ടി അവനവന്റെ സ്വന്തം പരമാരത്ഥത്തെ (ആത്മീയ ലക്ഷ്യത്തെ) ഉപേക്ഷിക്കരുത്. സ്വന്തം കടമയെ കൃത്യമായി അറിഞ്ഞശേഷം ശ്രദ്ധയോടെ അതിൽത്തന്നെ മുഴുകിയിരിക്കണം.",
  "chap13": "ലോകവഗ്ഗോ",
  "167": "നീചധര്‍മ്മത്തെ അനുസരിക്കരുത്. പ്രമാദത്തോടുകൂടിയിരിക്കരുത്. മിഥ്യാദൃഷ്ടിയെ (നാസ്തികമതത്തെ) ആശ്രയക്കരുത്. ലൌകികനായിത്തീരരുത്.",
  "168": "എഴുന്നേല്‍പ്പിന്‍, മടിയന്മാരാകരുത്. ധര്‍മ്മത്തെ സുചരിതമായി ആചരിക്കുവിന്‍. ധര്‍മ്മത്തെ അനുഷ്ഠിക്കുന്നവന്‍ ഇഹത്തിലും പരത്തിലും സുഖമായി ശയിക്കുന്നു.",
  "169": "ശുദ്ധചരിതമായ ധര്‍മ്മത്തെ ചെയ്യണം; ദുശ്ചരിതമായ ധര്‍മ്മത്തെ ചെയ്യരുത്. ധര്‍മ്മത്തെ അനുഷ്ഠിക്കുന്നവന്‍ ഇഹത്തിലും പരത്തിലും സുഖിക്കുന്നു.",
  "170": "ജലത്തിലെ കുമിളകളെപ്പോലെയും മരുഭൂമിയിലെ മരീചികയെപ്പോലെയും ലോകത്തെ കണ്ടുകൊള്ളണം. ഇപ്രകാരം ലോകത്തെ വീക്ഷിക്കുന്നവനെ മൃത്യുരാജന്‍ കാണുകയില്ല.",
  "171": "വരുവിന്‍! അലങ്കരിച്ച രാജരഥംപോലെയുള്ള ഈ ലോകത്തെ കാണുക. മൂഢന്മാര്‍ ഇതില്‍ മുഴുകി വിഷാദിക്കുന്നു; എന്നാല്‍ വിജ്ഞന്മാര്‍ക്ക് ഇതില്‍ യാതൊരു സംഗവുമില്ല.",
  "172": "ആദ്യത്തില്‍ പ്രമത്തനായിരുന്നിട്ടും പിന്നീട് പ്രമാദത്തെ വിടുന്നതായാല്‍, അവന്‍ മേഘങ്ങളില്‍നിന്ന് മുക്തനായ ചന്ദ്രനെപ്പോലെ ഈ ലോകത്തെ പ്രകാശിപ്പിക്കുന്നു.",
  "173": "ഏതൊരുവന്‍ താന്‍ ചെയ്ത പാപകര്‍മ്മത്തെ സത്കര്‍മ്മംകൊണ്ട് മറയ്ക്കുന്നുവോ, അവന്‍ മേഘമുക്തനായ ചന്ദ്രനെപ്പോലെ ഈ ലോകത്തെ പ്രകാശിപ്പിക്കുന്നു.",
  "174": "ഈ ലോകം അന്ധകാരമയമാകുന്നു; ഇവിടെ യഥാര്‍ത്ഥ കാഴ്ചയുള്ളവര്‍ വളരെ ചുരുക്കമാണ്. വലയില്‍നിന്ന് രക്ഷപ്പെടുന്ന പക്ഷികള്‍ കുറവായിരിക്കുന്നതുപോലെ, വളരെ കുറച്ചുപേര്‍ മാത്രം സ്വര്‍ഗ്ഗത്തിലേക്ക് പോകുന്നു.",
  "175": "അരയന്നങ്ങള്‍ സൂര്യമാര്‍ഗ്ഗത്തിലൂടെ സഞ്ചരിക്കുന്നു; ഋദ്ധിമാന്മാര്‍ ആകാശത്തിലൂടെ സഞ്ചരിക്കുന്നു. ധീരന്മാരായ പണ്ഡിതന്മാര്‍ മാരനെ സൈന്യസമേതം ജയിച്ച് ലോകത്തില്‍നിന്ന് വിമുക്തരായിത്തീരുന്നു.",
  "176": "സത്യമെന്ന ഉത്തമധര്‍മ്മത്തെ ലംഘിച്ച് മിഥ്യാവാദം പറയുന്നവനും, പരലോകത്തെ ഭയപ്പെടാത്തവനുമായ മനുഷ്യന് ചെയ്യാന്‍ കഴിയാത്ത പാപമില്ല.",
  "177": "പിശുക്കന്മാര്‍ ദേവലോകത്തെ പ്രാപിക്കുകയില്ല; മൂഢന്മാര്‍ മാത്രമേ ദാനത്തെ പ്രശംസിക്കാതിരിക്കുകയുള്ളു. എന്നാല്‍ ധീരനായ പണ്ഡിതന്‍ ദാനത്തെ അനുമോദിക്കുന്നു; അതുകൊണ്ടുതന്നെ അവന്‍ പരലോകത്ത് സുഖിയായി ഭവിക്കുന്നു.",
  "178": "ഭൂമിയിലെ ഏകഛത്രാധിപതിയാകുന്നതിനേക്കാളും, സ്വര്‍ഗ്ഗലോകം പ്രാപിക്കുന്നതിനേക്കാളും, സര്‍വ്വലോകങ്ങളുടെയും ആധിപത്യം നേടുന്നതിനേക്കാളും ശ്രേഷ്ഠമായിട്ടുള്ളത് സ്രോതാപത്തിഫലം (സന്മാര്‍ഗ്ഗപ്രവേശം) ആകുന്നു.",
  "chap14": "ബുദ്ധവഗ്ഗോ",
  "179": "യാതൊരുവന് അധീനപ്പെട്ടത് അന്യന്മാര്‍ക്ക് തിരിച്ചെടുക്കുവാന്‍ കഴിയാതിരിക്കുന്നുവോ, യാതൊരുവന്റെ ജയം ലോകത്തില്‍ മറ്റാരാലും തോല്‍പ്പിക്കുവാന്‍ കഴിയാത്തതാകുന്നുവോ, ആ അനന്തഗോചരനും അപദനുമായ ബുദ്ധനെ നിങ്ങള്‍ ഏതു വഴിക്കു കൊണ്ടുനടക്കും?",
  "180": "ജാലരൂപമായ വിഷയാസക്തിയും തൃഷ്ണയും ഏതൊരുവനെ എവിടേക്കും ആകര്‍ഷിക്കുന്നില്ലയോ, ആ അനന്തഗോചരനും അപദനുമായ ബുദ്ധനെ നിങ്ങള്‍ ഏതു വഴിക്കു കൊണ്ടുനടക്കും?",
  "181": "ധ്യാനശീലന്മാരും ജാഗ്രതയുള്ളവരും നിര്‍വ്വാണത്തിന്റെ ശാന്തിയില്‍ രമിക്കുന്നവരുമായ പണ്ഡിതന്മാരെ (ബുദ്ധന്മാരെ) ദേവന്മാര്‍ പോലും അസൂയയോടെ (ആഗ്രഹത്തോടെ) നോക്കുന്നു.",
  "182": "മനുഷ്യജന്മലാഭം പ്രയാസമുള്ളതാണ്; മര്‍ത്ത്യരുടെ ജീവിതവും പ്രയാസമേറിയതാണ്; സദ്ധര്‍മ്മശ്രവണം പ്രയാസമുള്ളതാണ്; ബുദ്ധന്മാരുടെ ജനനവും പ്രയാസമുള്ളതാകുന്നു.",
  "183": "സര്‍വ്വപാപങ്ങളും ചെയ്യാതിരിക്കുക, പുണ്യം സമ്പാദിക്കുക, സ്വന്തം മനസ്സിനെ പരിശുദ്ധമാക്കുക; ഇതാകുന്നു ബുദ്ധന്മാരുടെ ശാസനം.",
  "184": "ക്ഷമയാണ് പരമമായ തപസ്സ്, തിതിക്ഷയാണ് പരമമായ നിര്‍വ്വാണമെന്ന് ബുദ്ധന്മാര്‍ പറയുന്നു. പരദ്രോഹിയായവന്‍ പ്രവ്രജിതനാകുന്നില്ല; പരനെ ഉപദ്രവിക്കുന്നവന്‍ ശ്രമണനുമാകുന്നില്ല.",
  "185": "അന്യരെ ദുഷിക്കാതിരിക്കുക, ഹിംസിക്കാതിരിക്കുക, പ്രാതിമോക്ഷത്തില്‍ (ധര്‍മ്മനിയമങ്ങളില്‍) ഒതുങ്ങിജീവിക്കുക, ഭക്ഷണത്തില്‍ മിതത്വം പാലിക്കുക, ഏകാന്തമായി ശയനാസനം ചെയ്യുക, ചിത്തത്തില്‍ ധ്യാനയോഗം ശീലിക്കുക; ഇതാകുന്നു ബുദ്ധന്മാരുടെ ശാസനം.",
  "186": "നാണയങ്ങളുടെ (കാര്‍ഷാപണങ്ങളുടെ) മഴ പെയ്താല്‍പോലും കാമങ്ങളില്‍ തൃപ്തി വരുന്നില്ല. കാമങ്ങള്‍ അല്പമാത്രം സ്വാദുള്ളതും ദുഃഖകരങ്ങളുമാണെന്ന് പണ്ഡിതന്‍ അറിയുന്നു.",
  "187": "ദിവ്യഭോഗങ്ങളില്‍പ്പോലും അവന്‍ രമിക്കുന്നില്ല. സമ്യക്സംബുദ്ധന്റെ ശ്രാവകന്‍ തൃഷ്ണകളുടെ ക്ഷയത്തില്‍ (നാശത്തില്‍) മാത്രം സന്തോഷം കണ്ടെത്തുന്നു.",
  "188": "ഭയവിഹ്വലരായ മനുഷ്യര്‍ വളരെ പര്‍വ്വതങ്ങളെയും വനങ്ങളെയും ആരാമങ്ങളെയും വൃക്ഷങ്ങളെയും ചൈത്യങ്ങളെയും (ക്ഷേത്രങ്ങളെയും) ശരണം പ്രാപിക്കുന്നു.",
  "189": "എന്നാല്‍ ഇത് ക്ഷേമകരമായ ശരണമല്ല, ഉത്തമമായ ശരണവുമല്ല; ഈ ശരണങ്ങളെ ആശ്രയിച്ചതുകൊണ്ട് മാത്രം മനുഷ്യന്‍ സര്‍വ്വദുഃഖങ്ങളില്‍നിന്നും മോചിക്കപ്പെടുന്നില്ല.",
  "190": "ബുദ്ധനെയും ധര്‍മ്മത്തെയും സംഘത്തെയും ശരണം പ്രാപിച്ച്, ദുഃഖം, ദുഃഖകാരണം, ദുഃഖത്തിന്റെ നിവൃത്തി, ദുഃഖോപശമനമേകുന്ന ആര്യമായ അഷ്ടാങ്ഗമാര്‍ഗ്ഗം എന്നീ നാല് ആര്യസത്യങ്ങളെ സമ്യക്പ്രജ്ഞയോടെ ദര്‍ശിക്കുന്നവന്‍ ആരോ;",
  "191": "ഇതാകുന്നു ക്ഷേമകരമായ ശരണം, ഇതാകുന്നു ഉത്തമമായ ശരണം;",
  "192": "ഈ ശരണത്തെ പ്രാപിക്കുന്ന മനുഷ്യന്‍ സര്‍വ്വദുഃഖങ്ങളില്‍നിന്നും മോചിക്കപ്പെടുന്നു.",
  "193": "സര്‍വ്വോത്തമനായ പുരുഷന്‍ (ബുദ്ധന്‍) ദുര്‍ല്ലഭനാകുന്നു; അദ്ദേഹം എല്ലായിടത്തും ജനിക്കുകയില്ല. ആ ധീരനായ മഹാപുരുഷന്‍ ഏതു കുലത്തില്‍ ജനിക്കുന്നുവോ ആ കുലം സുഖവും ശ്രേയസ്സും പ്രാപിക്കുന്നു.",
  "194": "ബുദ്ധന്മാരുടെ ഉല്‍പ്പാദം സുഖകരമാകുന്നു; സദ്ധര്‍മ്മദേശന സുഖകരമാകുന്നു; സംഘത്തിന്റെ സമഗ്രത (ഐക്യം) സുഖകരമാകുന്നു; ഐക്യത്തോടെയുള്ള തപസ്സും സുഖകരമാകുന്നു.",
  "195": "പ്രപഞ്ച നിവൃത്തരും ശോകപ്രവാഹത്തെ കടന്നവരുമായ, പൂജാര്‍ഹരായ ബുദ്ധന്മാരെയോ അവരുടെ ശ്രാവകരെയോ പൂജിക്കുന്നവന്റെയും,",
  "196": "നിര്‍വൃതിയും ഭയരാഹിത്യവും പ്രാപിച്ച അത്തരക്കാരെ പൂജിക്കുന്നവന്റെയും പുണ്യഫലം ഇത്രയെന്ന് കണക്കാക്കുവാന്‍ ആരാലും സാധ്യമല്ല.",
  "chap15": "സുഖവഗ്ഗോ",
  "197": "വൈരമുള്ളവരുടെ ഇടയിൽ വൈരമില്ലാത്തവരായി നാം എത്രയോ സുഖമായി ജീവിക്കുന്നു; വൈരികളായ മനുഷ്യരുടെ നടുവിലും നാം വൈരമില്ലാതെ (സ്നേഹത്തോടെ) വിഹരിക്കുന്നു.",
  "198": "ആതുരന്മാരുടെ (രോഗാതുരരോ ദുഃഖിതരോ ആയവരുടെ) ഇടയിൽ ആതുരരല്ലാത്തവരായി നാം പരമസുഖമായി ജീവിക്കുന്നു; ആതുരരായ മനുഷ്യരുടെ മധ്യത്തിൽ നാം ആരോഗ്യത്തോടെ (ക്ലേശമില്ലാതെ) വിഹരിക്കുന്നു.",
  "199": "വിഷയവാസനകളിൽ ആകുലരായവരുടെ (ഉത്സുകന്മാരുടെ) ഇടയിൽ ആകുലതകളില്ലാത്തവരായി (അനുത്സുകരായി) നാം സുഖമായി ജീവിക്കുന്നു; അങ്ങനെയുള്ളവരുടെ മധ്യത്തിൽ നാം സന്തോഷത്തോടെ കഴിയുന്നു.",
  "200": "നമ്മുടേതെന്ന് പറയാൻ യാതൊരു ആസക്തിയുമില്ലെങ്കിലും നാം പരമസുഖത്തോടെ ജീവിക്കുന്നു; പ്രകാശമയന്മാരായ ആഭസ്വര ദേവന്മാരെയെന്നപോലെ നാം പ്രീതിയാകുന്ന അമൃത് ഭുജിച്ചുകൊണ്ട് കഴിയുന്നു.",
  "201": "ജയം വൈരത്തെ ഉണ്ടാക്കുന്നു; പരാജിതൻ ദുഃഖത്തോടെ ശയിക്കുന്നു. ജയപരാജയങ്ങളെ രണ്ടിനെയും ഉപേക്ഷിച്ച ശാന്തചിത്തൻ സുഖമായി ശയിക്കുന്നു (ജീവിക്കുന്നു).",
  "202": "രാഗത്തിന് (ആസക്തിക്ക്) തുല്യമായ അഗ്നിയില്ല; ദ്വേഷത്തിന് തുല്യമായ ദോഷമില്ല. പഞ്ചസ്കന്ധങ്ങൾക്ക് തുല്യമായ ദുഃഖമില്ല; ശാന്തിക്ക് മേലായി മറ്റൊരു സുഖവുമില്ല.",
  "203": "രോഗങ്ങളിൽ വെച്ച് ഏറ്റവും കഠിനമായത് വിശപ്പാകുന്നു; ദുഃഖങ്ങളിൽ വെച്ച് ഏറ്റവും വലിയത് സംസ്കാരങ്ങളും (വിഷയവാസനകളും) ആകുന്നു. ഇതുകളെ യഥാർത്ഥമായി തിരിച്ചറിയുന്നതാണ് പരമസുഖമായ നിർവ്വാണം.",
  "204": "ലാഭങ്ങളിൽ വെച്ച് ഉത്കൃഷ്ടമായത് ആരോഗ്യമാകുന്നു; ഏറ്റവും വലിയ ധനം സന്തുഷ്ടിയാകുന്നു. ഉത്കൃഷ്ടനായ ജ്ഞാതി (ബന്ധു) വിശ്വാസമാകുന്നു; പരമമായ സുഖം നിർവ്വാണവുമാകുന്നു.",
  "205": "ഏകാന്തതയുടെയും ഉപശമനത്തിന്റെയും രസത്തെ പാനം ചെയ്തവൻ ഭയവും പാപവുമില്ലാത്തവനായി ഭവിക്കുന്നു; അവൻ ധർമ്മപ്രീതിയാകുന്ന മധുരരസം പാനം ചെയ്ത് ആനന്ദിക്കുന്നു.",
  "206": "ആര്യന്മാരെ (സജ്ജനങ്ങളെ) ദർശിക്കുന്നത് സുഖകരമാകുന്നു; അവരോടൊത്തു ജീവിക്കുന്നത് എപ്പോഴും സുഖപ്രദമാണ്. മൂഢന്മാരെ കാണാതിരിക്കാൻ കഴിഞ്ഞാൽ മനുഷ്യൻ നിത്യസുഖിയായി ഭവിക്കും.",
  "207": "മൂഢന്മാരോടൊപ്പം സഞ്ചരിക്കുന്നവൻ ദീർഘകാലം ശോകിക്കേണ്ടിവരുന്നു; ശത്രുക്കളോടൊപ്പമുള്ള വാസം പോലെ മൂഢന്മാരോടൊപ്പമുള്ള സഹവാസം എപ്പോഴും ദുഃഖകരമാണ്. എന്നാൽ ധീരന്മാരുമായുള്ള സമ്പർക്കം ബന്ധുസമാഗമം പോലെ സുഖപ്രദമാകുന്നു.",
  "208": "അതിനാൽ, ധീരനും പ്രാജ്ഞനും ബഹുശ്രുതനും സൽസ്വഭാവിയും വ്രതശുദ്ധിയുള്ളവനും ആര്യനുമായ ആ സൽപുരുഷനെ, ചന്ദ്രൻ നക്ഷത്രവീഥിയെ എന്നപോലെ നിങ്ങളും ഭജിക്കുവിൻ.",
  "chap16": "പിയവഗ്ഗോ",
  "209": "അയോഗ്യമായ കാര്യങ്ങളിൽ ഏർപ്പെടുകയും യോഗ്യമായ കാര്യങ്ങളിൽ ശ്രദ്ധിക്കാതിരിക്കുകയും ചെയ്യുന്നവൻ, ജീവിതത്തിന്റെ പരമപ്രയോജനത്തെ ഉപേക്ഷിച്ച് ലൗകികപ്രിയങ്ങളെ മാത്രം ഗ്രഹിക്കുന്നു; അങ്ങനെയുള്ളവൻ പിന്നീട് സമാധിശീലരായ (ധ്യാനിക്കുന്ന) ജ്ഞാനികളെക്കണ്ട് അസൂയപ്പെടുന്നു.",
  "210": "പ്രിയവസ്തുക്കളോട് അമിതമായി അടുക്കരുത്, അപ്രിയവസ്തുക്കളോട് ഒരിക്കലും സമ്പർക്കം പുലർത്തുകയുമരുത്; കാരണം പ്രിയമുള്ളവയെ കാണാതിരിക്കുന്നതും അപ്രിയമുള്ളവയെ കാണേണ്ടിവരുന്നതും ദുഃഖകരമാകുന്നു.",
  "211": "അതിനാൽ ഒന്നിനോടും പ്രിയം വെക്കരുത്; പ്രിയപ്പെട്ടവയുടെ വിയോഗം കഠിനമായ സങ്കടമാണ്. യാതൊരുവർക്ക് പ്രിയവും അപ്രിയവുമില്ലയോ, അവർക്ക് സംസാരബന്ധങ്ങളായ ഗ്രന്ഥികൾ (കെട്ടുകൾ) ഉണ്ടാകുന്നില്ല.",
  "212": "പ്രിയത്തിൽനിന്ന് ശോകമുണ്ടാകുന്നു, പ്രിയത്തിൽനിന്ന് ഭയമുണ്ടാകുന്നു; പ്രിയത്തിൽനിന്ന് വിമുക്തനായവന് ശോകവുമില്ല, പിന്നെവിടെനിന്ന് ഭയം?",
  "213": "പ്രേമത്തിൽനിന്ന് ശോകം ജനിക്കുന്നു, പ്രേമത്തിൽനിന്ന് ഭയം ജനിക്കുന്നു; പ്രേമമില്ലാത്തവന് (പ്രേമത്തിൽനിന്ന് വിമുക്തനായവന്) ശോകവുമില്ല ഭയവുമില്ല.",
  "214": "രതിയിൽനിന്ന് (ആസക്തിയിൽനിന്ന്) ശോകം ഭവിക്കുന്നു, രതിയിൽനിന്ന് ഭയം ഭവിക്കുന്നു; രതിയൊഴിഞ്ഞവന് ശോകവും ഭയവുമില്ല.",
  "215": "കാമത്തിൽനിന്ന് ശോകമുണ്ടാകുന്നു, കാമത്തിൽനിന്ന് ഭയമുണ്ടാകുന്നു; കാമമൊഴിഞ്ഞവന് ശോകമോ ഭയമോ ഉണ്ടാകുന്നില്ല.",
  "216": "തൃഷ്ണയിൽനിന്ന് ശോകമുണ്ടാകുന്നു, തൃഷ്ണയിൽനിന്ന് ഭയമുണ്ടാകുന്നു; തൃഷ്ണയൊഴിഞ്ഞവന് ശോകമോ ഭയമോ ഉണ്ടാകുന്നതല്ല.",
  "217": "ഉത്തമമായ ശീലവും ഉൾക്കാഴ്ചയുമുള്ളവനും, ധർമ്മിഷ്ഠനും, സത്യവാദിയും, സ്വന്തം കടമകൾ കൃത്യമായി അനുഷ്ഠിക്കുന്നവനുമായ മഹാത്മാവിനെ ലോകർ ഏവർക്കും പ്രിയപ്പെട്ടവനായിത്തീരുന്നു.",
  "218": "നിർവ്വാണമാകുന്ന അവർണ്ണനീയ പദവിയിൽ ഹൃദയം ഉറച്ചവനും, മനസ്സിൽ പരമശാന്തി വന്നവനും, കാമങ്ങളിൽ ചിത്തം കുടുങ്ങാത്തവനുമായ മനുഷ്യൻ 'ഊർദ്ധ്വസ്രോതസ്സ്' (ഉയരങ്ങളിലേക്ക് പ്രവഹിക്കുന്നവൻ) എന്ന് പറയപ്പെടുന്നു.",
  "219": "വളരെക്കാലം പരദേശത്ത് വസിച്ച്, ദൂരത്തുനിന്ന് സുഖമായി മടങ്ങിവരുന്ന ഒരുവനെ അവന്റെ ജ്ഞാതികളും മിത്രങ്ങളും സുഹൃത്തുക്കളും സന്തോഷത്തോടെ എതിരേറ്റ് അഭിനന്ദിക്കുന്നു.",
  "220": "അപ്രകാരംതന്നെ, സത്കർമ്മങ്ങൾ ചെയ്ത പുണ്യവാൻ ഈ ലോകം വിട്ട് പരലോകത്തിലേക്ക് ചെല്ലുമ്പോൾ, അവൻ ചെയ്ത പുണ്യങ്ങൾ, ജ്ഞാതികൾ പ്രിയപ്പെട്ടവനെ എന്നപോലെ അവനെ സ്വീകരിക്കുന്നു.",
  "chap17": "കോധവഗ്ഗോ",
  "221": "ക്രോധത്തെ ത്യജിക്കണം; ഗർവ്വത്തെ അകറ്റണം. സർവ്വ ബന്ധങ്ങളെയും അതിക്രമിക്കണം. നാമത്തിലും രൂപത്തിലും ആസക്തിയില്ലാതെ, ഒന്നിലും മമതയില്ലാത്തവനായി (അകിഞ്ചനനായി) കഴിയുന്നവനെ ദുഃഖങ്ങൾ പിന്തുടരുന്നില്ല.",
  "222": "ഓടുന്ന രഥത്തെ എന്നപോലെ തന്നിൽ പെട്ടെന്നുയരുന്ന ക്രോധത്തെ അടക്കിനിർത്തുന്നത് ഏവനോ, അവനെയാണ് ഞാൻ യഥാർത്ഥ സാരഥി എന്ന് പറയുക. മറ്റുള്ളവർ കടിഞ്ഞാൺ പിടിക്കുന്നവർ മാത്രമാണ്.",
  "223": "അക്രോധം (സ്നേഹം) കൊണ്ട് ക്രോധത്തെ ജയിക്കണം; നന്മകൊണ്ട് തിന്മയെ ജയിക്കണം. ഔദാര്യംകൊണ്ട് പിശുക്കിനെ ജയിക്കണം; സത്യംകൊണ്ട് അസത്യവാദിയെ ജയിക്കണം.",
  "224": "എപ്പോഴും സത്യം പറയണം; ക്രോധത്തിന് വശപ്പെടരുത്. യാചിക്കപ്പെട്ടാൽ ഉള്ളതിൽനിന്ന് അല്പമെങ്കിലും കൊടുക്കണം. ഈ മൂന്ന് സദ്ഗുണങ്ങളിലൂടെ മനുഷ്യന് ദേവന്മാരുടെ സന്നിധിയിൽ എത്തിച്ചേരാം.",
  "225": "ഒരിക്കലും ഹിംസ ചെയ്യാത്തവരും, നിത്യവും ശരീരത്തെ സംയമനം ചെയ്തവരുമായ മുനികൾ യാതൊരുവരോ, അവർ ദുഃഖമില്ലാത്തതും മാറ്റമില്ലാത്തതുമായ ശാശ്വത പദവിയെ (നിർവ്വാണത്തെ) പ്രാപിക്കുന്നു.",
  "226": "എപ്പോഴും ജാഗരൂകരായിരിക്കുന്നവർക്കും, രാപ്പകൽ ധർമ്മശിക്ഷണം നേടുന്നവർക്കും, നിർവ്വാണത്തിൽ ചിത്തം ഉറപ്പിച്ചവർക്കും തൃഷ്ണകൾ (ആസ്രവങ്ങൾ) പൂർണ്ണമായി അസ്തമിക്കുന്നു.",
  "227": "ഹേ അതുല! ഇത് ഇന്നുണ്ടായതല്ല, പുരാതന കാലം മുതലുള്ള നിയമമാണ്; മിണ്ടാതിരിക്കുന്നവനെയും ജനങ്ങൾ കുറ്റപ്പെടുത്തും, അധികം സംസാരിക്കുന്നവനെയും കുറ്റപ്പെടുത്തും, മിതമായി സംസാരിക്കുന്നവനെയും കുറ്റപ്പെടുത്തും. ലോകത്തിൽ കുറ്റമൊഴിഞ്ഞവനായി ആരുമില്ല.",
  "228": "പൂർണ്ണമായി നിന്ദിക്കപ്പെട്ടവനായോ അല്ലെങ്കിൽ പൂർണ്ണമായി പ്രശംസിക്കപ്പെട്ടവനായോ ഒരു പുരുഷൻ മുൻപ് ഉണ്ടായിട്ടില്ല, ഇനി ഉണ്ടാവുകയുമില്ല, ഇപ്പോഴുമില്ല.",
  "229": "നിഷ്കളങ്കമായ ജീവിതം നയിക്കുന്നവനും, മേധാവികളും, പ്രജ്ഞയും ശീലവും സമാധിയും തികഞ്ഞവനുമായ ഒരുവനെ പണ്ഡിതന്മാർ ദിവസേനയെന്നോണം പ്രശംസിക്കുന്നു.",
  "230": "ജംബൂനദിയിലെ തങ്കംകൊണ്ടുണ്ടാക്കിയ നാണയംപോലെയുള്ള അവനെ ആർക്കാണ് നിന്ദിക്കുവാൻ കഴിയുക? അവനെ ദേവന്മാരും ബ്രഹ്മാവും പോലും പ്രശംസിക്കുന്നു.",
  "231": "കായികമായ പ്രകോപങ്ങളെ തടയണം; ശരീരംകൊണ്ട് സംയമനം പാലിക്കണം. ശാരീരികമായ ദുശ്ചരിതങ്ങളെ വെടിഞ്ഞ് ശരീരംകൊണ്ട് സുചരിതം ആചരിക്കണം.",
  "232": "വാക്കിന്റെ പ്രകോപങ്ങളെ തടയണം; വാക്കുകൊണ്ട് സംയമനം പാലിക്കണം. വാക്സംബന്ധമായ ദുശ്ചരിതങ്ങളെ വെടിഞ്ഞ് വാക്കുകൊണ്ട് സുചരിതം ആചരിക്കണം.",
  "233": "മനസ്സിന്റെ പ്രകോപങ്ങളെ തടയണം; മനസ്സുകൊണ്ട് സംയമനം പാലിക്കണം. മാനസികമായ ദുശ്ചരിതങ്ങളെ വെടിഞ്ഞ് മനസ്സുകൊണ്ട് സുചരിതം ആചരിക്കണം.",
  "234": "ധീരന്മാരായ പണ്ഡിതന്മാർ ശരീരംകൊണ്ടും വാക്കുകൊണ്ടും മനസ്സുകൊണ്ടും സ്വയം നിയന്ത്രിക്കുന്നു; അവർ തന്നെയാണ് യഥാർത്ഥത്തിൽ സുപരിസംവൃതന്മാർ (പരിപൂർണ്ണമായി സംയമനം സിദ്ധിച്ചവർ).",
  "chap18": "മലവഗ്ഗോ",
  "235": "നീ ഇപ്പോൾ പഴുത്തുണങ്ങിയ ഒരു ഇലപോലെ ആയിത്തീർന്നിരിക്കുന്നു; യമകിങ്കരന്മാർ നിന്നെയും കാത്തുനിൽക്കുന്നു. നീ മരണത്തിന്റെ പടിവാതിൽക്കലാണ് നിൽക്കുന്നത്; എന്നാൽ യാത്രയ്ക്കായി യാതൊരു വഴിച്ചിലവും (പുണ്യവും) നീ കരുതിയിട്ടില്ലതാനും.",
  "236": "അതിനാൽ നീ സ്വന്തമായി ഒരു ദ്വീപ് (ആശ്രയം) നിർമ്മിക്കുക; വേഗം യത്നിച്ച് ബുദ്ധിമാനാവുക. അശുദ്ധികൾ നീങ്ങി നിർദ്ദോഷിയാകുമ്പോൾ നീ ദിവ്യമായ ആര്യഭൂമിയെ (സ്വർഗ്ഗലോകത്തെ) പ്രാപിക്കും.",
  "237": "നിന്റെ ആയുസ്സ് പൂർണ്ണമായും അവസാനിച്ചു കഴിഞ്ഞു; നീ യമന്റെ സന്നിധിയിലേക്ക് യാത്രയായിക്കഴിഞ്ഞു. വഴിയിൽ നിനക്ക് വിശ്രമിക്കാൻ ഒരിടവുമില്ല; യാത്രയ്ക്കുള്ള വകയും നിന്റെ വശമില്ല.",
  "238": "അതിനാൽ നീ തന്നെ നിനക്കൊരു ദ്വീപാകുക; വേഗം തീവ്രമായി യത്നിച്ച് പണ്ഡിതനാവുക. നിന്റെ ചിത്തമലങ്ങൾ അകന്നുപോയാൽ പിന്നീട് നിനക്ക് ജന്മവും ജരയും അനുഭവിക്കേണ്ടി വരികയില്ല.",
  "239": "കൊല്ലൻ വെള്ളിയുടെ കറകളെ ഊതിക്കഴുകി വൃത്തിയാക്കുന്നതുപോലെ, ബുദ്ധിമാനായ മനുഷ്യൻ തന്നിലുള്ള അശുദ്ധികളെ (മലങ്ങളെ) ഓരോന്നോരോന്നായി, ഓരോ നിമിഷവും കുറേശ്ശെയായി കാലക്രമേണ കളയണം.",
  "240": "ഇരുമ്പിൽനിന്നുണ്ടാകുന്ന തുരുമ്പ് അതിനെത്തന്നെ കാർന്നുതിന്ന് നശിപ്പിക്കുന്നതുപോലെ, ധർമ്മം ലംഘിച്ചു ജീവിക്കുന്നവന്റെ ദുഷ്കർമ്മങ്ങൾ അവനെത്തന്നെ നരകതുല്യമായ ദുർഗ്ഗതിയിലേക്ക് നയിക്കുന്നു.",
  "241": "മന്ത്രങ്ങൾക്ക് കറ അത് ആവർത്തിച്ചു ജപിക്കാതിരിക്കലാകുന്നു; വീടുകൾക്ക് കറ അവ സൂക്ഷിക്കാതെ കേടുവരുത്തലാകുന്നു; ശാരീരിക വർണ്ണത്തിന് കറ മടിയാകുന്നു; കാവൽക്കാരന് കറ അശ്രദ്ധയാകുന്നു.",
  "242": "സ്ത്രീകൾക്ക് കറ ദുർവൃത്തി (ദുശ്ശീലം) ആകുന്നു; ദാനം ചെയ്യുന്നവന് കറ പിശുക്കാകുന്നു; ഈ ലോകത്തിലും പരലോകത്തിലും എല്ലാ പാപകർമ്മങ്ങളും കറകൾ തന്നെയാണ്.",
  "243": "എന്നാൽ ഈ കറകളെക്കാളെല്ലാം ഏറ്റവും വലിയ കറ അവിദ്യ (അജ്ഞാനം) ആകുന്നു; അതുകൊണ്ട് ഹേ ഭിക്ഷുക്കളേ, നിങ്ങൾ ആ പരമമലത്തെ പൂർണ്ണമായി വെടിഞ്ഞ് പരിശുദ്ധന്മാരായിത്തീരുവിൻ.",
  "244": "നിർലജ്ജനും, കാകവൃത്തിയുള്ളവനും (അന്യന്റെ വക തട്ടിയെടുക്കുന്നവൻ), പരദ്രോഹിയും, അഹങ്കാരിയും, നീചനുമായി ജീവിക്കുന്നവന് ഈ ലോകത്തിൽ എളുപ്പത്തിൽ കഴിഞ്ഞുകൂടാം.",
  "245": "എന്നാൽ ലജ്ജാശീലനും, എപ്പോഴും പരിശുദ്ധിയെ കാംക്ഷിക്കുന്നവനും, അഹംഭാവമില്ലാത്തവനും, വിനീതനും, സത്യദർശിയുമായ നിർമ്മലജീവിതം നയിക്കുന്നവന് ജീവിക്കുക എന്നത് പ്രയാസമേറിയതാകുന്നു.",
  "246": "ഏതൊരുവൻ പ്രാണികളെ ഹിംസിക്കുകയും, അസത്യം പറയുകയും, ലോകത്തിൽ അന്യൻ തരാത്ത ധനം മോഷ്ടിക്കുകയും, പരസ്ത്രീഗമനം നടത്തുകയും, മദ്യപാനം ചെയ്ത് ലഹരിയിൽ മുഴുകുകയും ചെയ്യുന്നുവോ,",
  "247": "അവൻ ഇഹലോകത്തിൽവെച്ചുതന്നെ തന്റെ സ്വന്തം വേരറുക്കുകയാണ് (നാശം വരുത്തുകയാണ്) ചെയ്യുന്നത്.",
  "248": "ഹേ മനുഷ്യാ, ഇതറിഞ്ഞാലും; ഇന്ദ്രിയങ്ങളെ അടക്കാതിരിക്കുന്നതുതന്നെയാണ് പാപം. ലോഭവും അധർമ്മവും നിന്നെ ദീർഘകാലം ദുഃഖത്തിലേക്ക് തള്ളിയിടാതിരിക്കാൻ ജാഗ്രതയുള്ളവനാകുക.",
  "249": "ജനങ്ങൾ തങ്ങളുടെ ശ്രദ്ധയ്ക്കും താല്പര്യത്തിനും അനുസരിച്ചാണ് ദാനം ചെയ്യുന്നത്; അവിടെ അന്യർക്ക് ലഭിക്കുന്ന ഭക്ഷണപാനീയങ്ങളെക്കുറിച്ച് ഏതൊരുവനാണോ അസൂയയും മനസ്താപവും ഉണ്ടാകുന്നത്, അവൻ പകലോ രാത്രിയോ ഒരിക്കലും സമാധി പ്രാപിക്കുന്നില്ല.",
  "250": "ഏതൊരുവന്റെ ഉള്ളിൽനിന്നാണോ ഈ അസൂയാനിന്ദകൾ വേരറുക്കപ്പെട്ട് പൂർണ്ണമായി നശിച്ചുപോകുന്നത്, അവൻ പകലും രാത്രിയും ഒരുപോലെ പരമമായ സമാധി സുഖം അനുഭവിക്കുന്നു.",
  "251": "രാഗത്തിന് (ആസക്തിക്ക്) തുല്യമായ അഗ്നിയില്ല; ദ്വേഷത്തിന് തുല്യമായ പിടിത്തമില്ല (മുതലയെപ്പോലെ); മോഹത്തിന് തുല്യമായ വലയില്ല; തൃഷ്ണയ്ക്ക് തുല്യമായ മറ്റൊരു നദിയില്ല.",
  "252": "അന്യന്റെ ദോഷം കാണാൻ വളരെ എളുപ്പമാണ്; എന്നാൽ സ്വന്തം ദോഷം ദർശിക്കാൻ പ്രയാസവുമാണ്. ഒരുവൻ പരദോഷങ്ങളെ പതിരുപോലെ കാറ്റിൽ തൂറ്റിക്കാണിക്കുന്നു; എന്നാൽ ചതിയനായ ചൂതാട്ടക്കാരൻ തന്റെ ചീത്ത കരുക്കളെ മറച്ചുവെക്കുംപോലെ സ്വന്തം ദോഷങ്ങളെ ഒളിപ്പുവെക്കുന്നു.",
  "253": "എപ്പോഴും പരദോഷം മാത്രം നോക്കി നടക്കുകയും, അന്യരെ നിന്ദിക്കാൻ അവസരം പാർത്തിരിക്കുകയും ചെയ്യുന്നവന്റെ ഉള്ളിൽ ആശ്രവങ്ങൾ (ചിത്തമലങ്ങൾ) വർദ്ധിച്ചുകൊണ്ടേയിരിക്കും; അവൻ തൃഷ്ണകളുടെ നാശത്തിൽനിന്ന് (മുക്തിയിൽനിന്ന്) വളരെ ദൂരത്തിലാണ്.",
  "254": "ആകാശത്തിൽ കാൽപ്പാടുകൾ ഉണ്ടാകാത്തതുപോലെ, ബുദ്ധമാർഗ്ഗത്തിന് പുറമെ യഥാർത്ഥ ശ്രമണന്മാർ (സന്യാസിമാർ) ഉണ്ടാകുന്നില്ല; സാധാരണ ജനങ്ങൾ പ്രപഞ്ചത്തിൽ രമിക്കുമ്പോൾ, തഥാഗതന്മാർ (ബുദ്ധന്മാർ) പ്രപഞ്ചത്തിനതീതരായി വർത്തിക്കുന്നു.",
  "255": "ആകാശത്തിൽ കാൽപ്പാടുകൾ ഇല്ലാത്തതുപോലെ, പുറമെ ശ്രമണന്മാരില്ല; സംസ്കാരങ്ങൾ (ലൗകിക പ്രതിഭാസങ്ങൾ) ഒന്നുംതന്നെ ശാശ്വതമല്ല. എന്നാൽ ബുദ്ധന്മാർക്ക് യാതൊരുവിധ ചിത്തചാഞ്ചല്യവുമില്ല.",
  "chap19": "ധമ്മട്ഠവഗ്ഗോ",
  "256": "കാര്യകാര്യങ്ങൾ പെട്ടെന്ന് (ആലോചനയില്ലാതെ) നടപ്പാക്കുന്നവൻ ധർമ്മിഷ്ഠനാകുന്നില്ല; എന്നാൽ കാര്യവും അകാര്യവും എന്തെന്ന് വേർതിരിച്ചറിഞ്ഞ് തീർപ്പുകൽപ്പിക്കുന്ന പണ്ഡിതനാണ് ധർമ്മിഷ്ഠൻ.",
  "257": "സാഹസം കൂടാതെ, നീതിയോടും സമത്വത്തോടും കൂടി അന്യരെ നയിക്കുന്നവനും, ധർമ്മത്തിന്റെ രക്ഷകനും, ബുദ്ധിമാനുമായ വ്യക്തിയെയാണ് 'ധർമ്മിഷ്ഠൻ' എന്ന് വിളിക്കുന്നത്.",
  "258": "അധികം സംസാരിക്കുന്നതുകൊണ്ട് മാത്രം ഒരുവൻ പണ്ഡിതനാകുന്നില്ല; എന്നാൽ ക്ഷമയുള്ളവനും, ആരോടും വൈരമില്ലാത്തവനും, ഭയരഹിതനുമായ മനുഷ്യനാണ് പണ്ഡിതനെന്ന് പറയപ്പെടുന്നത്.",
  "259": "വളരെ വാഗ്വാദം നടത്തുന്നതുകൊണ്ട് മാത്രം ഒരുവൻ ധർമ്മധരനാകുന്നില്ല; കുറച്ചേ കേട്ടിട്ടുള്ളുവെങ്കിലും ധർമ്മത്തെ സ്വന്തം ശരീരംകൊണ്ട് (ജീവിതംകൊണ്ട്) ദർശിക്കുകയും ധർമ്മത്തിൽ പ്രമാദം വരുത്താതിരിക്കുകയും ചെയ്യുന്നവനാണ് യഥാർത്ഥ ധർമ്മധരൻ.",
  "260": "തല നരച്ചതുകൊണ്ട് മാത്രം ഒരുവൻ 'സ്ഥവിരൻ' (മുതിർന്ന സന്യാസി) ആകുന്നില്ല; ഉള്ളിൽ ജ്ഞാനമില്ലാതെ പ്രായം മാത്രം മൂത്തവനെ 'മോഘജീർണ്ണൻ' (വെറുതെ വൃദ്ധനായവൻ) എന്ന് പറയുന്നു.",
  "261": "ഏതൊരുവനിൽ സത്യവും, ധർമ്മവും, അഹിംസയും, ഇന്ദ്രിയസംയമനവും, ദമവുമുണ്ടോ, മലങ്ങളെയെല്ലാം ഛർദ്ദിച്ചുകളഞ്ഞ (വെടിഞ്ഞ) ആ ധീരനായ പണ്ഡിതനാണ് 'സ്ഥവിരൻ' എന്ന് പറയപ്പെടുന്നത്.",
  "262": "ഈർഷയും പിശുക്കും കപടതയുമുള്ള ഒരു മനുഷ്യൻ, നല്ല വാക്ചാതുരി ഉള്ളതുകൊണ്ടോ ശരീരഭംഗി ഉള്ളതുകൊണ്ടോ മാത്രം സുന്ദരനോ സജ്ജനമോ ആകുന്നില്ല.",
  "263": "ഈ പറഞ്ഞ ദോഷങ്ങളെല്ലാം ഏതൊരുവനിൽനിന്ന് വേരറുക്കപ്പെട്ട് പൂർണ്ണമായി നശിച്ചുപോയോ, ദോഷങ്ങളകന്ന ബുദ്ധിമാനായ ആ മനുഷ്യൻ തന്നെയാണ് യഥാർത്ഥ 'സാധുരൂപൻ' (സുന്ദരൻ).",
  "264": "ധർമ്മവ്രതമില്ലാത്തവനും അസത്യം പറയുന്നവനുമായ ഒരുവൻ തല മൊട്ടയടിച്ചതുകൊണ്ട് മാത്രം ശ്രമണനാകുന്നില്ല; ആഗ്രഹങ്ങളും ലോഭവും നിറഞ്ഞവൻ എങ്ങനെ ശ്രമണനാകും?",
  "265": "അണുമാത്രമോ സ്ഥൂലമോ ആയ സർവ്വവിധ പാപങ്ങളെയും ഏതൊരുവൻ പൂർണ്ണമായി ശമിപ്പിക്കുന്നുവോ, പാപങ്ങളെ ശമിപ്പിച്ചതുകൊണ്ട് അവൻ 'ശ്രമണൻ' എന്ന് പറയപ്പെടുന്നു.",
  "266": "അന്യരിൽനിന്ന് പിച്ച (ഭിക്ഷ) വാങ്ങുന്നതുകൊണ്ട് മാത്രം ഒരുവൻ ഭിക്ഷുവാകുന്നില്ല; ഭിക്ഷുവിനുള്ള പവിത്രമായ ധർമ്മം മുഴുവൻ സ്വീകരിച്ച് ജീവിക്കുന്നവനാണ് യഥാർത്ഥ ഭിക്ഷു.",
  "267": "ഈ ലോകത്തിൽ പുണ്യത്തെയും പാപത്തെയും ഒരേപോലെ വെടിഞ്ഞ്, ബ്രഹ്മചര്യത്തോടെ, പ്രപഞ്ചത്തെ ശരിയായി മനസ്സിലാക്കി ജീവിക്കുന്നവൻ ആരോ, അവനാണ് ഭിക്ഷു എന്ന് പറയപ്പെടുന്നത്.",
  "268": "വിവേകമില്ലാത്ത അജ്ഞാനി മൗനം അവലംബിച്ചതുകൊണ്ട് മാത്രം മുനിയാകുന്നില്ല; എന്നാൽ ഒരുവൻ തുലാസ്സ് പിടിക്കുംപോലെ പുണ്യപാപങ്ങളെ തൂക്കിനോക്കി, ഉത്തമമായ നന്മയെ സ്വീകരിക്കുകയും പാപങ്ങളെ പൂർണ്ണമായി പരിവർജ്ജിക്കുകയും ചെയ്യുമ്പോൾ അവൻ മുനിയായിത്തീരുന്നു.",
  "269": "ഇഹപര ലോകങ്ങളെ ദീർഘമായി മനനം ചെയ്യുന്നതുകൊണ്ടാണ് അവൻ 'മുനി' എന്ന് പറയപ്പെടുന്നത്.",
  "270": "ജീവജാലങ്ങളെ ഹിംസിക്കുന്നവൻ 'ആര്യൻ' (ശ്രേഷ്ഠൻ) ആകുന്നില്ല; സർവ്വ പ്രാണികളോടും അഹിംസ പാലിക്കുകയും ദയ കാണിക്കുകയും ചെയ്യുന്നവനാണ് ആര്യൻ എന്ന് പറയപ്പെടുന്നത്.",
  "271": "ഭിക്ഷോ, കേവലം ശീല വ്രതങ്ങൾ കൊണ്ടോ, ബഹുശ്രുതത്വം (ശാസ്ത്രപാണ്ഡിത്യം) കൊണ്ടോ, സമാധി ലാഭം കൊണ്ടോ, ഏകാന്തശയനം കൊണ്ടോ മാത്രം സാധാരണ ജനങ്ങൾക്ക് അപ്രാപ്യമായ നൈഷ്കർമ്മ്യസുഖം (നിർവ്വാണസുഖം) ലഭിക്കുകയില്ല.",
  "272": "അതുകൊണ്ട് ചിത്തമലങ്ങൾ പൂർണ്ണമായി നശിച്ച് ആസ്രവക്ഷയം പ്രാപിക്കുന്നതുവരെ നീ ആത്മവിശ്വാസത്തിൽ (കൃതാർത്ഥതയിൽ) മുഴുകിപ്പോകരുത്.",
  "chap20": "മഗ്ഗവഗ്ഗോ",
  "273": "എല്ലാ മാർഗ്ഗങ്ങളിലും വെച്ച് ശ്രേഷ്ഠമായത് അഷ്ടാംഗമാർഗ്ഗമാകുന്നു; സത്യങ്ങളിൽ വെച്ച് ശ്രേഷ്ഠം നാല് ആര്യസത്യങ്ങളാകുന്നു. ധർമ്മങ്ങളിൽ വെച്ച് ശ്രേഷ്ഠം വൈരാഗ്യവും (ആസക്തിയില്ലായ്മ), മനുഷ്യരിൽ വെച്ച് ശ്രേഷ്ഠൻ ജ്ഞാനക്കണ്ണുള്ളവനും (ബുദ്ധൻ) ആകുന്നു.",
  "274": "ഉൾക്കാഴ്ചയുടെ വിശുദ്ധിക്ക് ഈ ഒരു മാർഗ്ഗമേയുള്ളൂ, വേറെയൊന്നുമില്ല; അതിനാൽ നിങ്ങൾ ഈ വഴിയിലൂടെത്തന്നെ നടക്കുവിൻ. ഇത് മാരനെ (തിന്മയെ) ഭ്രമിപ്പിച്ചു തോൽപ്പിക്കുന്ന വഴിയാകുന്നു.",
  "275": "ഈ വഴിയിലൂടെ സഞ്ചരിച്ചാൽ നിങ്ങൾക്ക് ദുഃഖങ്ങളുടെ അവസാനം വരുത്താം; സൻസാരരൂപമായ ശല്യങ്ങളെ (ബാധകളെ) എപ്രകാരം നീക്കാമെന്ന് അനുഭവിച്ചറിഞ്ഞിട്ടാണ് ഞാൻ ഈ മാർഗ്ഗം നിങ്ങൾക്ക് ഉപദേശിച്ചുതന്നത്.",
  "276": "നിങ്ങളുടെ കടമകൾ നിറവേറ്റാൻ നിന്നുതന്നെ തീവ്രമായി യത്നിക്കേണ്ടതുണ്ട്; തഥാഗതന്മാർ വഴി കാട്ടുന്ന ഉപദേശകർ മാത്രമാകുന്നു. ധ്യാനശീലരായവർ ഈ മാർഗ്ഗം അവലംബിച്ചാൽ അവർ മാരന്റെ ബന്ധനങ്ങളിൽനിന്ന് പൂർണ്ണമായി മോചിതരാകും.",
  "277": "എല്ലാ സംസ്കാരങ്ങളും (ലൗകിക പ്രതിഭാസങ്ങളും) അനിത്യമാണെന്ന് ഏതൊരുവൻ പ്രജ്ഞകൊണ്ട് തിരിച്ചറിയുന്നുവോ, അവൻ ദുഃഖങ്ങളിൽനിന്ന് പിന്തിരിയുന്നു (ഉദാസീനനാകുന്നു); ഇതാകുന്നു വിശുദ്ധിയിലേക്കുള്ള മാർഗ്ഗം.",
  "278": "എല്ലാ സംസ്കാരങ്ങളും ദുഃഖമയമാണെന്ന് ഏതൊരുവൻ പ്രജ്ഞകൊണ്ട് ദർശിക്കുന്നുവോ, അവൻ ദുഃഖങ്ങളിൽനിന്ന് പിന്തിരിയുന്നു; ഇതാകുന്നു വിശുദ്ധിയിലേക്കുള്ള മാർഗ്ഗം.",
  "279": "എല്ലാ പദാർത്ഥങ്ങളും അനാത്മമാണെന്ന് (സ്ഥിരമായ ആത്മാവില്ലാത്തവയാണെന്ന്) ഏതൊരുവൻ പ്രജ്ഞകൊണ്ട് ദർശിക്കുന്നുവോ, അവൻ ദുഃഖങ്ങളിൽനിന്ന് പിന്തിരിയുന്നു; ഇതാകുന്നു വിശുദ്ധിയിലേക്കുള്ള മാർഗ്ഗം.",
  "280": "ഉണർന്നു പ്രവർത്തിക്കേണ്ട യൗവനകാലത്തും കരുത്തുള്ള സമയത്തും മടിപിടിച്ചിരിക്കുന്നവനും, ഉന്മേഷവും ശരിയായ വിചാരങ്ങളുമില്ലാതെ കുത്സിതനായി കഴിയുന്നവനുമായ അലസൻ ജ്ഞാനത്തിന്റെ മാർഗ്ഗം ഒരിക്കലും കണ്ടെത്തുകയില്ല.",
  "281": "വാക്കിനെ സൂക്ഷിച്ചും, മനസ്സിനെ നന്നായി ഒതുക്കിയും, ശരീരംകൊണ്ട് യാതൊരുവിധ ദുഷ്കർമ്മങ്ങളും ചെയ്യാതെയും ജീവിക്കുന്നവൻ ഈ മൂന്ന് കർമ്മമാർഗ്ഗങ്ങളെയും ശുദ്ധീകരിച്ച് സൂക്ഷിക്കുന്നു; അവൻ ഋഷിമാർ ഉപദേശിച്ച പരമമാർഗ്ഗത്തെ പ്രാപിക്കുന്നു.",
  "282": "ധ്യാനയോഗത്തിൽനിന്ന് ജ്ഞാനമുണ്ടാകുന്നു, യോഗമില്ലായ്മയിൽനിന്ന് ജ്ഞാനം നശിക്കുന്നു; അഭിവൃദ്ധിയുടെയും നാശത്തിന്റെയും ഈ രണ്ടു വഴികളെയും തിരിച്ചറിഞ്ഞ്, ജ്ഞാനം വർദ്ധിക്കുന്ന തരത്തിൽ ഓരോരുത്തരും തങ്ങളെത്തന്നെ ഉത്തമമായ നിലയിൽ ഉറപ്പിച്ചുനിർത്തണം.",
  "283": "ഹേ ഭിക്ഷുക്കളേ, നിങ്ങൾ (ആശാരൂപമായ) വനത്തെ വെട്ടിമാറ്റുവിൻ, ഒരു വൃക്ഷത്തെ മാത്രമല്ല; എന്തെന്നാൽ ഈ വനത്തിൽനിന്നാണ് ഭയമുണ്ടാകുന്നത്. വനത്തെയും അതിലെ കുറ്റിക്കാടുകളെയും (ആസക്തികളെ) വേരറുത്ത് നിങ്ങൾ ആശാരഹിതരായി (നിർവ്വനന്മാരായി) ഭവിക്കുവിൻ.",
  "284": "മുലകുടിക്കുന്ന പശുകുട്ടിക്ക് തള്ളപ്പശുവിനോടുള്ള ആസക്തിപോലെ, ഒരു പുരുഷന് സ്ത്രീകളോട് അണുമാത്രമെങ്കിലും ആസക്തി അവശേഷിക്കുന്നുവോ, അത്രത്തോളം അവന്റെ മനസ്സ് ബന്ധനത്തിലായിരിക്കും; ആശാബന്ധം വിട്ടുപോകുകയുമില്ല.",
  "285": "ശരത്കാലത്തെ ആമ്പൽപൂവിനെ കൈകൊണ്ട് അനായാസം പറിച്ചുകളയുന്നതുപോലെ, തന്നോടുള്ള ആത്മസ്നേഹത്തെ (അഹംഭാവത്തെ) അറുത്തുമാറ്റുവിൻ; സുഗതൻ (ബുദ്ധൻ) ഉപദേശിച്ച പരമശാന്തി നൽകുന്ന നിർവ്വാണമാർഗ്ഗത്തെത്തന്നെ മുറുകെപ്പിടിക്കുവിൻ.",
  "286": "'വർഷാകാലത്ത് ഞാൻ ഇവിടെ പാർക്കും, ഹേമന്തത്തിലും ഗ്രീഷ്മത്തിലും ഇവിടെത്തന്നെ കഴിയും' എന്നിങ്ങനെ മൂഢനായ മനുഷ്യൻ വിചാരിച്ചുകൊണ്ടിരിക്കുന്നു; എന്നാൽ തന്റെ ജീവന് വരാനിരിക്കുന്ന വിഘ്നത്തെക്കുറിച്ചോ മരണത്തെക്കുറിച്ചോ അവൻ അറിയുന്നില്ല.",
  "287": "ഉറങ്ങിക്കിടക്കുന്ന ഗ്രാമത്തെ പെട്ടെന്നുണ്ടാകുന്ന വൻവെള്ളപ്പൊക്കം ഒഴുക്കിക്കൊണ്ടുപോകുന്നതുപോലെ, പുത്രന്മാരിലും മൃഗങ്ങളിലും ലൗകികസമ്പത്തിലും മനസ്സുടക്കി വിഷയാസക്തനായി കഴിയുന്ന മനുഷ്യനെ മൃത്യു പെട്ടെന്ന് തട്ടിക്കൊണ്ടുപോകുന്നു.",
  "288": "കാലന്റെ പിടിയിൽ അകപ്പെട്ടുപോയവനെ രക്ഷിക്കാൻ പുത്രന്മാർക്കോ, പിതാവിനോ, ബന്ധുക്കൾക്കോ, മറ്റ് ജ്ഞാതികളിൽ ആർക്കെങ്കിലുമോ സാധ്യമാവുകയില്ല; മരിക്കുമ്പോൾ ആരും തുണയാവുന്നില്ല.",
  "289": "ഈ പരമാർത്ഥത്തെ ശരിയായി മനസ്സിലാക്കി, പണ്ഡിതനും ശീലഗുണങ്ങളാൽ സംയമനം പാലിക്കുന്നവനുമായ മനുഷ്യൻ നിർവ്വാണത്തിലേക്ക് നയിക്കുന്ന സന്മാർഗ്ഗത്തെ വേഗത്തിൽത്തന്നെ വെട്ടിത്തെളിച്ച് ശുദ്ധമാക്കേണ്ടതാകുന്നു.",
  "chap21": "പകിണ്ണകവഗ്ഗോ",
  "290": "അല്പമായ സുഖം ഉപേക്ഷിക്കുന്നതിലൂടെ വലിയൊരു സുഖം കൈവരുമെന്ന് തിരിച്ചറിയുമ്പോൾ, ധീരനായ പണ്ഡിതൻ ആ വലിയ സുഖം നേടാനായി അല്പസുഖത്തെ സന്തോഷത്തോടെ ത്യജിക്കുന്നു.",
  "291": "അന്യർക്ക് ദുഃഖം വരുത്തിവെച്ച് അതിലൂടെ സ്വന്തം സുഖം കാംക്ഷിക്കുന്നവൻ, വൈരത്തിന്റെ (ദ്വേഷത്തിന്റെ) വലയിൽ അകപ്പെട്ട് ഒരിക്കലും ആ വൈരത്തിൽനിന്ന് മോചനം നേടാനാകാതെ വലയുന്നു.",
  "292": "ചെയ്യേണ്ടതായ കടമകൾ (കൃത്യങ്ങൾ) ചെയ്യാതിരിക്കുകയും, ചെയ്യരുതാത്ത വിലക്കപ്പെട്ട കാര്യങ്ങൾ (അകൃത്യങ്ങൾ) ചെയ്യുകയും ചെയ്യുന്ന അഹങ്കാരികളും പ്രമാദികളുമായ മനുഷ്യരിൽ ആശ്രവങ്ങൾ (ചിത്തമലങ്ങൾ) വർദ്ധിച്ചുകൊണ്ടേയിരിക്കും.",
  "293": "ഏതൊരുവന്റെയും ജാഗ്രത എപ്പോഴും സ്വന്തം ശാരീരിക കർമ്മങ്ങളെക്കുറിച്ചാണോ, അകൃത്യങ്ങൾ ചെയ്യാതിരിക്കുകയും ചെയ്യേണ്ട കൃത്യങ്ങളിൽ സദാ നിരതരായിരിക്കുകയും ചെയ്യുന്ന, സ്മൃതിയും വിവേകവുമുള്ള ആ ജ്ഞാനികളുടെ ആശ്രവങ്ങൾ അസ്തമിക്കുന്നു.",
  "294": "തൃഷ്ണയാകുന്ന മാതാവിനെയും, അഹങ്കാരമാകുന്ന പിതാവിനെയും, ശാശ്വത-ഉച്ഛേദ ദൃഷ്ടികളാകുന്ന രണ്ട് ക്ഷത്രിയ രാജാക്കന്മാരെയും, അനുചരന്മാരോടുകൂടിയ ഇന്ദ്രിയായതനങ്ങളാകുന്ന രാജ്യത്തെയും പൂർണ്ണമായി നശിപ്പിച്ചിട്ട് ബ്രാഹ്മണൻ (യഥാർത്ഥ ജ്ഞാനി) യാതൊരു ക്ലേശവുമില്ലാതെ പരമപഥം പ്രാപിക്കുന്നു.",
  "295": "തൃഷ്ണയാകുന്ന മാതാവിനെയും, അഹങ്കാരമാകുന്ന പിതാവിനെയും, രണ്ട് ശ്രോത്രിയ രാജാക്കന്മാരെയും, സദ്കർമ്മങ്ങൾക്ക് ബാധകമാകുന്ന കാമക്രോധാദി അഞ്ച് തടസ്സങ്ങളെയും (നിവാരണങ്ങളെ) വേരറുത്തിട്ട് ബ്രാഹ്മണൻ പാപരഹിതനായി ജീവിക്കുന്നു.",
  "296": "ഗൗതമശിഷ്യന്മാർ (ബുദ്ധശിഷ്യന്മാർ) എപ്പോഴും പൂർണ്ണമായ ഉണർവോടെ ജീവിക്കുന്നു; അവരുടെ ചിന്തകൾ രാവും പകലും എപ്പോഴും ബുദ്ധനെത്തന്നെ കേന്ദ്രീകരിച്ചിട്ടുള്ളതായിരിക്കും.",
  "297": "ഗൗതമശിഷ്യന്മാർ എപ്പോഴും ജാഗരൂകരായി ഉണർന്നിരിക്കുന്നു; രാപ്പകൽ ഭേദമന്യേ അവരുടെ ചിന്തകൾ സദാ ധർമ്മത്തെത്തന്നെ കേന്ദ്രീകരിച്ചിട്ടുള്ളതായിരിക്കും.",
  "298": "ഗൗതമശിഷ്യന്മാർ എപ്പോഴും ഉണർവുള്ളവരായി ജീവിക്കുന്നു; അവരുടെ മനസ്സും ചിന്തകളും രാപ്പകൽ സദാ ഭിക്ഷുസംഘത്തെത്തന്നെ കേന്ദ്രീകരിച്ചിട്ടുള്ളതായിരിക്കും.",
  "299": "ഗൗതമശിഷ്യന്മാർ എപ്പോഴും ആത്മബോധത്തോടെ ഉണർന്നിരിക്കുന്നു; അവരുടെ ചിന്തകൾ രാവും പകലും എപ്പോഴും സ്വന്തം ശരീരത്തിന്റെ (കായത്തിന്റെ) അനിത്യതയെയും സംയമനത്തെയും കുറിച്ചായിരിക്കും.",
  "300": "ഗൗതമശിഷ്യന്മാർ എപ്പോഴും അതീവ ജാഗ്രതയോടെ കഴിയുന്നു; രാപ്പകൽ എപ്പോഴും അവരുടെ മനസ്സ് അഹിംസയിലും കരുണയിലും മാത്രം രമിക്കുന്നതായിരിക്കും.",
  "301": "ഗൗതമശിഷ്യന്മാർ എപ്പോഴും ധ്യാനനിരതരായി ഉണർന്നിരിക്കുന്നു; അവരുടെ മനസ്സ് രാവും പകലും സമാധി ഭാവനയിൽ (ധ്യാനത്തിൽ) മാത്രം ലയിച്ചിരിക്കുന്നതാകുന്നു.",
  "302": "പ്രപഞ്ചസുഖങ്ങൾ വെടിഞ്ഞ് സന്യാസം (പ്രവ്രജ്യാ) സ്വീകരിക്കുന്നത് പ്രയാസമാണ്, അതിൽ രമിക്കുന്നതും പ്രയാസമാണ്; ഗൃഹസ്ഥാശ്രമ ജീവിതവും ദുഃഖകരമാണ്. സമാനമനസ്കരല്ലാത്തവരോടൊപ്പമുള്ള വാസവും ദുഃഖമാണ്, ലക്‌ഷ്യമില്ലാതെ അലഞ്ഞുതിരിയുന്നതും ദുഃഖമാണ്; അതിനാൽ വെറുതെ വേഷം കെട്ടി അലയുന്നവനാകരുത്, ദുഃഖത്തിന് ഇരയാകരുത്.",
  "303": "ദൃഢമായ ശ്രദ്ധയും ശുദ്ധമായ ശീലവുമുള്ളവനും, കീർത്തിയും ഐശ്വര്യവുമുള്ളവനുമായ പുണ്യപുരുഷൻ ഏതൊരു പ്രദേശത്ത് ചെല്ലുന്നുവോ, അവിടെയെല്ലാം അവൻ അത്യധികം പൂജിക്കപ്പെടുന്നു.",
  "304": "ഹിമവത് പർവ്വതമെന്നപോലെ സജ്ജനങ്ങളായ പുണ്യവാന്മാർ ദൂരത്തുനിന്നുപോലും പ്രകാശിച്ചു കാണപ്പെടുന്നു; എന്നാൽ ദുർജ്ജനങ്ങൾ രാത്രിയിൽ എയ്തുവിട്ട അമ്പുപോലെ എവിടെയും ദൃശ്യമാകാതെ ഇരുട്ടിൽ മറഞ്ഞുപോകുന്നു.",
  "305": "ഒരുവൻ ഏകനായി ഇരിക്കാൻ ശീലിക്കണം, ഏകനായി ഉറങ്ങണം, മടി കൂടാതെ ഏകാകിയായിത്തന്നെ സഞ്ചരിക്കണം; തനിയെ തന്റെ മനസ്സിനെ നിയന്ത്രിച്ചുകൊണ്ട് വനാന്തത്തിന്റെ (ഏകാന്തതയുടെ) ശാന്തിയിൽ രമിക്കുന്നവനാകണം.",
  "chap22": "നിരയവഗ്ഗോ",
  "306": "നുണ പറയുന്നവൻ നരകത്തിൽ പോകുന്നു; ചെയ്ത കർമ്മത്തെ ഇല്ലെന്നു പറയുന്നവനും അങ്ങനെയേ സംഭവിക്കൂ. ഇരുവരും പരലോകത്തിൽ തുല്യരായിത്തീരുന്നു; നീചമായ കർമ്മങ്ങൾ ചെയ്തവരാണല്ലോ അവർ.",
  "307": "കാവി വസ്ത്രം ധരിച്ച അനേകം പേർ അനിയന്ത്രിതരും ദുശ്ശീലരുമാണ്. ദുശ്ശീലം മൂലം അവർ സ്വന്തം പാപകർമ്മങ്ങളാൽ നരകത്തിൽ ജനിക്കുന്നു.",
  "308": "ദുശ്ശീലത്തോടും നിയന്ത്രണമില്ലാതെയും കഴിയുന്നവൻ നാട്ടുകാരുടെ ഭിക്ഷ സ്വീകരിക്കുന്നതിനേക്കാൾ നല്ലത് തീജ്വാലപോലെ കത്തുന്ന ഇരുമ്പ് ഗോളം ഭക്ഷിക്കുന്നതാണ്.",
  "309": "മറ്റൊരുവന്റെ ഭാര്യയോടൊത്തു കഴിയുന്ന അശ്രദ്ധനായ മനുഷ്യന് നാല് കാര്യങ്ങൾ സംഭവിക്കുന്നു: പാപം, ഉറക്കക്കുറവ്, അപമാനം, നരകപ്രാപ്തി.",
  "310": "ഭയപ്പെട്ട ദമ്പതികൾക്ക് അല്പനേരത്തെ സുഖം ലഭിക്കുമെങ്കിലും, പാപവും നരകപ്രാപ്തിയുമാണ് അതിലൂടെ അവന് ലഭിക്കുന്നത്; മാത്രമല്ല, രാജാവിനാൽ കഠിനമായ ശിക്ഷയും ലഭിക്കുന്നു. അതുകൊണ്ടാണ് മറ്റൊരുവന്റെ ഭാര്യയെ സമീപിക്കരുത് എന്ന് പറയുന്നത്.",
  "311": "ദർഭപ്പുല്ല് തെറ്റായി പിടിച്ചാൽ അത് കൈയെ മുറിപ്പെടുത്തുന്നതുപോലെ, തെറ്റായി സ്വീകരിച്ച സന്യാസജീവിതം (അവിനീതമായ സന്യാസം) നരകത്തിലേക്കാണ് നയിക്കുക.",
  "312": "എന്തെങ്കിലും മടിയുള്ള പ്രവർത്തനമോ, അശുദ്ധമായ ആചാരമോ, സംശയകരമായ സന്യാസജീവിതമോ അധികം ഫലപ്രദമല്ല.",
  "313": "എന്തെങ്കിലും ചെയ്യേണ്ടതുണ്ടെങ്കിൽ അത് നിശ്ചയദാർഢ്യത്തോടെ ചെയ്യണം. അലസമായി നയിക്കുന്ന സന്യാസജീവിതം ദോഷത്തെ വർദ്ധിപ്പിക്കുകയേ ഉള്ളൂ.",
  "314": "പാപകർമ്മങ്ങൾ ചെയ്യാതിരിക്കുന്നതാണ് നല്ലത്, കാരണം അത് പിന്നീട് ദുഃഖം നൽകും. സത്കർമ്മങ്ങൾ ചെയ്യുന്നതാണ് നല്ലത്, അത് പിന്നീട് ദുഃഖം നൽകുകയില്ല.",
  "315": "അതിർത്തിയിലുള്ള ഒരു നഗരം അകത്തും പുറത്തും കാവൽ ഏർപ്പെടുത്തിയിരിക്കുന്നതുപോലെ, നിങ്ങളെത്തന്നെ നന്നായി കാത്തുസൂക്ഷിക്കുക. നിമിഷങ്ങൾ പാഴാക്കരുത്. അവസരം നഷ്ടപ്പെടുത്തിയാൽ നരകത്തിൽ ചെന്ന് നിങ്ങൾ വിലപിക്കേണ്ടിവരും.",
  "316": "ലജ്ജിക്കേണ്ടതിനെക്കുറിച്ച് ലജ്ജയില്ലാത്തവരും, ലജ്ജിക്കേണ്ടതിനെക്കുറിച്ച് ലജ്ജിക്കുന്നവരും, തെറ്റായ കാഴ്ചപ്പാടുകൾ വെച്ചുപുലർത്തുന്നവരുമായ ജീവികൾ നരകത്തിൽ ജനിക്കുന്നു.",
  "317": "ആപത്തില്ലാത്ത സ്ഥലത്ത് ആപത്തുണ്ടെന്ന് ഭയപ്പെടുകയും, യഥാർത്ഥ ആപത്തിനെ അവഗണിക്കുകയും ചെയ്യുന്നവരും, തെറ്റായ കാഴ്ചപ്പാടുകൾ വെച്ചുപുലർത്തുന്നവരുമായ ജീവികൾ നരകത്തിൽ ജനിക്കുന്നു.",
  "318": "തെറ്റില്ലാത്തതിനെ കുറ്റമായി കാണുകയും, യഥാർത്ഥ കുറ്റത്തെ അവഗണിക്കുകയും ചെയ്യുന്നവരും, തെറ്റായ കാഴ്ചപ്പാടുകൾ വെച്ചുപുലർത്തുന്നവരുമായ ജീവികൾ നരകത്തിൽ ജനിക്കുന്നു.",
  "319": "കുറ്റത്തെ കുറ്റമായി തിരിച്ചറിയുകയും, കുറ്റമില്ലാത്തതിനെ കുറ്റമില്ലാത്തതായി തിരിച്ചറിയുകയും ചെയ്യുന്നവരും, ശരിയായ കാഴ്ചപ്പാടുകൾ വെച്ചുപുലർത്തുന്നവരുമായ ജീവികൾ സ്വർഗ്ഗലോകത്തിൽ (നല്ല ഗതിയിൽ) ജനിക്കുന്നു.",
  "chap23": "നാഗവഗ്ഗോ",
  "320": "യുദ്ധക്കളത്തിൽ ശത്രുക്കളുടെ വില്ലിൽനിന്ന് പാഞ്ഞുവരുന്ന അമ്പുകളെ ഏൽക്കേണ്ടിവരുന്ന ആനയെപ്പോലെ, ഞാൻ അന്യരുടെ ദുർവാക്കുകളെയും നിന്ദകളെയും ക്ഷമയോടെ സഹിച്ചുകൊള്ളാം. എന്തെന്നാൽ ഈ ലോകത്തിൽ അധികം ജനങ്ങളും ദുശ്ശീലമുള്ളവരാകുന്നു.",
  "321": "നന്നായി മെരുക്കിയെടുത്ത ആനയെയാണ് ജനങ്ങൾ സഭകളിലേക്ക് കൊണ്ടുപോകുന്നത്; അത്തരം ആനയുടെ പുറത്താണ് രാജാവ് കയറുന്നത്. അതുപോലെ അന്യരുടെ പരിഹാസങ്ങളെയും അധിക്ഷേപങ്ങളെയും ക്ഷമയോടെ സഹിക്കുന്ന, സ്വയം നിയന്ത്രിച്ച മനുഷ്യനാണ് മനുഷ്യരിൽവെച്ച് ഏറ്റവും ശ്രേഷ്ഠൻ.",
  "322": "നന്നായി മെരുക്കിയെടുത്ത കോവർകഴുതകളും, സിന്ധുദേശത്തുനിന്നുള്ള നല്ലയിനം കുതിരകളും, വലിയ കൊമ്പനാനകളും ഉത്തമ വാഹനങ്ങളാണ്; എന്നാൽ സ്വന്തം മനസ്സിനെ ശിക്ഷിച്ചൊതുക്കിയ മനുഷ്യൻ അതിനേക്കാളെല്ലാം എത്രയോ ശ്രേഷ്ഠനാകുന്നു.",
  "323": "മേൽപ്പറഞ്ഞ മൃഗങ്ങളാകുന്ന വാഹനങ്ങളിൽ ഏറിയാൽ ഒരുവന് ഇതുവരെ ആരും എത്തിച്ചേർന്നിട്ടില്ലാത്ത ആ പരമപഥത്തിലേക്ക് (നിർവ്വാണത്തിലേക്ക്) പോകാൻ സാധിക്കുകയില്ല; എന്നാൽ തന്റെ മനസ്സിനെ നന്നായി മെരുക്കിയെടുത്തവന്, നിയന്ത്രിതമായ ആത്മാവാകുന്ന ഉത്തമ വാഹനത്തിന്റെ സഹായത്താൽ അവിടെ എത്തിച്ചേരാം.",
  "324": "കവിളുകളിൽനിന്ന് മദം പ്രവഹിക്കുന്നവനും തടയാൻ പ്രയാസമേറിയതുമായ 'ധനപാലകൻ' എന്ന പേരുള്ള ആന, തളയ്ക്കപ്പെട്ട് ബന്ധനസ്ഥനായിരിക്കുമ്പോൾ ഒരൊറ്റ ഉരുള ഭക്ഷണംപോലും കഴിക്കുന്നില്ല; ആ സമയത്ത് അത് തന്റെ പ്രിയപ്പെട്ട ആനക്കാടിനെ (സ്വാതന്ത്ര്യത്തെ) മാത്രം ഓർത്തു കരയുന്നു.",
  "325": "ഒരുവൻ അമിതമായി ഭക്ഷണം കഴിച്ച് തടിച്ചുകൊഴുത്തവനും, ഉറക്കപ്രിയനും, കിടന്നകിടപ്പിൽ ഉരുളുന്നവനുമാണെങ്കിൽ, തീറ്റികൊടുത്തു തടിപ്പിച്ച വലിയ പന്നി വാസസ്ഥലത്ത് കിടന്നുരുളുന്നതുപോലെ, മൂഢനായ ആ മന്ദബുദ്ധി വീണ്ടും വീണ്ടും ജനനമരണങ്ങളാകുന്ന ഗർഭപാത്രത്തിൽ പ്രവേശിച്ചുകൊണ്ടിരിക്കും.",
  "326": "മുൻപ് ഈ മനസ്സ് അതിന്റെ ഇച്ഛയ്ക്കനുസരിച്ചും കാമവികാരങ്ങൾക്കനുസരിച്ചും തോന്നിയതുപോലെ സുഖമായി അലഞ്ഞുതിരിഞ്ഞു നടന്നിരുന്നു; എന്നാൽ ഇന്ന്, ആനക്കാരൻ തോട്ടി (അങ്കുശം) കൊണ്ട് മത്തഗജത്തെ അടക്കിനിർത്തുന്നതുപോലെ ഞാൻ ഈ മനസ്സിനെ വിവേകംകൊണ്ട് പൂർണ്ണമായും ഒതുക്കിനിർത്തും.",
  "327": "നിങ്ങൾ എപ്പോഴും അതീവ ജാഗ്രതയുള്ളവരായിരിക്കുവിൻ; സ്വന്തം ചിത്തത്തെ കാത്തുസൂക്ഷിക്കുവിൻ. ചതുപ്പിൽ (ചളിയിൽ) താണുപോയ ആന സ്വന്തം കരുത്തുകൊണ്ട് സ്വയം വലിച്ചുകയറുന്നതുപോലെ, നിങ്ങൾ നിങ്ങളെത്തന്നെ ദുർമാർഗ്ഗമാകുന്ന നാശത്തിൽനിന്ന് ഉദ്ധരിക്കുവിൻ.",
  "328": "വിവേകശാലിയും, സദ്വൃത്തനും, ധീരനുമായ ഒരു നല്ല കൂട്ടുകാരനെ സഹായിയായി ലഭിക്കുകയാണെങ്കിൽ, എല്ലാത്തരം വിപത്തുകളെയും അതിജീവിച്ച്, അതീവ സന്തുഷ്ടനായും ആത്മബോധത്തോടെയും അദ്ദേഹത്തോടൊപ്പം ജീവിക്കണം.",
  "329": "വിവേകശാലിയും സദ്വൃത്തനുമായ അത്തരം ഒരു ഉത്തമ സഹായിയെ കൂട്ടിന് കിട്ടിയില്ലെങ്കിൽ, ശത്രുക്കൾ കീഴടക്കിയ സ്വന്തം രാജ്യം ഉപേക്ഷിച്ചുപോകുന്ന രാജാവിനെപ്പോലെയും, മാതംഗവനത്തിൽ തനിയെ അലയുന്ന ഒറ്റയാനായ ആനയെപ്പോലെയും ഏകാകിയായി സഞ്ചരിക്കണം.",
  "330": "ഒറ്റയ്ക്ക് ജീവിക്കുന്നതാണ് ഏറ്റവും ഉത്തമം; എന്തെന്നാൽ മൂഢനായ ഒരുവനുമായി കൂട്ടുകൂടുന്നതിൽ യാതൊരു ഗുണവുമില്ല. ആഗ്രഹങ്ങൾ ചുരുക്കി, പാപങ്ങളൊന്നും ചെയ്യാതെ, മാതംഗവനത്തിലെ ആനയെപ്പോലെ ഏകാകിയായിത്തന്നെ ജീവിക്കണം.",
  "331": "ജീവിതത്തിൽ എന്തെങ്കിലും ആവശ്യം (ക്ലേശം) വരുമ്പോൾ വിശ്വസ്തരായ കൂട്ടുകാരെ ലഭിക്കുന്നത് സുഖകരമാണ്; ഏതു സാഹചര്യത്തിലും ഉള്ളതുകൊണ്ട് തൃപ്തിപ്പെടുന്നത് സുഖകരമാണ്; ആയുസ്സിന്റെ അവസാനസമയത്ത് താൻ ചെയ്ത പുണ്യം തുണയാകുന്നത് സുഖകരമാണ്; സർവ്വ ദുഃഖങ്ങളെയും പൂർണ്ണമായി ഇല്ലാതാക്കുന്നത് പരമസുഖമാകുന്നു.",
  "332": "ലോകത്തിൽ മാതാവിനോട് ഭക്തിയോടും ദയയോടും കൂടി പെരുമാറുന്നത് (മാതൃത്വം) സുഖകരമാണ്; പിതാവിനെ ബഹുമാനിക്കുന്നത് (പിതൃത്വം) സുഖകരമാണ്; സന്യാസജീവിതം നയിക്കുന്നത് (ശ്രമണത്വം) സുഖകരമാണ്; ബ്രഹ്മജ്ഞാനിയായി ജീവിക്കുന്നത് (ബ്രാഹ്മണത്വം) സുഖകരമാകുന്നു.",
  "333": "വാർദ്ധക്യം വരേയ്ക്കും സദാചാരം (ശീലം) പാലിക്കുന്നത് സുഖകരമാണ്; ധർമ്മത്തിൽ വേരുറച്ച ശ്രദ്ധയുള്ളവനായിരിക്കുന്നത് സുഖകരമാണ്; യഥാർത്ഥ ജ്ഞാനം കൈവരുന്നത് സുഖകരമാണ്; ജീവിതത്തിൽ ഒരുവിധത്തിലുള്ള പാപങ്ങളും ചെയ്യാതിരിക്കുന്നത് പരമ സുഖമാകുന്നു.",
  "chap24": "തණ්ഹാവഗ്ഗോ",
  "334": "പ്രമാദശീലനായ (അശ്രദ്ധനായ) മനുഷ്യന്റെ ഉള്ളിൽ തൃഷ്ണ, കാട്ടിൽ പടർന്നുപിടിക്കുന്ന 'മാലൂവാ' ലതപോലെ വളരുന്നു; കാട്ടിൽ പഴങ്ങൾ കൊതിച്ച് മരങ്ങളിൽനിന്ന് മരങ്ങളിലേക്ക് ചാടിനടക്കുന്ന കുരങ്ങനെപ്പോലെ അവൻ ജന്മങ്ങളിൽനിന്ന് ജന്മങ്ങളിലേക്ക് അലഞ്ഞുതിരിയുന്നു.",
  "335": "ഈ ലോകത്തിൽ അതിഭയങ്കരമായ വിഷം നിറഞ്ഞ, പറ്റിപ്പിടിക്കുന്ന തൃഷ്ണ ഏതൊരുവനെയാണോ കീഴടക്കുന്നത്, മഴ പെയ്യുമ്പോൾ വീരണപ്പുല്ല് തഴച്ചുവളരുന്നതുപോലെ അവന്റെ ദുഃഖങ്ങൾ വർദ്ധിച്ചുകൊണ്ടേയിരിക്കുന്നു.",
  "336": "ഈ ലോകത്തിൽ കീഴടക്കാൻ ഏറ്റവും പ്രയാസമേറിയ ഈ അധമ തൃഷ്ണയെ ഏതൊരുവൻ ജയിക്കുന്നുവോ, താമരയിലയിൽനിന്ന് വെള്ളത്തുള്ളികൾ അനായാസം ഒഴിഞ്ഞുപോകുന്നതുപോലെ അവന്റെ ശോകങ്ങൾ അവനിൽനിന്ന് ഒഴിഞ്ഞുപോകുന്നു.",
  "337": "ഇവിടെ ഒരുമിച്ചുകൂടിയിരിക്കുന്ന നിങ്ങൾക്കെല്ലാവർക്കും ക്ഷേമമുണ്ടാകാനായി ഞാൻ ഒരു കാര്യം പറയാം: സുഗന്ധമുള്ള രാമച്ചത്തിന്റെ വേരിനായി വീരണപ്പുല്ല് സമൂലം തോണ്ടിപ്പറിച്ച് കളയുന്നതുപോലെ നിങ്ങൾ തൃഷ്ണയെ വേരോടെ പിഴുതെറിയുവിൻ. കുത്തൊഴുക്ക് ആറ്റിലെ ചണപ്പുല്ലിനെ തകർത്തുകളയുന്നതുപോലെ മാരൻ നിങ്ങളെ വീണ്ടും വീണ്ടും നശിപ്പിക്കാൻ ഇടവരരുത്.",
  "338": "വൃക്ഷത്തിന്റെ വേരുകൾക്ക് കേടുപാടുകൾ സംഭവിക്കാതെ ദൃഢമായിരുന്നാൽ, അത് മുകളിൽനിന്ന് വെട്ടിമാറ്റിയാലും വീണ്ടും തളിർത്തു വളരും; അതുപോലെ മനസ്സിൽ ഒളിഞ്ഞിരിക്കുന്ന തൃഷ്ണയുടെ വേരുകളെ പൂർണ്ണമായി നശിപ്പിക്കാതിരുന്നാൽ, ഈ ജന്മദുഃഖങ്ങൾ വീണ്ടും വീണ്ടും ഉണ്ടായിക്കൊണ്ടേയിരിക്കും.",
  "339": "ഏതൊരുവന്റെ ഉള്ളിലാണ് മനസ്സിനെ ഇളക്കിമറിക്കുന്ന സുഖഭോഗങ്ങളാകുന്ന മുപ്പത്താറ് തൃഷ്ണാപ്രവാഹങ്ങൾ ശക്തമായി ഒഴുകുന്നത്, കണ്ണ് മങ്ങിയവനും രാഗത്തിന് അടിമയുമായ ആ മനുഷ്യനെ ആസക്തിയിൽനിന്നുണ്ടാകുന്ന സങ്കല്പങ്ങൾ (മോഹങ്ങൾ) ഒഴുക്കിക്കൊണ്ടുപോകുന്നു.",
  "340": "ഈ തൃഷ്ണാപ്രവാഹങ്ങൾ എല്ലാ ഇന്ദ്രിയദ്വാരങ്ങളിലൂടെയും ഒഴുകുന്നു; തൃഷ്ണയാകുന്ന ലത മുളച്ചുപൊന്തി പടർന്നുപന്തലിച്ചു നിൽക്കുന്നു. ഈ ലത പടരുന്നത് കാണുമ്പോൾത്തന്നെ പ്രജ്ഞയാകുന്ന മൂർച്ചയേറിയ ആയുധംകൊണ്ട് അതിന്റെ വേരറുത്തു കളയണം.",
  "341": "മനുഷ്യന് ഇന്ദ്രിയവിഷയങ്ങളോടുള്ള സ്നേഹവും സുഖഭോഗങ്ങളും നദിപോലെ ഒഴുകിക്കൊണ്ടിരിക്കുന്നു; അവർ എപ്പോഴും ആ ലൗകികസുഖങ്ങളെത്തന്നെ ആശ്രയിച്ച് അതിൽ മുഴുകിക്കഴിയുന്നു. സുഖം മാത്രം കൊതിച്ച് തൃഷ്ണയിൽ കുടുങ്ങിക്കിടക്കുന്ന ആ മനുഷ്യർ വീണ്ടും വീണ്ടും ജനനമരണങ്ങളാകുന്ന ജരാനരകൾക്ക് ഇരയായിത്തീരുന്നു.",
  "342": "വേട്ടക്കാരന്റെ വലയിൽ കുടുങ്ങിപ്പോയ മുയലിനെപ്പോലെ മനുഷ്യർ തൃഷ്ണയാകുന്ന വലയിൽ കുടുങ്ങി ഭയന്നോടുന്നു; ലൗകികബന്ധനങ്ങളിൽ അമർന്നുപോയ അവർ വളരെക്കാലം വീണ്ടും വീണ്ടും സംസാരദുഃഖങ്ങൾ അനുഭവിച്ചുകൊണ്ടേയിരിക്കുന്നു.",
  "343": "വലയിൽപ്പെട്ട മുയലിനെപ്പോലെ തൃഷ്ണയിൽ അകപ്പെട്ട ജനങ്ങൾ ഉഴലുന്നു; അതിനാൽ തനിക്ക് പൂർണ്ണമായ വൈരാഗ്യവും (മുക്തിയും) ഉണ്ടാകാൻ ആഗ്രഹിക്കുന്ന ഭിക്ഷു, തന്റെ ഉള്ളിലെ തൃഷ്ണയെ പൂർണ്ണമായി അകറ്റി നിർത്തേണ്ടതാകുന്നു.",
  "344": "ഗൃഹസ്ഥാശ്രമമാകുന്ന കാടിനെ വെടിഞ്ഞ് സന്യാസമാകുന്ന തപോവനത്തിൽ പ്രവേശിച്ചതിനുശേഷം, വീണ്ടും പഴയ ലൗകികബന്ധനങ്ങളാകുന്ന കാട്ടിലേക്ക് തന്നെ തിരിഞ്ഞോടുന്ന മനുഷ്യനെ നോക്കൂ! ബന്ധനത്തിൽനിന്ന് മോചിതനായിട്ടും അവൻ വീണ്ടും പഴയ തടവറയിലേക്ക് തന്നെയാണ് ഓടിയടുക്കുന്നത്.",
  "345": "ഇരുമ്പുകൊണ്ട് ഉണ്ടാക്കിയതോ, തടികൊണ്ട് ഉണ്ടാക്കിയതോ, കയറുകൊണ്ട് മുറുക്കിയതോ ആയ ബന്ധനങ്ങളെ (ചങ്ങലകളെ)യല്ല ബുദ്ധിമാന്മാർ ദൃഢമായ ബന്ധനമെന്ന് പറയുന്നത്; മറിച്ച് വിലയേറിയ മണികുണ്ഡലങ്ങളോടും ആഭരണങ്ങളോടും ഉള്ള അതിരറ്റ ആസക്തിയെയാണ് അവർ യഥാർത്ഥ ബന്ധനമെന്ന് വിളിക്കുന്നത്.",
  "346": "ഇരുമ്പ്, മരം, ചണനാര് (വക്കുനാർ) എന്നിവകൊണ്ടുണ്ടാക്കുന്ന ചങ്ങലകളെ വലിയ ബന്ധനങ്ങളെന്ന് ബുദ്ധിമാന്മാർ പറയുന്നില്ല; എന്നാൽ മണികുണ്ഡലങ്ങളോടുള്ള ആർത്തിയും, പുത്രന്മാരിലും ഭാര്യമാരിലുമുള്ള അമിതമായ മോഹവുമാണ് എല്ലാറ്റിലും ഉറപ്പേറിയ ബന്ധനം.",
  "347": "അധഃപതനത്തിലേക്ക് വലിച്ചിഴയ്ക്കുന്നതും, പുറമേ അയഞ്ഞതെന്ന് തോന്നിയാലും അറുത്തുമാറ്റാൻ ഏറ്റവും പ്രയാസമേറിയതുമായ തൃഷ്ണാബന്ധനമാണ് ഏറ്റവും ശക്തമെന്ന് വിദ്വാന്മാർ പറയുന്നു; ഈ ആസക്തിയെക്കൂടി ഛേദിച്ചുകളഞ്ഞിട്ടാണ് ധീരന്മാർ കാമസുഖങ്ങളെല്ലാം വെടിഞ്ഞ് സന്യാസം സ്വീകരിക്കുന്നത്.",
  "348": "ചിലന്തി സ്വന്തമായി നെയ്തുണ്ടാക്കിയ വലയിൽത്തന്നെ കുടുങ്ങിപ്പോകുന്നതുപോലെ, തീവ്രമായ രാഗത്തിന് അടിമപ്പെട്ട മനുഷ്യർ തങ്ങൾതന്നെ സൃഷ്ടിച്ച തൃഷ്ണാപ്രവാഹത്തിൽ അകപ്പെട്ടുപോകുന്നു; എന്നാൽ വിവേകശാലികൾ ഈ ആസക്തിയെ പൂർണ്ണമായി മുറിച്ചുമാറ്റി, യാതൊരു അപേക്ഷയുമില്ലാതെ സർവ്വേ ദുഃഖങ്ങളും വെടിയുന്നു.",
  "349": "ഹേ ഉഗ്രസേനാ, നീ സംസാരസാഗരത്തിന്റെ മറുകര പറ്റി മുക്തിനേടാൻ ആഗ്രഹിക്കുന്നുവെങ്കിൽ നിന്റെ ഭൂതകാലത്തോടുള്ള ആസക്തിയെയും (മുൻപിലുള്ളത്), ഭാവികാലത്തോടുള്ള മോഹങ്ങളെയും (പിൻപിലുള്ളത്), വർത്തമാനകാല ഭോഗങ്ങളെയും (ഇടയിലുള്ളത്) ഉപേക്ഷിക്കുക; എല്ലാറ്റിൽനിന്നും മനസ്സ് മുക്തമായാൽ നീ വീണ്ടും ജനനമരണങ്ങളാകുന്ന ജരാനരകളിലേക്ക് മടങ്ങിവരികയില്ല.",
  "350": "മനസ്സിനെ അലട്ടുന്ന ദുർവിചാരങ്ങളാൽ വലയുന്നവനും, കഠിനമായ രാഗത്താൽ മൂടപ്പെട്ടവനും, ബാഹ്യമായ രമ്യതയെ (ശരീരഭംഗിയെ) മാത്രം നോക്കിനിൽക്കുന്നവനുമായ മനുഷ്യന്റെ ഉള്ളിൽ തൃഷ്ണ മേൽക്കുമേൽ വർദ്ധിച്ചുകൊണ്ടേയിരിക്കുന്നു; അവൻ തന്റെ ബന്ധനത്തെ കൂടുതൽ ദൃഢമാക്കുകയാണ് ചെയ്യുന്നത്.",
  "351": "മനസ്സിലെ ദുർവിചാരങ്ങളെ ശമിപ്പിക്കുന്നതിൽ താല്പര്യമുള്ളവനും, ലൗകികവസ്തുക്കളുടെ അശുഭഭാവനയെ (അസ്ഥിരതയെയും അശുദ്ധിയെയും) സദാ ആത്മബോധത്തോടെ ധ്യാനിക്കുന്നവനുമായ മനുഷ്യൻ നിശ്ചയമായും തൃഷ്ണയെ ഇല്ലാതാക്കും; അവൻ മാരന്റെ ബന്ധനത്തെ പൂർണ്ണമായി അറുത്തുമാറ്റുകയും ചെയ്യും.",
  "352": "പരമമായ ലക്ഷ്യത്തിലെത്തിയവനും, ഭയരഹിതനും, തൃഷ്ണയും ചിത്തമലങ്ങളും ഒഴിഞ്ഞവനുമായ ആ ജ്ഞാനി സംസാരമാകുന്ന ജീവിതശല്യങ്ങളെ മുഴുവൻ പിഴുതെറിഞ്ഞിരിക്കുന്നു; ഇതവന്റെ അവസാനത്തെ ശരീരമാകുന്നു (ഇനി അവന് ജന്മമില്ല).",
  "353": "തൃഷ്ണയും ആസക്തിയും പൂർണ്ണമായി നശിച്ചവനും, നിരുക്തിയും ശബ്ദശാസ്ത്രവും നന്നായി ഗ്രഹിച്ചവനും, അക്ഷരങ്ങളുടെ കോർപ്പും അവയുടെ പൂർവ്വാപരബന്ധവും അറിയുന്നവനുമായ ആ മനുഷ്യൻ തന്റെ അവസാന ജന്മത്തിലാണ് ജീവിക്കുന്നത്; അവനെയാണ് 'മഹാപ്രാജ്ഞൻ' എന്നും 'മഹാപുരുഷൻ' എന്നും വിളിക്കുന്നത്.",
  "354": "ഞാൻ സർവ്വതിനെയും ജയിച്ചവനും, എല്ലാം അറിയുന്നവനും, സർവ്വ ധർമ്മങ്ങളിലും (പ്രതിഭാസങ്ങളിലും) കളങ്കപ്പെടാതെ ഒഴിഞ്ഞുനിൽക്കുന്നവനുമാകുന്നു; എല്ലാം ത്യജിച്ച്, തൃഷ്ണ നശിച്ച് മുക്തനായ ഞാൻ എന്റെ സ്വന്തം പ്രജ്ഞയാൽത്തന്നെയാണ് ഇത് സാക്ഷാത്കരിച്ചത്, ഇനി ആരെയാണ് ഞാൻ എന്റെ ഗുരുവായി ചൂണ്ടിക്കാണിക്കേണ്ടത്?",
  "355": "ധർമ്മദാനം മറ്റെല്ലാ ദാനങ്ങളെക്കാളും ശ്രേഷ്ഠമാകുന്നു; ധർമ്മത്തിന്റെ സ്വാദ് (രസം) മറ്റെല്ലാ ലൗകിക രസങ്ങളെയും ജയിക്കുന്നു; ധർമ്മത്തോടുള്ള പ്രീതി മറ്റെല്ലാ ആനന്ദങ്ങളെയും ജയിക്കുന്നു; തൃഷ്ണയുടെ പൂർണ്ണമായ നാശം സർവ്വ ദുഃഖങ്ങളെയും ഇല്ലായ്മ ചെയ്യുന്നു.",
  "356": "ലൗകികഭോഗങ്ങൾ മൂഢനായ മനുഷ്യനെ നശിപ്പിച്ചുകളയുന്നു; എന്നാൽ സംസാരസാഗരത്തിന്റെ മറുകര തേടുന്ന മുമുക്ഷുക്കളെ അവ ബാധിക്കുന്നില്ല. ലൗകികസുഖങ്ങളോടുള്ള തൃഷ്ണ കാരണം മൂഢൻ മറ്റുള്ളവരെയെന്നപോലെ സ്വന്തം ആത്മാവിനെയും നശിപ്പിക്കുന്നു.",
  "357": "കളകൾ നിറഞ്ഞതാണ് കൃഷിനിലങ്ങൾക്ക് നാശം വരുത്തുന്നത്; അതുപോലെ രാഗദ്വേഷങ്ങളാണ് മനുഷ്യരാശിയെ നശിപ്പിക്കുന്നത്. അതിനാൽ രാഗം ഒഴിഞ്ഞവരായ (വീതരാഗരായ) സജ്ജനങ്ങൾക്കായി നൽകുന്ന ദാനം മഹാഫലം നൽകുന്നതാകുന്നു.",
  "358": "പുല്ലുകൾ വളരുന്നതാണ് കൃഷിഭൂമിയെ നശിപ്പിക്കുന്നത്; അതുപോലെ ക്രോധമാണ് (ദ്വേഷം) മനുഷ്യർക്ക് ദോഷം വരുത്തുന്നത്. അതിനാൽ ക്രോധം ഒഴിഞ്ഞവരായ പുണ്യവാന്മാർക്ക് നൽകുന്ന ദാനത്തിന് വലിയ ഫലസിദ്ധിയുണ്ട്.",
  "359": "കളകൾ നിറഞ്ഞതാണ് കൃഷിപ്പാടങ്ങളെ നശിപ്പിക്കുന്നത്; അതുപോലെ മോഹമാണ് (അജ്ഞത) മനുഷ്യന് ദോഷം ചെയ്യുന്നത്. അതിനാൽ മോഹമൊഴിഞ്ഞ ജ്ഞാനികൾക്ക് ചെയ്യുന്ന ദാനം എപ്പോഴും മഹാഫലപ്രദമാകുന്നു. കൃഷിസ്ഥലങ്ങൾക്ക് ദോഷം വരുത്തുന്നത് പുല്ലുകളാണ്; അതുപോലെ മനുഷ്യർക്ക് ദോഷം വരുത്തുന്നത് അവരുടെ അടങ്ങാത്ത ഇച്ഛയാണ് (ആഗ്രഹങ്ങൾ). അതിനാൽ ഇച്ഛകളില്ലാത്ത വീതാശന്മാർക്ക് നൽകുന്ന ദാനം ഏറ്റവും വലിയ പുണ്യഫലം നൽകുന്നതാകുന്നു.",
  "chap25": "ഭിക്ഖുവഗ്ഗോ",
  "360": "കണ്ണ്, കാത്, മൂക്ക്, നാക്ക് എന്നിവയിലൂടെയുള്ള ഇന്ദ്രിയസംയമനം അഥവാ അടക്കം എപ്പോഴും നല്ലതാകുന്നു.",
  "361": "ശരീരത്തെ അടക്കിനിർത്തുന്നത് നല്ലതാണ്; വാക്കിനെ നിയന്ത്രിക്കുന്നത് നല്ലതാണ്; മനസ്സിനെ കാത്തുസൂക്ഷിക്കുന്നത് നല്ലതാണ്; ചിന്തകളെ അടക്കുന്നത് നല്ലതാണ്. ലൗകികവസ്തുക്കളിൽനിന്നെല്ലാം ഇന്ദ്രിയങ്ങളെ പിന്തിരിപ്പിച്ച് സർവ്വത്ര സംയമനം പാലിക്കുന്ന ഭിക്ഷു സർവ്വ ദുഃഖങ്ങളിൽനിന്നും പൂർണ്ണമായി മോചിക്കപ്പെടുന്നു.",
  "362": "കൈകളും കാലുകളും വാക്കും നിയന്ത്രിച്ചവനും, സംയമനം പാലിക്കുന്നവരിൽ ഉത്തമനും, എപ്പോഴും ആത്മചിന്തയിൽ മുഴുകിയവനും, ഏകാകിയും, ഉള്ളതുകൊണ്ട് തൃപ്തിപ്പെടുന്നവനുമായ മനുഷ്യനെയാണ് യഥാർത്ഥ 'ഭിക്ഷു' എന്ന് വിളിക്കുന്നത്.",
  "363": "ഏതൊരു ഭിക്ഷുവാണോ തന്റെ നാവിനെ നിയന്ത്രിച്ചു നിർത്തി, അഹങ്കാരമില്ലാതെ മിതമായും ശാന്തമായും സംസാരിക്കുകയും, ധർമ്മത്തിന്റെ അന്തസ്സത്തയും അർത്ഥവും വ്യക്തമാക്കിക്കൊണ്ട് പ്രസംഗിക്കുകയും ചെയ്യുന്നത്, അവന്റെ വാക്കുകൾ കേൾക്കാൻ അതീവ മധുരമുള്ളതായിരിക്കും.",
  "364": "ധർമ്മത്തിൽത്തന്നെ രമിക്കുന്നവനും, ധർമ്മത്തിൽ സന്തുഷ്ടനും, ധർമ്മതത്ത്വങ്ങളെക്കുറിച്ച് എപ്പോഴും ആഴത്തിൽ ചിന്തിക്കുകയും അനുസ്മരിക്കുകയും ചെയ്യുന്ന ഭിക്ഷു, നേരായ സദ്ധർമ്മത്തിൽനിന്ന് ഒരിക്കലും വ്യതിചലിക്കുകയോ തെറ്റിപ്പോകുകയോ ഇല്ല.",
  "365": "തനിക്ക് ലഭിക്കുന്ന ലാഭം ചെറുതാണെങ്കിലും വലുതാണെങ്കിലും അതിനെ നിസ്സാരമായിക്കണ്ട് വെറുക്കരുത്; അതുപോലെ അന്യർക്ക് ലഭിക്കുന്നതിനെച്ചൊല്ലി അസൂയപ്പെടുകയും അരുത്. മറ്റുള്ളവരോട് അസൂയ വെച്ചുപുലർത്തുന്ന ഭിക്ഷുവിന് ഒരിക്കലും മനസ്സമാധാനമോ (സമാധിയോ) കൈവരികയില്ല.",
  "366": "തനിക്ക് കിട്ടുന്ന ലാഭം വളരെ തുച്ഛമാണെങ്കിൽപ്പോലും അതിനെ നിന്ദിക്കാതെ തൃപ്തിപ്പെടുകയും, പരിശുദ്ധമായ ജീവിതം നയിക്കുകയും, മടിയില്ലാതെ ഉത്സാഹത്തോടെയിരിക്കുകയും ചെയ്യുന്ന ഭിക്ഷുവിനെ ദേവന്മാർപോലും ആദരവോടെ പ്രശംസിക്കുന്നു.",
  "367": "തന്റെ ശരീരത്തോടും മനസ്സിനോടും (നാമരൂപങ്ങളോട്) ഒട്ടുംതന്നെ മമതയില്ലാത്തവനും, ലൗകികവസ്തുക്കളുടെ അഭാവത്തിൽ (നഷ്ടങ്ങളിൽ) ലേശംപോലും ദുഃഖിക്കാത്തവനുമായ മനുഷ്യൻ ആരോ, അവനെയാണ് യഥാർത്ഥത്തിൽ 'ഭിക്ഷു' എന്ന് പറയേണ്ടത്.",
  "368": "സർവ്വ ജീവജാലങ്ങളോടും കരുണയോടും മൈത്രിയോടും കൂടി ജീവിക്കുന്നവനും, ബുദ്ധഭഗവാന്റെ ഉപദേശങ്ങളിൽ പൂർണ്ണമായി പ്രസന്നനുമായ ഭിക്ഷു, ലൗകികവാസനകളുടെ നിവൃത്തിയിൽനിന്നുണ്ടാകുന്ന ശാന്തവും പരമസുഖപ്രദവുമായ നിർവ്വാണപദം പ്രാപിക്കുന്നു.",
  "369": "ഹേ ഭിക്ഷോ, ലൗകികാസക്തിയാകുന്ന ഈ തോണിയിലെ വെള്ളം (രാഗദ്വേഷങ്ങൾ) നീ തേവിക്കളയുക; വെള്ളം ഒഴിഞ്ഞാൽ ഈ തോണി വേഗത്തിൽ സഞ്ചരിക്കും. അതുപോലെ നിന്റെ ഉള്ളിലെ രാഗത്തെയും ദ്വേഷത്തെയും പൂർണ്ണമായി ഛേദിച്ചുമാറ്റിയാൽ നിനക്ക് അനായാസം നിർവ്വാണം പ്രാപിക്കാം.",
  "370": "മനുഷ്യൻ തന്റെ ഉള്ളിലെ അഞ്ച് കീഴ്ബന്ധനങ്ങളെ (മിഥ്യാസങ്കല്പം, സംശയം, മിഥ്യാചാരം, ഭോഗേച്ഛ, ഹിംസ) ഛേദിക്കണം; അഞ്ച് മേൽബന്ധനങ്ങളെ (രൂപരാഗം, അരൂപരാഗം, അഹങ്കാരം, അസ്ഥിരത, അവിദ്യ) വെടിയണം; അഞ്ച് ഗുണങ്ങളെ (ശ്രദ്ധ, ഉത്സാഹം, സ്മൃതി, സമാധി, പ്രജ്ഞ) വളർത്തണം; അഞ്ച് മലങ്ങളെ (ലോഭം, ദ്വേഷം, മോഹം, മാനം, മിഥ്യാകല്പന) കടന്നുപോകണം. ഇപ്രകാരം ചെയ്യുന്ന ഭിക്ഷുവാണ് സംസാരപ്രവാഹത്തെ കടന്നവൻ.",
  "371": "ഹേ ഭിക്ഷോ, നീ പ്രമാദത്തിന് (മടിക്ക്) അടിപ്പെടാതെ സദാ ധ്യാനിക്കുക; നിന്റെ ചിത്തം കാമഭോഗങ്ങളിൽ ഉലയാൻ ഇടവരുത്തരുത്. അശ്രദ്ധകാരണം നരകത്തിലെ ഉരുകിയ ഇരുമ്പുണ്ട വിഴുങ്ങേണ്ടി വരുന്ന അവസ്ഥ വരുത്തരുത്; അന്ന് തീവ്രവേദനയാൽ 'അയ്യോ ഞാൻ വെന്തുരുകുന്നേ' എന്ന് നിലവിളിക്കാൻ ഇടയാക്കരുത്.",
  "372": "യഥാർത്ഥ ജ്ഞാനമില്ലാത്തവന് (അപ്രജ്ഞന്) ധ്യാനമില്ല; ധ്യാനമില്ലാത്തവന് യഥാർത്ഥ ജ്ഞാനം കൈവരുകയുമില്ല. എന്നാൽ ഏതൊരുവന്റെ ഉള്ളിലാണോ പ്രജ്ഞയും ധ്യാനവും ഒരുപോലെ ഒത്തുചേരുന്നത്, അവൻ നിർവ്വാണത്തോട് ഏറ്റവും അടുത്തവനാകുന്നു.",
  "373": "വിജനമായ ശൂന്യാലയത്തിൽ (ഏകാന്തതയിൽ) പ്രവേശിച്ച്, മനസ്സ് പൂർണ്ണമായും ശാന്തമാക്കി, ധർമ്മത്തെ യഥാവിധി ദർശിക്കുന്ന ഭിക്ഷുവിന് ലൗകികാതീതമായ (അമാനുഷികമായ) ആനന്ദം അനുഭവപ്പെടുന്നു.",
  "374": "ശരീരത്തിന്റെ പഞ്ചസ്കന്ധങ്ങളുടെ ഉത്പത്തിയും വിനാശവും (അസ്ഥിരത) എപ്പോഴൊക്കെയാണോ ഒരുവൻ ആഴത്തിൽ ചിന്തിച്ചറിയുന്നത്, അപ്പോഴെല്ലാം അവന് അമൃത് ആസ്വദിച്ചതുപോലെയുള്ള പരമമായ പ്രീതിയും അളക്കാനാവാത്ത സന്തോഷവും ഉണ്ടാകുന്നു.",
  "375": "ഇന്ദ്രിയങ്ങളെ കാത്തുസൂക്ഷിക്കുക, ഉള്ളതുകൊണ്ട് സംതൃപ്തനാവുക, ധർമ്മനിയമങ്ങൾ (പ്രാതിമോക്ഷം) പാലിക്കുക, പരിശുദ്ധമായ ജീവിതം നയിക്കുന്നവരും അപ്രമാദികളുമായ ഉത്തമ മിത്രങ്ങളെ ഭജിക്കുകഇവയെല്ലാമാണ് ജ്ഞാനിയായ ഒരു ഭിക്ഷുവിന്റെ ആദ്യത്തെ കർത്തവ്യങ്ങൾ.",
  "376": "എല്ലാവരോടും സദ്വർത്തിയായി ജീവിക്കുകയും ആചാരമര്യാദകളിൽ അത്യന്തം സമർത്ഥനായിരിക്കുകയും വേണം; അതിലൂടെ സന്തോഷം വർദ്ധിക്കുകയും അവൻ ലൗകികദുഃഖങ്ങൾക്ക് ശാശ്വതമായ അന്ത്യം കുറിക്കുകയും ചെയ്യും.",
  "377": "ഹേ ഭിക്ഷുക്കളേ, മുല്ലവള്ളി തന്നിൽ വിരിഞ്ഞ വാടിയ പഴയ പുഷ്പങ്ങളെ അനായാസം കൊഴിച്ചുകളയുന്നതുപോലെ, നിങ്ങൾ നിങ്ങളുടെ ഉള്ളിലെ രാഗദ്വേഷങ്ങളെ പൂർണ്ണമായും ഉപേക്ഷിച്ച് വിമുക്തന്മാരാകുവിൻ.",
  "378": "ശരീരവും വാക്കും മനസ്സും ശാന്തമാക്കിയവനും, സമാധിയിൽ ദൃഢമായി ലയിച്ചവനും, ലൗകികസുഖങ്ങളാകുന്ന ആഹാരത്തെ (ആസക്തികളെ) പൂർണ്ണമായി ഛർദ്ദിച്ചു കളഞ്ഞവനുമായ ഭിക്ഷുവിനെയാണ് 'ഉപശാന്തൻ' എന്ന് വിളിക്കുന്നത്.",
  "379": "നീ തന്നെ നിന്നെ ഉദ്ധരിക്കണം, തന്നെത്താൻ എപ്പോഴും പരിശോധിക്കണം. സ്വന്തം ആത്മാവിനെ കാത്തുസൂക്ഷിച്ച്, സദാ ഉണർവുള്ളവനായി (സ്മൃതിമാനായി) ജീവിക്കുന്ന ഭിക്ഷു എന്നും പരമസുഖത്തോടെ വാഴും.",
  "380": "തനിക്ക് നാഥൻ താൻതന്നെയാണ്; തനിക്ക് ഏക ആശ്രയവും (ഗതിയും) താൻതന്നെയാണ്. അതിനാൽ ബുദ്ധിമാനായ ഒരു വ്യാപാരി നല്ല കുതിരയെ മെരുക്കി നിർത്തുന്നതുപോലെ, നിങ്ങൾ നിങ്ങളെത്തന്നെ എപ്പോഴും നിയന്ത്രിച്ചു നിർത്തണം.",
  "381": "എപ്പോഴും സന്തോഷം നിറഞ്ഞവനും ബുദ്ധധർമ്മത്തിൽ അടിയുറച്ച ശ്രദ്ധയുള്ളവനുമായ ഭിക്ഷു, ലൗകികസംസ്കാരങ്ങളുടെ നിവൃത്തി നൽകുന്നതും, അതീവ ശാന്തവും സുഖപ്രദവുമായ നിർവ്വാണപദത്തെ പ്രാപിക്കുന്നു.",
  "382": "ചെറുപ്പക്കാരനായ ഒരു ഭിക്ഷുവാണെങ്കിൽപ്പോലും, അവൻ ബുദ്ധഭഗവാന്റെ ഉപദേശങ്ങൾ പൂർണ്ണമനസ്സോടെ അനുഷ്ഠിക്കുകയാണെങ്കിൽ, കറുത്ത മേഘങ്ങളിൽനിന്ന് പൂർണ്ണമായി മോചിതനായ ചന്ദ്രനെപ്പോലെ അവൻ ഈ ലോകത്തെ മുഴുവൻ ജ്ഞാനത്താൽ പ്രകാശിപ്പിക്കിക്കുന്നു.",
  "chap26": "ബ്രാഹ്മണവഗ്ഗോ",
  "383": "ഹേ ബ്രാഹ്മണാ, നീ ധീരതയോടെ പൊരുതി തൃഷ്ണയാകുന്ന ഈ കുത്തൊഴുക്കിനെ മുറിച്ചുമാറ്റുക; ലൗകികമായ കാമങ്ങളെ ദൂരേക്ക് എറിഞ്ഞുകളയുക. കൃത്രിമമായി ഉണ്ടാക്കപ്പെട്ട സർവ്വ ലൗകിക സംസ്കാരങ്ങളുടെയും നാശത്തെ (അസ്ഥിരതയെ) തിരിച്ചറിയുമ്പോൾ, നീ അകൃത്രിമവും ശാശ്വതവുമായ നിർവ്വാണത്തെ പൂർണ്ണമായി അറിയും.",
  "384": "ഏതൊരു ബ്രാഹ്മണനാണോ ശമമെന്നും ധ്യാനമെന്നുമുള്ള രണ്ട് ഉത്തമ ധർമ്മങ്ങളുടെയും മറുകര പറ്റിയിരിക്കുന്നത്, ആ പരമജ്ഞാനിയെ ബാധിച്ചിരുന്ന സർവ്വ ലൗകിക ബന്ധനങ്ങളും അവനിൽനിന്ന് പൂർണ്ണമായി ഒഴിഞ്ഞുപോകുന്നു.",
  "385": "ഈ കരയെന്നോ (ബാഹ്യേന്ദ്രിയങ്ങൾ) മറുകരയെന്നോ (വിഷയസുഖങ്ങൾ) ഭേദമില്ലാത്തവനും, ഇരുകരകളോടും ഒട്ടും ആസക്തിയില്ലാത്തവനും, ലേശംപോലും ഭയമില്ലാത്തവനും, രാഗാദികളിൽനിന്ന് പൂർണ്ണമായി വിമുക്തനുമായവനെയാണ് ഞാൻ യഥാർത്ഥ 'ബ്രാഹ്മണൻ' എന്ന് വിളിക്കുന്നത്.",
  "386": "സദാ ധ്യാനനിരതനായിരിക്കുന്നവനും, ചിത്തമലങ്ങൾ (രജസ്സ്) ഒഴിഞ്ഞവനും, ഒരിടത്ത് ഉറച്ചുനിൽക്കുന്നവനും, ചെയ്യേണ്ട കർത്തവ്യങ്ങളെല്ലാം പൂർത്തിയാക്കിയവനും, ആശ്രവങ്ങൾ (ആസക്തികൾ) ഇല്ലാത്തവനും, പരമമായ നിർവ്വാണലക്ഷ്യം കൈവരിച്ചവനുമായ ജ്ഞാനിയെയാണ് ഞാൻ ബ്രാഹ്മണൻ എന്ന് പറയുന്നത്.",
  "387": "പകൽസമയത്ത് സൂര്യൻ ജ്വലിച്ചുനിൽക്കുന്നു; രാത്രികാലങ്ങളിൽ ചന്ദ്രൻ ശോഭിക്കുന്നു; യുദ്ധത്തിന് സന്നദ്ധനായ ക്ഷത്രിയൻ തന്റെ ആയുധങ്ങളാൽ ശോഭിക്കുന്നു; സമാധിയിലിരിക്കുന്ന ബ്രാഹ്മണൻ തന്റെ തപസ്സാൽ ശോഭിക്കുന്നു; എന്നാൽ ബുദ്ധഭഗവാനാകട്ടെ, രാവും പകലും ഒരേപോലെ തന്റെ പരമമായ ജ്ഞാനതേജസ്സുകൊണ്ട് പ്രപഞ്ചമാകെ ശോഭിച്ചുകൊണ്ടേയിരിക്കുന്നു.",
  "388": "തന്റെ ഉള്ളിലെ പാപങ്ങളെ മുഴുവൻ കഴുകിക്കളഞ്ഞവനെ 'ബ്രാഹ്മണൻ' എന്നും, സദാ ശാന്തതയോടും സമഭാവനയോടും കൂടി ജീവിക്കുന്നവനെ 'ശ്രമണൻ' എന്നും, സ്വന്തം ആത്മാവിലെ അശുദ്ധിയെ (മലങ്ങളെ) പുറന്തള്ളിയവനെ 'പരിവ്രാജകൻ' (സന്യാസി) എന്നും വിളിക്കുന്നു.",
  "389": "ഒരു ബ്രാഹ്മണനെയും ആരും ഒരിക്കലും ദ്രോഹിക്കുകയോ പ്രഹരിക്കുകയോ ചെയ്യരുത്; ഒരു ബ്രാഹ്മണൻ തന്നെ ആരെങ്കിലും ഉപദ്രവിച്ചാൽപ്പോലും അവരോട് തിരിച്ച് പകരം വീട്ടുകയുമരുത്. ബ്രാഹ്മണനെ ദ്രോഹിക്കുന്നവൻ മഹാപാപിയാണ്; എന്നാൽ അതിന് പകരമായി ക്രോധത്തോടെ ദ്രോഹിക്കുന്ന ബ്രാഹ്മണൻ അതിലും വലിയ പാപിയാകുന്നു.",
  "390": "പ്രിയപ്പെട്ട ലൗകികവസ്തുക്കളിൽനിന്ന് സ്വന്തം മനസ്സിനെ പിന്തിരിപ്പിച്ചു നിർത്തുന്നതുകൊണ്ട് ബ്രാഹ്മണന് ലഭിക്കുന്നത് നിസ്സാരമായ നന്മയല്ല. അവന്റെ ഉള്ളിലെ ഹിംസാബുദ്ധി എത്രത്തോളം പിൻവലിയുന്നുവോ, അത്രത്തോളം അവന്റെ ജീവിതത്തിലെ സർവ്വ ദുഃഖങ്ങളും ശമിച്ചുകൊണ്ടേയിരിക്കും.",
  "391": "ശരീരത്തെക്കൊണ്ടോ, വാക്കുകളെക്കൊണ്ടോ, മനസ്സുകൊണ്ടോ യാതൊരുവിധ ദുഷ്കൃത്യങ്ങളും (പാപങ്ങളും) ചെയ്യാതെ, ഈ മൂന്ന് സ്ഥാനങ്ങളെയും എപ്പോഴും പൂർണ്ണമായ സംയമനത്തോടെ കാത്തുസൂക്ഷിക്കുന്നവനെയാണ് ഞാൻ ബ്രാഹ്മണൻ എന്ന് വിളിക്കുന്നത്.",
  "392": "സമ്യക് സംബുദ്ധനായ ഭഗവാൻ ഉപദേശിച്ച ഉത്തമ ധർമ്മത്തെ ഏതൊരു ഗുരുവരിൽനിന്നാണോ ഒരുവൻ പഠിച്ചറിയുന്നത്, യാഗാഗ്നിയെ ബ്രാഹ്മണൻ എത്രത്തോളം ഭക്തിയോടെ വണങ്ങുന്നുവോ അത്രത്തോളം ആദരവോടെ ആ ധർമ്മഗുരുവിനെ അവൻ എപ്പോഴും നമസ്കരിക്കേണ്ടതാകുന്നു.",
  "393": "തലയിലെ ജടകൊണ്ടോ, ജനിച്ച ഗോത്രംകൊണ്ടോ, ഉച്ചകുലത്തിലുള്ള ജനനംകൊണ്ടോ മാത്രം ഒരുവൻ യഥാർത്ഥ ബ്രാഹ്മണനായിത്തീരുന്നില്ല. ഏതൊരുവന്റെ ഉള്ളിലാണോ സത്യവും ധർമ്മവും സദാ കുടികൊള്ളുന്നത്, അവൻ മാത്രമാണ് പരിശുദ്ധൻ; അവൻ തന്നെയാണ് യഥാർത്ഥ ബ്രാഹ്മണൻ.",
  "394": "ഹേ മൂഢാ, നിന്റെ തലയിലെ ഈ നീണ്ട ജടകൾകൊണ്ടും നീ ധരിച്ചിരിക്കുന്ന മാന്തോൽകൊണ്ടും എന്തുകാര്യം? നിന്റെ ഉള്ളിൽ രാഗദ്വേഷങ്ങളാകുന്ന കൊടുങ്കാട് നിറഞ്ഞിരിക്കുകയാണ്; നീ നിന്റെ പുറംമോടി മാത്രമാണ് വൃത്തിയാക്കി വെച്ചിരിക്കുന്നത്.",
  "395": "കീറിപ്പറിഞ്ഞ വസ്ത്രങ്ങൾ (പാംശുകൂലം) ധരിച്ചവനും, വ്രതാനുഷ്ഠാനങ്ങളാൽ ശരീരം മെലിഞ്ഞ് ഞരമ്പുകൾ പുറത്തേക്ക് കാണാവുന്ന അവസ്ഥയിലായവനും, വനത്തിൽ ഏകാന്തനായിരുന്ന് സദാ ധ്യാനത്തിൽ മുഴുകുന്നവനുമായ ആത്മാവിനെയാണ് ഞാൻ ബ്രാഹ്മണൻ എന്ന് വിശേഷിപ്പിക്കുന്നത്.",
  "396": "ബ്രാഹ്മണസ്ത്രീയുടെ ഗർഭത്തിൽ ജനിച്ചു എന്നതുകൊണ്ടോ, സമ്പന്നമായ കുടുംബ പശ്ചാത്തലമുള്ളതുകൊണ്ടോ മാത്രം ഞാൻ ഒരാളെ ബ്രാഹ്മണൻ എന്ന് വിളിക്കുകയില്ല; അങ്ങനെയുള്ളവൻ കേവലം അഹംഭാവത്തോടെ 'ഭോ' എന്ന് മറ്റുള്ളവരെ അഭിസംബോധന ചെയ്യുന്നവൻ (ഭോവാദി) മാത്രമാണ്. എന്നാൽ യാതൊരു സമ്പാദ്യവുമില്ലാത്തവനും (അകിഞ്ചനൻ), ലൗകികാശകൾ പൂർണ്ണമായി വെടിഞ്ഞവനുമായ ദരിദ്രനെയാണ് ഞാൻ യഥാർത്ഥ ബ്രാഹ്മണൻ എന്ന് വിളിക്കുന്നത്.",
  "397": "ലൗകികമായ എല്ലാവിധ കെട്ടുപാടുകളെയും പൂർണ്ണമായി അറുത്തുമാറ്റി, ഒന്നിനെക്കുറിച്ചും പരിതപിക്കാതെയും ഭയപ്പെടാതെയും, നിസ്സംഗനായും വിമുക്തനായും ജീവിക്കുന്ന മഹാത്മാവിനെയാണ് ഞാൻ ബ്രാഹ്മണൻ എന്ന് പറയുന്നത്.",
  "398": "ക്രോധമാകുന്ന കയറും, രാഗമാകുന്ന വടവും, തൃഷ്ണയാകുന്ന ചങ്ങലയും അതിന്റെ കണ്ണികളും പൂർണ്ണമായി മുറിച്ചുമാറ്റി, അവിദ്യയാകുന്ന തടസ്സത്തെ (സാക്ഷയെ) നീക്കി പരമജ്ഞാനം പ്രാപിച്ച ബുദ്ധനെയാണ് ഞാൻ യഥാർത്ഥ ബ്രാഹ്മണൻ എന്ന് വിളിക്കുന്നത്.",
  "399": "താൻ യാതൊരു തെറ്റും ചെയ്യാതിരുന്നിട്ടും മറ്റുള്ളവരുടെ നിന്ദകളെയും പ്രഹരങ്ങളെയും ബന്ധനങ്ങളെയും മനസ്സിൽ ലേശവും ദ്വേഷമില്ലാതെ ക്ഷമയോടെ സഹിക്കുന്നവനും, ക്ഷമാബലത്തെത്തന്നെ തന്റെ വലിയ സൈന്യമാക്കി മാറ്റിയവനുമായ വ്യക്തിയെയാണ് ഞാൻ ബ്രാഹ്മണൻ എന്ന് പറയുന്നത്.",
  "400": "ആരോടും ഒരിക്കലും ക്രോധം കാണിക്കാത്തവനും, വ്രതശുദ്ധിയുള്ളവനും, സുശീലനും, തൃഷ്ണയില്ലാത്തവനും, ഇന്ദ്രിയങ്ങളെ പൂർണ്ണമായി ജയിച്ചവനും, തന്റെ അവസാനത്തെ ശരീരത്തെ ചുമക്കുന്നവനുമായ (ഇനി ജന്മമില്ലാത്ത) ജ്ഞാനിയെയാണ് ഞാൻ ബ്രാഹ്മണൻ എന്ന് വിളിക്കുന്നത്.",
  "401": "താമരയിലയിൽ വെള്ളത്തുള്ളി ഒട്ടാതെ നിൽക്കുന്നതുപോലെയും, സൂചിയുടെ അഗ്രത്തിൽ കടുകുമണി നില്ക്കാതെ വഴുതിപ്പോകുന്നതുപോലെയും, ഏതൊരുവന്റെ ഉള്ളിലാണോ ലൗകികമായ കാമാദികൾ ഒട്ടും പറ്റിപ്പിടിക്കാതെ ഒഴിഞ്ഞുപോകുന്നത്, അവനെയാണ് ഞാൻ യഥാർത്ഥ ബ്രാഹ്മണൻ എന്ന് പറയുന്നത്.",
  "402": "ഇഹലോക ജീവിതത്തിൽവെച്ചുതന്നെ തന്റെ സർവ്വ ദുഃഖങ്ങൾക്കും ശാശ്വതമായ അന്ത്യം കുറിച്ചവനും, ജന്മങ്ങളാകുന്ന ഭാരങ്ങളെല്ലാം ഇറക്കിവെച്ചവനും, ലൗകികബന്ധങ്ങളിൽനിന്ന് പൂർണ്ണമായി വിമുക്തനുമായ ജ്ഞാനിയെയാണ് ഞാൻ യഥാർത്ഥ ബ്രാഹ്മണൻ എന്ന് വിളിക്കുന്നത്.",
  "403": "അഗാധമായ ബുദ്ധിവൈഭവമുള്ളവനും, ഉന്നതമായ പ്രജ്ഞയോടുകൂടിയ മേധാവിയും, സന്മാര്‍ഗ്ഗമേതെന്നും ദുര്‍മാര്‍ഗ്ഗമേതെന്നും വ്യക്തമായി തിരിച്ചറിയുന്നവനും, പരമമായ സിദ്ധി (നിര്‍വ്വാണം) പ്രാപിച്ചവനുമായ ജ്ഞാനിയെയാണ് ഞാന്‍ യഥാര്‍ത്ഥ 'ബ്രാഹ്മണന്‍' എന്ന് വിളിക്കുന്നത്.",
  "404": "ലൗകികരായ ഗൃഹസ്ഥന്മാരുടെയും സന്യാസികളായ ഭിക്ഷുക്കളുടെയും കൂട്ടങ്ങളില്‍നിന്ന് മാറിനടക്കുന്നവനും, സ്വന്തമായി വീടില്ലാത്തവനും (അനാഗാരി), ലേശംപോലും ആഗ്രഹങ്ങളില്ലാത്തവനുമായ ആത്മാവിനെയാണ് ഞാന്‍ ബ്രാഹ്മണന്‍ എന്ന് പറയുന്നത്.",
  "405": "ഇളകുന്നവയോ (ത്രസ) ഉറച്ചുനില്‍ക്കുന്നവയോ (സ്ഥാവര) ആയ പ്രപഞ്ചത്തിലെ സകല ചരാചരങ്ങളിലും യാതൊരുവിധ ഹിംസയും ചെയ്യാത്തവനും, മറ്റുള്ളവരെക്കൊണ്ട് ചെയ്യിക്കാത്തവനുമായ കാരുണ്യമൂർത്തിയെയാണ് ഞാന്‍ ബ്രാഹ്മണന്‍ എന്ന് വിശേഷിപ്പിക്കുന്നത്.",
  "406": "വിരോധത്തോടെ പെരുമാറുന്നവരുടെ ഇടയിലും വിരോധമില്ലാതെ ശാന്തനായിരിക്കുന്നവനും, ആയുധമേന്തി അതിക്രമം കാണിക്കുന്നവരുടെ മുന്നില്‍പ്പോലും ക്ഷമയോടെ വിനയം പാലിക്കുന്നവനും, ലോഭികളായ (ആർത്തിയുള്ള) മനുഷ്യരുടെ നടുവിലും യാതൊരു ആഗ്രഹവുമില്ലാതെ ജീവിക്കുന്നവനുമായ വ്യക്തിയെയാണ് ഞാന്‍ ബ്രാഹ്മണന്‍ എന്ന് വിളിക്കുന്നത്.",
  "407": "സൂചിയുടെ അഗ്രത്തില്‍നിന്ന് കടുകുമണി വഴുതിവീഴുന്നതുപോലെ, ഏതൊരുവന്റെ ഉള്ളില്‍നിന്നാണോ രാഗം, ദ്വേഷം, അഹംഭാവം, കപടത (ദംഭം) എന്നിവയെല്ലാം പൂർണ്ണമായി വീണുപോകുന്നത്, അവനെയാണ് ഞാന്‍ ബ്രാഹ്മണന്‍ എന്ന് പറയുന്നത്.",
  "408": "ആരുടെയും മനസ്സിന് ലേശവും അസഹ്യതയോ വേദനയോ ഉണ്ടാക്കാത്തതും, മൃദുവും, അറിവ് പകരുന്നതുമായ സത്യവാക്കുകള്‍ മാത്രം എപ്പോഴും ഉച്ചരിക്കുന്നവനെയാണ് ഞാന്‍ യഥാര്‍ത്ഥ ബ്രാഹ്മണന്‍ എന്ന് വിളിക്കുന്നത്.",
  "409": "ഈ ലോകത്തില്‍ നീളമുള്ളതോ കുറിയതോ, വലുതോ ചെറുതോ, നല്ലതോ ചീത്തയോ ആയ ഏതൊരു വസ്തുവാണെങ്കിലും, തനിക്ക് ദാനമായി നല്‍കാത്ത ഒന്നിനെയും സ്വന്തമാക്കാത്തവനെ (അന്യന്റെ ധനം മോഷ്ടിക്കാത്തവനെ) ആണ് ഞാന്‍ ബ്രാഹ്മണന്‍ എന്ന് പറയുന്നത്.",
  "410": "ഈ ലോകത്തെ ലൗകികസുഖങ്ങളിലോ പരലോകത്തെ സുഖഭോഗങ്ങളിലോ യാതൊരുവിധ പ്രതീക്ഷകളും ഇല്ലാത്തവനും, ആശാതീതനും, സകല ബന്ധനങ്ങളിൽനിന്നും വിമുക്തനുമായി ജീവിക്കുന്നവനെയാണ് ഞാന്‍ ബ്രാഹ്മണന്‍ എന്ന് വിളിക്കുന്നത്.",
  "411": "യാതൊരുവിധ ലൗകികാസക്തികളും ഇല്ലാത്തവനും, പരമമായ സത്യജ്ഞാനം ലഭിച്ചതുമൂലം 'എങ്ങനെ, എന്തിന്' എന്നൊക്കെയുള്ള സകല സംശയങ്ങളും ഒഴിഞ്ഞവനും, അമൃതാബ്ധിയാകുന്ന നിര്‍വ്വാണത്തില്‍ പ്രവേശിച്ചവനുമായ ജ്ഞാനിയെയാണ് ഞാന്‍ ബ്രാഹ്മണന്‍ എന്ന് വിശേഷിപ്പിക്കുന്നത്.",
  "412": "ഈ ലോകത്തില്‍ പുണ്യത്തിന്റെയും പാപത്തിന്റെയും കെട്ടുപാടുകളെ (രണ്ടിന്റെയും സംഗത്തെ) ഒരേപോലെ മറികടന്നവനും, ദുഃഖങ്ങളില്ലാത്തവനും (അശോകന്‍), ചിത്തമലങ്ങള്‍ ഒഴിഞ്ഞവനും (വിരജന്‍), അങ്ങേയറ്റം പരിശുദ്ധനുമായ മഹാത്മാവിനെയാണ് ഞാന്‍ ബ്രാഹ്മണന്‍ എന്ന് പറയുന്നത്.",
  "413": "പൂർണ്ണചന്ദ്രനെപ്പോലെ അത്യന്തം നിർമ്മലനും പരിശുദ്ധനും, മനസ്സിൽ യാതൊരുവിധ ആകുലതകളോ അസ്വസ്ഥതകളോ ഇല്ലാത്തവനും, സംസാരസുഖങ്ങളോടുള്ള ആസക്തി പൂർണ്ണമായി നശിച്ചവനുമായ ജ്ഞാനിയെയാണ് ഞാന്‍ ബ്രാഹ്മണന്‍ എന്ന് വിളിക്കുന്നത്.",
  "414": "അപകടങ്ങളും ചതിക്കുഴികളും നിറഞ്ഞതും മോഹവലയങ്ങളാൽ ചുറ്റപ്പെട്ടതുമായ ഈ സംസാരസാഗരത്തെ പൂർണ്ണമായി അതിക്രമിച്ച് മറുകര പൂകിയവനും, ധ്യാനനിരതനും, ചഞ്ചലതയില്ലാത്തവനും, ശങ്കകളൊഴിഞ്ഞവനും, ഒന്നിനോടും പറ്റിപ്പിടിക്കാതെ പരമശാന്തി (നിര്‍വ്വാണം) പ്രാപിച്ചവനുമായ ആളെയാണ് ഞാന്‍ യഥാര്‍ത്ഥ ബ്രാഹ്മണന്‍ എന്ന് പറയുന്നത്.",
  "415": "ലൗകികങ്ങളായ കാമങ്ങളെല്ലാം പൂർണ്ണമായി ഉപേക്ഷിച്ച്, ഗൃഹം വെടിഞ്ഞ് പരിവ്രാജകനായി ജീവിക്കുന്നവനും, തന്റെ ഉള്ളിൽ കാമവാസനകളുടെ ഉത്ഭവം പാടേ നശിച്ചവനുമായ ജ്ഞാനിയെയാണ് ഞാൻ യഥാർത്ഥ 'ബ്രാഹ്മണൻ' എന്ന് വിളിക്കുന്നത്.",
  "416": "ഈ ലോകത്തിൽ സകലവിധ തൃഷ്ണകളെയും (ആഗ്രഹങ്ങളെ) അറുത്തുമാറ്റി, വീടുപേക്ഷിച്ച് പരിവ്രാജകനായി ജീവിക്കുന്നവനും, തൃഷ്ണകളുടെ വേരുകൾ പൂർണ്ണമായി ഒഴിഞ്ഞുപോയവനുമായ മഹാത്മാവിനെയാണ് ഞാൻ ബ്രാഹ്മണൻ എന്ന് പറയുന്നത്.",
  "417": "മാനുഷികമായ സകല കെട്ടുപാടുകളും ഉപേക്ഷിച്ച്, ദിവ്യമായ ബന്ധനങ്ങളെയും മറികടന്ന്, പ്രപഞ്ചത്തിലെ എല്ലാവിധ യോഗങ്ങളിൽനിന്നും പൂർണ്ണമായി വിമുക്തനായിത്തീർന്നവനെയാണ് ഞാൻ ബ്രാഹ്മണൻ എന്ന് വിശേഷിപ്പിക്കുന്നത്.",
  "418": "സുഖഭോഗങ്ങളോടുള്ള അനുരാഗവും (രതി) ലൗകികകാര്യങ്ങളോടുള്ള വിരക്തിയും (അരതി) ഒരുപോലെ വെടിഞ്ഞ്, മനസ്സ് പൂർണ്ണമായി തണുത്തുശാന്തമായവനും (ശീതിഭൂതൻ), പുനർജന്മത്തിന്റെ ഉപാധികൾ ഒഴിഞ്ഞവനും, സകല ലോകങ്ങളെയും ജയിച്ച ധീരനുമായവനെയാണ് ഞാൻ ബ്രാഹ്മണൻ എന്ന് വിളിക്കുന്നത്.",
  "419": "പ്രാണികളുടെ മരണത്തെയും (ച്യുതി) അവയുടെ പുനർജനനത്തെയും (ഉത്പത്തി) എല്ലാവിധത്തിലും പൂർണ്ണമായി തിരിച്ചറിയുന്നവനും, ഒന്നിനോടും ആസക്തിയില്ലാത്തവനും, സദ്ഗതി പ്രാപിച്ചവനും (സുഗതൻ), പരമജ്ഞാനിയുമായ ബുദ്ധനെയാണ് ഞാൻ ബ്രാഹ്മണൻ എന്ന് പറയുന്നത്.",
  "420": "ഏതൊരുവന്റെ പരമമായ ഗതിയെ ദേവന്മാർക്കോ ഗന്ധർവ്വന്മാർക്കോ മനുഷ്യർക്കോ പോലും മനസ്സിലാക്കാൻ സാധ്യമല്ലയോ, ആശ്രവങ്ങളെല്ലാം (രാഗാദി ദോഷങ്ങൾ) ക്ഷയിച്ച് ആർഹത്യം (അർഹന്ത പദം) കൈവരിച്ച ആ ജ്ഞാനിയെയാണ് ഞാൻ ബ്രാഹ്മണൻ എന്ന് വിളിക്കുന്നത്.",
  "421": "ഭൂതകാലത്തെക്കുറിച്ചോ (മുൻപ്), ഭാവികാലത്തെക്കുറിച്ചോ (പിമ്പ്), വർത്തമാനകാലത്തെക്കുറിച്ചോ (മധ്യം) യാതൊരുവിധ മമതയുമില്ലാത്തവനും, ഒരു സമ്പാദ്യവുമില്ലാത്തവനും (നിഷ്കിഞ്ചനൻ), ലൗകികാസക്തികൾ പൂർണ്ണമായി ഒഴിഞ്ഞവനുമായ മഹാത്മാവിനെയാണ് ഞാൻ ബ്രാഹ്മണൻ എന്ന് വിശേഷിപ്പിക്കുന്നത്.",
  "422": "ഭയമില്ലാത്തവനും (വൃഷഭൻ), സർവ്വോത്കൃഷ്ടനും, വീരനും, മഹർഷിയും, ഇന്ദ്രിയങ്ങളെ പൂർണ്ണമായി ജയിച്ചവനും, തൃഷ്ണകളാകുന്ന മലങ്ങൾ കഴുകിക്കളഞ്ഞവനും (സ്നാതകൻ), സർവ്വജ്ഞനുമായ ബുദ്ധനെയാണ് ഞാൻ ബ്രാഹ്മണൻ എന്ന് വിളിക്കുന്നത്.",
  "423": "തന്റെ പൂർവ്വജന്മങ്ങളെക്കുറിച്ച് വ്യക്തമായ അറിവുള്ളവനും, സ്വർഗ്ഗനരകങ്ങളെ നേരിട്ടു ദർശിക്കുന്നവനും, പുനർജന്മങ്ങളുടെ അന്ത്യം കുറിച്ചവനും (ജാതിക്ഷയം), പരമജ്ഞാനം നേടി കൃതകൃത്യനായിത്തീർന്നവനും, സർവ്വവിധ ക്ലേശങ്ങൾക്കും ശാശ്വതമായ അന്ത്യം കുറിച്ചവനുമായ മുനിയെയാണ് ഞാൻ യഥാർത്ഥ 'ബ്രാഹ്മണൻ' എന്ന് വിളിക്കുന്നത്."
};
